              </div>
              <div className="flex items-center gap-3 p-3 bg-white/[0.03] border border-white/[0.06] rounded-xl text-left">
                <Mail size={16} className="text-purple-400 flex-shrink-0" />
                <span className="text-sm text-gray-300">Confirmation envoyée à <span className="text-white">{formData.contactEmail}</span></span>
              </div>
            </div>

            <div className="flex gap-3 justify-center pt-4">
              <button onClick={() => { setViewMode('browse'); setJoinStep('form'); }}
                className="px-6 py-3 bg-white/[0.06] border border-white/[0.08] rounded-2xl text-white text-sm font-medium hover:bg-white/10 transition-colors">
                Retour à l'annuaire
              </button>
              <button onClick={onNavigateToPlan}
                className="px-6 py-3 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-2xl text-sm flex items-center gap-2 shadow-lg shadow-purple-500/20">
                <Zap size={16} /> Booster mon indexation
              </button>
            </div>
          </div>
        )}
      </div>
    );
  };

  // =============================================
  // RENDER
  // =============================================
  return (
    <div className="animate-in fade-in duration-500">

      {viewMode === 'browse' && (
        <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
          <ArrowLeft size={18} className="mr-2" /> Retour
        </button>
      )}

      {viewMode === 'browse' ? renderBrowser() : renderJoinFunnel()}

      {/* --- ALERTE LIMITE ATTEINTE --- */}
      {showLimitAlert && createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setShowLimitAlert(false)} />
          <div className="relative bg-[#111111] border border-red-500/20 rounded-2xl w-full max-w-md shadow-2xl shadow-red-500/5 overflow-hidden max-h-[90vh] overflow-y-auto">
            <div className="bg-gradient-to-r from-red-500/10 to-orange-500/10 border-b border-white/[0.06] p-6 text-center">
              <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-red-500/10 border border-red-500/20 flex items-center justify-center">
                <AlertCircle size={32} className="text-red-400" />
              </div>
              <h2 className="text-xl font-bold text-white mb-2">Limite de projets atteinte</h2>
              <p className="text-sm text-gray-400">
                Votre plan <span className="font-bold text-white">{planLabel}</span> autorise <span className="font-bold text-white">{maxClients}</span> projet{maxClients > 1 ? 's' : ''} maximum.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div className="flex items-center justify-between p-3 bg-white/[0.03] rounded-xl border border-white/[0.06]">
                <span className="text-sm text-gray-400">Projets utilisés</span>
                <span className="text-lg font-bold text-red-400">{directClientCount}/{maxClients}</span>
              </div>
              <p className="text-xs text-gray-500 text-center">Passez à un plan supérieur pour ajouter votre entreprise à l'annuaire.</p>
              <div className="flex gap-3">
                <button onClick={() => setShowLimitAlert(false)} className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.08] rounded-xl transition-colors">Fermer</button>
                <button onClick={() => { setShowLimitAlert(false); onNavigateToPlan(); }}
                  className="flex-1 px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-colors shadow-lg shadow-purple-500/20">
                  <Zap size={16} /> Upgrader
                </button>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}
      {/* --- ALERTE PLAN D'ACTION INCOMPLET --- */}
      {showActionPlanAlert && createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setShowActionPlanAlert(false)} />
          <div className="relative bg-[#111111] border border-amber-500/20 rounded-2xl w-full max-w-md shadow-2xl shadow-amber-500/5 overflow-hidden max-h-[90vh] overflow-y-auto">
            <div className="bg-gradient-to-r from-amber-500/10 to-orange-500/10 border-b border-white/[0.06] p-6 text-center">
              <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-amber-500/10 border border-amber-500/20 flex items-center justify-center">
                <ClipboardList size={32} className="text-amber-400" />
              </div>
              <h2 className="text-xl font-bold text-white mb-2">Plan d'action à compléter</h2>
              <p className="text-sm text-gray-400">
                Vous devez valider toutes les solutions de votre plan d'action AEO avant de pouvoir rejoindre l'index.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div className="space-y-2">
                <div className="flex items-center justify-between text-sm">
                  <span className="text-gray-400">Solutions validées</span>
                  <span className="font-bold text-amber-400">{actionPlanProgress.completed}/{actionPlanProgress.total}</span>
                </div>
                <div className="h-2 bg-white/10 rounded-full overflow-hidden">
                  <div
                    className="h-full bg-gradient-to-r from-amber-500 to-orange-500 rounded-full transition-all duration-500"
                    style={{ width: actionPlanProgress.total > 0 ? `${(actionPlanProgress.completed / actionPlanProgress.total) * 100}%` : '0%' }}
                  />
                </div>
              </div>
              <p className="text-xs text-gray-500 text-center">Générez et validez chaque solution d'amélioration dans l'onglet Monitoring AEO.</p>
              <div className="flex gap-3">
                <button onClick={() => setShowActionPlanAlert(false)} className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.08] rounded-xl transition-colors">Fermer</button>
                <button onClick={() => { setShowActionPlanAlert(false); onNavigateToActionPlan(); }}
                  className="flex-1 px-4 py-2.5 bg-gradient-to-r from-amber-500 to-orange-500 hover:from-amber-600 hover:to-orange-600 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-colors shadow-lg shadow-amber-500/20 text-sm">
                  Compléter mon plan d'action <ArrowRight size={14} />
                </button>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
};

export default Directory;
"}

