      nextInvoiceAmount: 0
    },
    legal: { address: '-', vatNumber: 'En attente', siret: 'En attente', country: 'France' },
    mission: {
      missionId: 'MIS-2026-005',
      analyzedUrl: 'https://startuplab.io',
      aeoScore: 15,
      budget: 7500,
      missionStatus: 'nouveau',
      deadline: '2026-05-01',
      recommendations: 6
    }
  },
  {
    id: 'C-M006',
    companyName: 'WellnessZone',
    contactName: 'Camille Petit',
    role: 'Gérante',
    email: 'camille@wellnesszone.fr',
    phone: '-',
    status: 'active',
    plan: 'Starter',
    mrr: 29,
    avatar: 'CP',
    source: 'mission',
    createdAt: '2026-02-13',
    contract: {
      startDate: '2026-02-14',
      renewalDate: '2027-02-14',
      billingCycle: 'Mensuel',
      paymentMethod: 'Stripe (CB)',
      slaLevel: 'Standard',
      nextInvoiceAmount: 34.80
    },
    legal: { address: '8 Rue du Bien-Être, 44000 Nantes', vatNumber: 'FR 44 333222111', siret: '333 222 111 00044', country: 'France' },
    mission: {
      missionId: 'MIS-2026-007',
      analyzedUrl: 'https://wellnesszone.fr',
      aeoScore: 28,
      budget: 3500,
      missionStatus: 'en_cours',
      deadline: '2026-03-25',
      recommendations: 4
    }
  },
];

const ALL_INITIAL_CLIENTS = [...DIRECT_CLIENTS, ...MISSION_CLIENTS];

interface ClientsProps {
  onBack: () => void;
  onNavigate: (view: string) => void;
  user: { name: string; email: string; plan: 'free' | 'pro' | 'enterprise'; credits: number } | null;
  directClientCount: number;
  maxClients: number;
}

const MISSION_STATUS_LABELS: Record<string, { label: string; color: string }> = {
  nouveau: { label: 'Nouveau', color: 'text-blue-400 bg-blue-500/10 border-blue-500/20' },
  accepte: { label: 'Accepté', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20' },
  en_cours: { label: 'En cours', color: 'text-amber-400 bg-amber-500/10 border-amber-500/20' },
  termine: { label: 'Terminé', color: 'text-green-400 bg-green-500/10 border-green-500/20' },
  refuse: { label: 'Refusé', color: 'text-red-400 bg-red-500/10 border-red-500/20' },
};

const getScoreColor = (score: number) => {
  if (score >= 70) return 'text-green-400';
  if (score >= 50) return 'text-yellow-400';
  if (score >= 30) return 'text-orange-400';
  return 'text-red-400';
};

const Clients: React.FC<ClientsProps> = ({ onBack, onNavigate, user, directClientCount, maxClients }) => {
  const [clients, setClients] = useState<Client[]>(ALL_INITIAL_CLIENTS);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [sourceFilter, setSourceFilter] = useState<'all' | 'direct' | 'mission'>('all');
  const [showNewClientModal, setShowNewClientModal] = useState(false);
  const [showLimitAlert, setShowLimitAlert] = useState(false);

  useEffect(() => {
    if (showLimitAlert || showNewClientModal) { document.body.style.overflow = 'hidden'; }
    return () => { document.body.style.overflow = ''; };
  }, [showLimitAlert, showNewClientModal]);

  // Compteur de clients directs ajoutés manuellement (excluant les clients mission)
  const addedDirectClients = useMemo(() => clients.filter(c => c.source === 'direct').length, [clients]);
  const totalDirectCount = directClientCount + addedDirectClients - DIRECT_CLIENTS.length; // nouveaux directs ajoutés cette session + ceux du mois
  const isAtLimit = totalDirectCount >= maxClients && user?.plan !== 'enterprise';
  const planLabel = user?.plan === 'free' ? 'Starter' : user?.plan === 'pro' ? 'Pro' : 'Agency';

  // New client form state
  const [newClient, setNewClient] = useState({
    companyName: '',
    contactName: '',
    email: '',
    phone: '',
    role: '',
    plan: 'Starter' as 'Starter' | 'Pro' | 'Agency',
    address: '',
    siret: '',
    vatNumber: '',
  });

  const filteredClients = useMemo(() => {
    return clients.filter(client => {
      const matchesSearch = client.companyName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            client.contactName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            client.email.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = statusFilter === 'all' || client.status === statusFilter;
      const matchesSource = sourceFilter === 'all' || client.source === sourceFilter;
      return matchesSearch && matchesStatus && matchesSource;
    });
  }, [clients, searchTerm, statusFilter, sourceFilter]);

  const totalMRR = useMemo(() => clients.reduce((acc, curr) => curr.status === 'active' ? acc + curr.mrr : acc, 0), [clients]);
  const activeCount = useMemo(() => clients.filter(c => c.status === 'active').length, [clients]);
  const missionClientCount = useMemo(() => clients.filter(c => c.source === 'mission').length, [clients]);

  // --- EXPORT CSV ---
  const handleExportCSV = () => {
    const headers = [
      'ID', 'Entreprise', 'Contact', 'Rôle', 'Email', 'Téléphone',
      'Statut', 'Plan', 'MRR (€)', 'Source', 'Date création',
      'Cycle facturation', 'Méthode paiement', 'SLA',
      'Adresse', 'SIRET', 'TVA', 'Pays',
      'Mission ID', 'URL analysée', 'Score AEO', 'Budget mission (€)', 'Statut mission', 'Deadline mission'
    ];

    const rows = filteredClients.map(c => [
      c.id,
      c.companyName,
      c.contactName,
      c.role,
      c.email,
      c.phone,
      c.status,
      c.plan,
      c.mrr,
      c.source,
      c.createdAt,
      c.contract.billingCycle,
      c.contract.paymentMethod,
      c.contract.slaLevel,
      c.legal.address,
      c.legal.siret,
      c.legal.vatNumber,
      c.legal.country,
      c.mission?.missionId || '',
      c.mission?.analyzedUrl || '',
      c.mission?.aeoScore || '',
      c.mission?.budget || '',
      c.mission?.missionStatus || '',
      c.mission?.deadline || '',
    ]);

    const csvContent = [
      headers.join(';'),
      ...rows.map(row => row.map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(';'))
    ].join('\n');

    // BOM for Excel UTF-8 compatibility
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `citedby-clients-${new Date().toISOString().slice(0, 10)}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // --- TENTATIVE OUVERTURE MODAL ---
  const handleOpenNewClient = () => {
    if (isAtLimit) {
      setShowLimitAlert(true);
      return;
    }
    setShowNewClientModal(true);
  };

  // --- ADD NEW CLIENT ---
  const handleAddClient = () => {
    if (!newClient.companyName.trim() || !newClient.contactName.trim() || !newClient.email.trim()) return;

    const id = `C-${String(clients.length + 1).padStart(3, '0')}`;
    const avatar = newClient.contactName
      .split(' ')
      .map(n => n.charAt(0).toUpperCase())
      .slice(0, 2)
      .join('');

    const client: Client = {
      id,
      companyName: newClient.companyName,
      contactName: newClient.contactName,
      email: newClient.email,
      phone: newClient.phone || '-',
      role: newClient.role || '-',
      status: 'pending',
      plan: newClient.plan,
      mrr: 0,
      avatar,
      source: 'direct',
      createdAt: new Date().toISOString().slice(0, 10),
      contract: {
        startDate: '-',
        renewalDate: '-',
        billingCycle: 'Mensuel',
        paymentMethod: 'Stripe (CB)',
        slaLevel: 'Standard',
        nextInvoiceAmount: 0,
      },
      legal: {
        address: newClient.address || '-',
        vatNumber: newClient.vatNumber || 'En attente',
        siret: newClient.siret || 'En attente',
        country: 'France',
      },
    };

    setClients(prev => [client, ...prev]);
    setShowNewClientModal(false);
    setNewClient({ companyName: '', contactName: '', email: '', phone: '', role: '', plan: 'Starter', address: '', siret: '', vatNumber: '' });
  };

  // --- RENDER DETAIL VIEW ---
  if (selectedClient) {
    const m = selectedClient.mission;
    const mStatusConf = m ? MISSION_STATUS_LABELS[m.missionStatus] : null;

    return (
      <div className="animate-in fade-in slide-in-from-right duration-300">
        <button
          onClick={() => setSelectedClient(null)}
          className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors group"
        >
          <ArrowLeft size={18} className="mr-2 group-hover:-translate-x-1 transition-transform" />
          Retour à la base clients
        </button>

        {/* Header Fiche Client */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-gray-800 to-black border border-white/[0.08] flex items-center justify-center text-white font-bold text-2xl shadow-inner">
              {selectedClient.avatar}
            </div>
            <div>
              <h1 className="text-3xl font-sans font-bold text-white mb-1">{selectedClient.companyName}</h1>
              <div className="flex items-center gap-3 flex-wrap">
                <span className="text-sm text-gray-500 flex items-center gap-1">
                  <Building2 size={14} /> {selectedClient.id}
                </span>
                <span className={`px-2 py-0.5 text-xs font-bold rounded-full border ${
                  selectedClient.status === 'active' ? 'bg-purple-500/10 border-white/[0.1] text-purple-300' :
                  selectedClient.status === 'pending' ? 'bg-amber-500/10 border-amber-500/20 text-amber-400' :
                  'bg-red-500/10 border-red-500/20 text-red-400'
                }`}>
                  {selectedClient.status === 'active' ? 'Actif' : selectedClient.status === 'pending' ? 'En attente' : 'Inactif'}
                </span>
                <span className={`px-2 py-0.5 text-[10px] font-semibold rounded-full border ${
                  selectedClient.source === 'mission'
                    ? 'bg-orange-500/10 border-orange-500/20 text-orange-400'
                    : 'bg-white/5 border-white/10 text-gray-500'
                }`}>
                  {selectedClient.source === 'mission' ? 'Via Mission' : 'Client direct'}
                </span>
              </div>
            </div>
          </div>
          <div className="flex gap-3">
            <button className="px-4 py-2 bg-white/[0.04] border border-white/[0.08] hover:bg-purple-500/10 rounded-full text-sm font-medium text-white transition-colors flex items-center gap-2">
              <Download size={16} /> Factures
            </button>
            <button className="px-4 py-2 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-full hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center gap-2">
              <FileText size={16} /> Éditer Contrat
            </button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

          {/* Colonne Gauche: Info Contact & Plan */}
          <div className="space-y-6">
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
              <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                <Users size={16} /> Contact Principal
              </h3>
              <div className="flex items-center gap-3 mb-4">
                <div className="w-10 h-10 rounded-full bg-white/[0.08] flex items-center justify-center text-sm font-bold">
                  {selectedClient.avatar}
                </div>
                <div>
                  <p className="font-bold text-white">{selectedClient.contactName}</p>
                  <p className="text-xs text-gray-500">{selectedClient.role}</p>
                </div>
              </div>
              <div className="space-y-3">
                <div className="flex items-center gap-3 text-sm text-gray-300">
                  <Mail size={16} className="text-purple-400" />
                  <a href={`mailto:${selectedClient.email}`} className="hover:text-white transition-colors">{selectedClient.email}</a>
                </div>
                <div className="flex items-center gap-3 text-sm text-gray-300">
                  <Phone size={16} className="text-purple-400" />
                  <span>{selectedClient.phone}</span>
                </div>
                <div className="flex items-center gap-3 text-sm text-gray-300">
                  <Calendar size={16} className="text-purple-400" />
                  <span>Client depuis le {selectedClient.createdAt}</span>
                </div>
              </div>
            </div>

            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
              <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-4 flex items-center gap-2">
                <ShieldCheck size={16} /> Abonnement
              </h3>
              <div className="flex justify-between items-end mb-4">
                <div>
                  <p className="text-xs text-gray-500 mb-1">Plan Actuel</p>
                  <p className="text-xl font-bold text-white">{selectedClient.plan}</p>
                </div>
                <div className="text-right">
                  <p className="text-xs text-gray-500 mb-1">MRR</p>
                  <p className="text-xl font-bold text-purple-300">{selectedClient.mrr}€</p>
                </div>
              </div>
              <div className="p-3 bg-white/[0.04] rounded-2xl border border-white/[0.06]">
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-gray-500">Cycle</span>
                  <span className="text-white font-medium">{selectedClient.contract.billingCycle}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">SLA</span>
                  <span className="text-purple-400 font-bold">{selectedClient.contract.slaLevel}</span>
                </div>
              </div>
            </div>

            {/* Mission AEO Card (only for mission clients) */}
            {m && (
              <div className="bg-gradient-to-br from-orange-500/5 to-amber-500/5 border border-orange-500/15 rounded-2xl p-6">
                <h3 className="text-sm font-bold text-orange-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                  <ClipboardList size={16} /> Ordre de Mission
                </h3>
                <div className="space-y-3 text-sm">
                  <div className="flex justify-between">
                    <span className="text-gray-500">Mission</span>
                    <span className="text-white font-mono text-xs">{m.missionId}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">URL analysée</span>
                    <a href={m.analyzedUrl} target="_blank" rel="noopener noreferrer" className="text-purple-400 hover:text-purple-300 flex items-center gap-1">
                      {m.analyzedUrl.replace('https://', '').replace('www.', '')}
                      <ExternalLink size={11} />
                    </a>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Score AEO</span>
                    <span className={`font-bold ${getScoreColor(m.aeoScore)}`}>{m.aeoScore}/100</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Budget mission</span>
                    <span className="text-white font-semibold">{m.budget.toLocaleString('fr-FR')} €</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Recommandations</span>
                    <span className="text-gray-300">{m.recommendations}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">Deadline</span>
                    <span className="text-gray-300">{new Date(m.deadline).toLocaleDateString('fr-FR')}</span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-gray-500">Statut mission</span>
                    {mStatusConf && (
                      <span className={`px-2 py-0.5 text-[11px] font-semibold rounded-md border ${mStatusConf.color}`}>
                        {mStatusConf.label}
                      </span>
                    )}
                  </div>
                </div>
                <button
                  onClick={() => onNavigate('mission-orders')}
                  className="mt-4 w-full py-2 bg-orange-500/10 border border-orange-500/20 rounded-xl text-sm text-orange-400 hover:bg-orange-500/20 transition-colors flex items-center justify-center gap-2"
                >
                  <ClipboardList size={14} />
                  Voir dans Ordres de Mission
                </button>
              </div>
            )}
          </div>

          {/* Colonne Centrale: Données Contractuelles */}
          <div className="lg:col-span-2 space-y-6">
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
              <h3 className="text-lg font-sans font-bold text-white mb-6 flex items-center gap-2 border-b border-white/[0.08] pb-4">
                <FileText size={20} className="text-purple-400" /> Informations Contractuelles
              </h3>

              <div className="grid md:grid-cols-2 gap-8">
                <div className="space-y-4">
                  <div>
                    <label className="text-xs text-gray-500 block mb-1">Date de début</label>
                    <div className="flex items-center gap-2 text-sm text-white font-medium">
                      <Calendar size={16} className="text-gray-500" />
                      {selectedClient.contract.startDate}
                    </div>
                  </div>
                  <div>
                    <label className="text-xs text-gray-500 block mb-1">Prochain Renouvellement</label>
                    <div className="flex items-center gap-2 text-sm text-white font-medium">
                      <Calendar size={16} className="text-gray-500" />
                      {selectedClient.contract.renewalDate}
                    </div>
                  </div>
                  <div>
                    <label className="text-xs text-gray-500 block mb-1">Méthode de paiement</label>
                    <div className="flex items-center gap-2 text-sm text-white font-medium">
                      <CreditCard size={16} className="text-gray-500" />
                      {selectedClient.contract.paymentMethod}
                    </div>
                  </div>
                </div>

                <div className="space-y-4">
                  <div>
                    <label className="text-xs text-gray-500 block mb-1">Entité Légale</label>
                    <p className="text-sm text-white font-medium">{selectedClient.companyName}</p>
                  </div>
                  <div>
                    <label className="text-xs text-gray-500 block mb-1">SIRET</label>
                    <p className="text-sm text-gray-300 font-mono">{selectedClient.legal.siret}</p>
                  </div>
                  <div>
                    <label className="text-xs text-gray-500 block mb-1">Numéro TVA</label>
                    <p className="text-sm text-gray-300 font-mono">{selectedClient.legal.vatNumber}</p>
                  </div>
                  <div>
                    <label className="text-xs text-gray-500 block mb-1">Adresse de facturation</label>
                    <p className="text-sm text-gray-300">{selectedClient.legal.address}</p>
                    <p className="text-sm text-gray-300">{selectedClient.legal.country}</p>
                  </div>
                </div>
              </div>
            </div>

            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] bg-gradient-to-br from-white/5 to-transparent">
               <div className="flex justify-between items-center mb-4">
                  <h3 className="text-sm font-bold text-gray-300 uppercase tracking-wider">Prochaine Facture</h3>
                  <span className="text-xs bg-blue-500/10 text-blue-400 px-2 py-1 rounded border border-blue-500/20">
                    {selectedClient.contract.nextInvoiceAmount > 0 ? 'Programmé' : 'Aucune'}
                  </span>
               </div>
               <div className="flex justify-between items-center">
                  <div>
                     <p className="text-3xl font-bold text-white">{selectedClient.contract.nextInvoiceAmount.toFixed(2)} € <span className="text-sm font-normal text-gray-500">TTC</span></p>
                     <p className="text-xs text-gray-500 mt-1">Prévu le {selectedClient.contract.renewalDate}</p>
                  </div>
                  <button className="px-4 py-2 bg-white/[0.08] hover:bg-white/20 rounded-full text-sm text-white transition-colors">
                     Générer pro-forma
                  </button>
               </div>
            </div>
          </div>

        </div>
      </div>
    );
  }

  // --- RENDER LIST VIEW ---
  return (
    <div className="animate-in fade-in duration-500">

      {/* Header Dashboard */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-6">
        <div>
          <h1 className="text-3xl font-sans font-bold text-white mb-2">Base Clients</h1>
          <p className="text-gray-500">Gérez vos contrats, facturations et relations clients.</p>
        </div>

        <div className="flex gap-3 items-center">
           {/* Quota indicateur */}
           {user && user.plan !== 'enterprise' && (
             <div className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-white/[0.03] border border-white/[0.06] rounded-xl">
               <span className="text-[11px] text-gray-500">Clients directs</span>
               <span className={`text-sm font-bold ${isAtLimit ? 'text-red-400' : 'text-white'}`}>
                 {totalDirectCount}/{maxClients}
               </span>
             </div>
           )}
           <button
             onClick={handleExportCSV}
             className="px-4 py-2.5 bg-white/[0.04] hover:bg-purple-500/10 border border-white/[0.08] rounded-2xl text-gray-300 flex items-center gap-2 transition-colors"
           >
              <Download size={18} /> Export CSV
           </button>
           <button
             onClick={handleOpenNewClient}
             className={`px-4 py-2.5 font-bold rounded-2xl flex items-center gap-2 transition-colors shadow-lg ${
               isAtLimit
                 ? 'bg-white/[0.06] border border-white/[0.08] text-gray-400 shadow-none cursor-not-allowed'
                 : 'bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white shadow-purple-500/20'
             }`}
           >
              <Plus size={18} /> Nouveau Client
              {isAtLimit && <span className="text-[10px] ml-1 text-red-400">Limite</span>}
           </button>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] flex items-center gap-4">
           <div className="w-12 h-12 rounded-full bg-purple-500/10 flex items-center justify-center text-purple-300">
              <Wallet size={24} />
           </div>
           <div>
              <p className="text-sm text-gray-500">MRR Total</p>
              <p className="text-2xl font-bold text-white">{totalMRR} €</p>
           </div>
        </div>
        <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] flex items-center gap-4">
           <div className="w-12 h-12 rounded-full bg-blue-500/10 flex items-center justify-center text-blue-400">
              <Users size={24} />
           </div>
           <div>
              <p className="text-sm text-gray-500">Clients Actifs</p>
              <p className="text-2xl font-bold text-white">{activeCount}</p>
           </div>
        </div>
        <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] flex items-center gap-4">
           <div className="w-12 h-12 rounded-full bg-orange-500/10 flex items-center justify-center text-orange-400">
              <ClipboardList size={24} />
           </div>
           <div>
              <p className="text-sm text-gray-500">Via Missions</p>
              <p className="text-2xl font-bold text-white">{missionClientCount}</p>
           </div>
        </div>
        <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] flex items-center gap-4">
           <div className="w-12 h-12 rounded-full bg-purple-500/10 flex items-center justify-center text-purple-400">
              <TrendingUp size={24} />
           </div>
           <div>
              <p className="text-sm text-gray-500">Total Clients</p>
              <p className="text-2xl font-bold text-white">{clients.length}</p>
           </div>
        </div>
      </div>

      {/* Filters & Search */}
      <div className="flex flex-col gap-3 mb-6 bg-[#111111] p-3 rounded-2xl border border-white/[0.08]">
        <div className="flex flex-col md:flex-row justify-between items-center gap-3">
          <div className="relative w-full md:w-96">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input
                type="text"
                placeholder="Rechercher une entreprise, un contact ou un email..."
                className="w-full bg-[#0f1115] border border-white/[0.08] rounded-xl pl-10 pr-4 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
          </div>
          <div className="flex gap-2 w-full md:w-auto overflow-x-auto no-scrollbar">
              {(['all', 'active', 'pending', 'churned'] as const).map(status => (
                <button
                    key={status}
                    onClick={() => setStatusFilter(status)}
                    className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors whitespace-nowrap ${
                      statusFilter === status ? 'bg-purple-500/20 text-purple-300 border border-purple-500/30' : 'text-gray-500 hover:text-gray-300 border border-transparent'
                    }`}
                >
                    {status === 'all' ? 'Tous' : status === 'active' ? 'Actifs' : status === 'pending' ? 'En attente' : 'Inactifs'}
                </button>
              ))}
          </div>
        </div>
        {/* Source filter */}
        <div className="flex gap-2">
          {([
            { key: 'all' as const, label: 'Toutes sources' },
            { key: 'direct' as const, label: 'Clients directs' },
            { key: 'mission' as const, label: 'Via Ordres de Mission' },
          ]).map(f => (
            <button
              key={f.key}
              onClick={() => setSourceFilter(f.key)}
              className={`px-3 py-1 rounded-lg text-[11px] font-medium transition-colors ${
                sourceFilter === f.key
                  ? 'bg-orange-500/15 text-orange-300 border border-orange-500/25'
                  : 'text-gray-600 hover:text-gray-400 border border-transparent'
              }`}
            >
              {f.label}
            </button>
          ))}
        </div>
      </div>

      {/* Clients Table */}
      <div className="bg-[#111111] border border-white/[0.08] rounded-2xl overflow-hidden">
         <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
               <thead>
                  <tr className="border-b border-white/[0.08] text-xs text-gray-500 uppercase bg-white/[0.02]">
                     <th className="p-4 font-medium pl-6">Entreprise</th>
                     <th className="p-4 font-medium">Contact</th>
                     <th className="p-4 font-medium">Plan</th>
                     <th className="p-4 font-medium">Statut</th>
                     <th className="p-4 font-medium">Source</th>
                     <th className="p-4 font-medium">Score AEO</th>
                     <th className="p-4 font-medium text-right pr-6">Revenus</th>
                  </tr>
               </thead>
               <tbody className="text-sm divide-y divide-white/5">
                  {filteredClients.map((client) => (
                     <tr
                        key={client.id}
                        className="hover:bg-white/[0.02] transition-colors cursor-pointer group"
                        onClick={() => setSelectedClient(client)}
                     >
                        <td className="p-4 pl-6">
                           <div className="flex items-center gap-3">
                              <div className="w-8 h-8 rounded-full bg-white/[0.04] border border-white/[0.08] flex items-center justify-center text-xs font-bold text-gray-300">
                                 {client.avatar}
                              </div>
                              <div>
                                <span className="font-bold text-white group-hover:text-purple-400 transition-colors block">{client.companyName}</span>
                                {client.mission && (
                                  <span className="text-[10px] text-gray-600 font-mono">{client.mission.missionId}</span>
                                )}
                              </div>
                           </div>
                        </td>
                        <td className="p-4">
                           <div className="flex flex-col">
                              <span className="text-gray-300">{client.contactName}</span>
                              <span className="text-xs text-gray-500">{client.email}</span>
                           </div>
                        </td>
                        <td className="p-4">
                           <span className={`px-2 py-1 rounded text-xs font-bold border ${
                              client.plan === 'Agency' ? 'bg-purple-500/10 text-purple-400 border-white/[0.1]' :
                              client.plan === 'Pro' ? 'bg-blue-500/10 text-blue-400 border-blue-500/20' :
                              'bg-gray-500/10 text-gray-500 border-gray-500/20'
                           }`}>
                              {client.plan}
                           </span>
                        </td>
                        <td className="p-4">
                           <div className="flex items-center gap-2">
                              <div className={`w-2 h-2 rounded-full ${
                                 client.status === 'active' ? 'bg-green-400' :
                                 client.status === 'pending' ? 'bg-amber-400 animate-pulse' :
                                 'bg-red-500'
                              }`}></div>
                              <span className="text-gray-300">{
                                client.status === 'active' ? 'Actif' :
                                client.status === 'pending' ? 'En attente' : 'Inactif'
                              }</span>
                           </div>
                        </td>
                        <td className="p-4">
                          <span className={`px-2 py-0.5 rounded text-[10px] font-semibold border ${
                            client.source === 'mission'
                              ? 'bg-orange-500/10 text-orange-400 border-orange-500/20'
                              : 'bg-white/5 text-gray-500 border-white/10'
                          }`}>
                            {client.source === 'mission' ? 'Mission' : 'Direct'}
                          </span>
                        </td>
                        <td className="p-4">
                          {client.mission ? (
                            <span className={`font-bold ${getScoreColor(client.mission.aeoScore)}`}>
                              {client.mission.aeoScore}/100
                            </span>
                          ) : (
                            <span className="text-gray-600">-</span>
                          )}
                        </td>
                        <td className="p-4 text-right pr-6 font-bold text-white">
                           {client.mrr > 0 ? `${client.mrr} €/mois` : '-'}
                        </td>
                     </tr>
                  ))}
               </tbody>
            </table>
         </div>
         {filteredClients.length === 0 && (
            <div className="p-12 text-center text-gray-500">
               Aucun client ne correspond à votre recherche.
            </div>
         )}
      </div>

      {/* Footer bar */}
      <div className="mt-4 flex items-center justify-between text-xs text-gray-600 px-2">
        <span>{filteredClients.length} client{filteredClients.length > 1 ? 's' : ''} affiché{filteredClients.length > 1 ? 's' : ''} sur {clients.length}</span>
        <span>Export : {filteredClients.length} lignes</span>
      </div>

      {/* --- ALERTE LIMITE ATTEINTE --- */}
      {showLimitAlert && createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setShowLimitAlert(false)} />
          <div className="relative bg-[#111111] border border-red-500/20 rounded-2xl w-full max-w-md shadow-2xl shadow-red-500/5 overflow-hidden max-h-[90vh] overflow-y-auto">
            <div className="bg-gradient-to-r from-red-500/10 to-orange-500/10 border-b border-white/[0.06] p-6 text-center">
              <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-red-500/10 border border-red-500/20 flex items-center justify-center">
                <AlertCircle size={32} className="text-red-400" />
              </div>
              <h2 className="text-xl font-bold text-white mb-2">Limite de clients atteinte</h2>
              <p className="text-sm text-gray-400">
                Votre plan <span className="font-bold text-white">{planLabel}</span> autorise <span className="font-bold text-white">{maxClients}</span> client{maxClients > 1 ? 's' : ''} direct{maxClients > 1 ? 's' : ''} maximum.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div className="flex items-center justify-between p-3 bg-white/[0.03] rounded-xl border border-white/[0.06]">
                <span className="text-sm text-gray-400">Clients directs utilisés</span>
                <span className="text-lg font-bold text-red-400">{totalDirectCount}/{maxClients}</span>
              </div>
              <div className="p-3 bg-orange-500/5 border border-orange-500/10 rounded-xl">
                <p className="text-xs text-orange-300/80 flex items-center gap-2">
                  <ClipboardList size={14} className="text-orange-400 shrink-0" />
                  Les clients reçus via <span className="font-bold">Ordres de Mission</span> ne sont pas soumis à cette limite.
                </p>
              </div>
              <div className="flex gap-3">
                <button
                  onClick={() => setShowLimitAlert(false)}
                  className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.08] rounded-xl transition-colors"
                >
                  Fermer
                </button>
                <button
                  onClick={() => {
                    setShowLimitAlert(false);
                    onNavigate('account');
                  }}
                  className="flex-1 px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-colors shadow-lg shadow-purple-500/20"
                >
                  <Zap size={16} /> Upgrader
                </button>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* --- MODAL NOUVEAU CLIENT --- */}
      {showNewClientModal && createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setShowNewClientModal(false)} />
          <div className="relative bg-[#111111] border border-white/[0.08] rounded-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto shadow-2xl">
            {/* Modal Header */}
            <div className="sticky top-0 bg-[#111111] border-b border-white/[0.06] p-5 flex items-center justify-between rounded-t-2xl z-10">
              <h2 className="text-lg font-bold text-white flex items-center gap-2">
                <Plus size={18} className="text-purple-400" />
                Nouveau Client
              </h2>
              <button
                onClick={() => setShowNewClientModal(false)}
                className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/10 transition-colors"
              >
                <X size={16} />
              </button>
            </div>

            {/* Modal Body */}
            <div className="p-5 space-y-4">
              {/* Entreprise */}
              <div>
                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Entreprise *</label>
                <input
                  type="text"
                  value={newClient.companyName}
                  onChange={e => setNewClient(p => ({ ...p, companyName: e.target.value }))}
                  placeholder="Nom de l'entreprise"
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                />
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Nom du contact *</label>
                  <input
                    type="text"
                    value={newClient.contactName}
                    onChange={e => setNewClient(p => ({ ...p, contactName: e.target.value }))}
                    placeholder="Prénom Nom"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                  />
                </div>
                <div>
                  <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Rôle</label>
                  <input
                    type="text"
                    value={newClient.role}
                    onChange={e => setNewClient(p => ({ ...p, role: e.target.value }))}
                    placeholder="CEO, CTO, CMO..."
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Email *</label>
                  <input
                    type="email"
                    value={newClient.email}
                    onChange={e => setNewClient(p => ({ ...p, email: e.target.value }))}
                    placeholder="email@entreprise.com"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                  />
                </div>
                <div>
                  <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Téléphone</label>
                  <input
                    type="tel"
                    value={newClient.phone}
                    onChange={e => setNewClient(p => ({ ...p, phone: e.target.value }))}
                    placeholder="+33 6 00 00 00 00"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Plan</label>
                <div className="flex gap-2">
                  {(['Starter', 'Pro', 'Agency'] as const).map(plan => (
                    <button
                      key={plan}
                      onClick={() => setNewClient(p => ({ ...p, plan }))}
                      className={`flex-1 py-2 rounded-xl text-sm font-medium border transition-all ${
                        newClient.plan === plan
                          ? plan === 'Agency'
                            ? 'bg-purple-500/20 border-purple-500/30 text-purple-300'
                            : plan === 'Pro'
                              ? 'bg-blue-500/20 border-blue-500/30 text-blue-300'
                              : 'bg-white/10 border-white/20 text-white'
                          : 'bg-white/[0.03] border-white/[0.06] text-gray-500 hover:bg-white/[0.06]'
                      }`}
                    >
                      {plan}
                    </button>
                  ))}
                </div>
              </div>

              <div className="border-t border-white/[0.06] pt-4">
                <p className="text-xs text-gray-500 uppercase tracking-wider mb-3">Informations légales (optionnel)</p>
                <div className="space-y-3">
                  <input
                    type="text"
                    value={newClient.address}
                    onChange={e => setNewClient(p => ({ ...p, address: e.target.value }))}
                    placeholder="Adresse de facturation"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                  />
                  <div className="grid grid-cols-2 gap-3">
                    <input
                      type="text"
                      value={newClient.siret}
                      onChange={e => setNewClient(p => ({ ...p, siret: e.target.value }))}
                      placeholder="SIRET"
                      className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                    />
                    <input
                      type="text"
                      value={newClient.vatNumber}
                      onChange={e => setNewClient(p => ({ ...p, vatNumber: e.target.value }))}
                      placeholder="N° TVA"
                      className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Modal Footer */}
            <div className="sticky bottom-0 bg-[#111111] border-t border-white/[0.06] p-5 flex items-center justify-between rounded-b-2xl">
              <button
                onClick={() => setShowNewClientModal(false)}
                className="px-4 py-2.5 text-sm text-gray-400 hover:text-white transition-colors"
              >
                Annuler
              </button>
              <button
                onClick={handleAddClient}
                disabled={!newClient.companyName.trim() || !newClient.contactName.trim() || !newClient.email.trim()}
                className="px-6 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 disabled:opacity-40 disabled:cursor-not-allowed text-white font-bold rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-purple-500/20"
              >
                <Save size={16} />
                Créer le client
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
};

export default Clients;
"}

{"content":"import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { User } from '../types';
import {
  User as UserIcon, Mail, Key, Bell, LogOut, Fuel, Check, Copy, AlertTriangle,
  Droplet, Database, CreditCard, ShieldCheck, LayoutList, History, FileText,
  Download, Loader2, Sparkles, FolderOpen, TrendingUp, Zap, ArrowUpRight,
  Palette, Eye, Globe, Lock
} from 'lucide-react';
import jsPDF from 'jspdf';
import StripeCheckout from '../components/StripeCheckout';
import PageHeader from '../components/layout/PageHeader';

interface AccountProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (view: any) => void;
  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
  projectCount: number;
  maxProjects: number;
  initialTab?: 'profile' | 'subscription' | 'billing' | 'whitelabel';
}

const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate, onUpgrade, projectCount, maxProjects, initialTab = 'profile' }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'subscription' | 'billing' | 'whitelabel'>(initialTab);
  const [apiKeyCopied, setApiKeyCopied] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
  const [paidAmount, setPaidAmount] = useState(0);
  const [paymentHistory, setPaymentHistory] = useState([
    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
  ]);

  // White Label state
  const [whiteLabel, setWhiteLabel] = useState(() => {
    try {
      const saved = localStorage.getItem('citedby-whitelabel');
      return saved ? JSON.parse(saved) : { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' };
    } catch { return { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' }; }
  });
  const [wlSaved, setWlSaved] = useState(false);

  const handleSaveWhiteLabel = () => {
    localStorage.setItem('citedby-whitelabel', JSON.stringify(whiteLabel));
    setWlSaved(true);
    setTimeout(() => setWlSaved(false), 2000);
  };

  const generateBrandedPdf = () => {
    const doc = new jsPDF();
    doc.setFillColor(whiteLabel.primaryColor || '#a855f7');
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text(whiteLabel.agencyName || 'Mon Agence', 20, 25);
    doc.setFontSize(10);
    doc.text('Rapport AEO — Marque Blanche', 20, 33);
    doc.setTextColor(60, 60, 60);
    doc.setFontSize(12);
    doc.text('Rapport de Visibilité IA', 20, 55);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Généré le ${new Date().toLocaleDateString('fr-FR')}`, 20, 63);
    doc.text(`Client : ${user?.name || 'N/A'}`, 20, 70);
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('Score Global AEO', 20, 90);
    doc.setFontSize(36);
    doc.setTextColor(whiteLabel.primaryColor || '#a855f7');
    doc.text('78/100', 20, 110);
    doc.setTextColor(100, 100, 100);
    doc.setFontSize(9);
    doc.text(`Powered by ${whiteLabel.agencyName || 'CitedBy.ai'}`, 20, 280);
    doc.save(`Rapport_${whiteLabel.agencyName || 'AEO'}_${Date.now()}.pdf`);
  };

  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  useEffect(() => {
    if (upgradeModal && paymentStep === 'success') { document.body.style.overflow = 'hidden'; }
    return () => { document.body.style.overflow = ''; };
  }, [upgradeModal, paymentStep]);

  if (!user) return null;

  // ── Helpers ──

  const handleCopyApiKey = () => {
    navigator.clipboard.writeText(`cb_pk_live_${user.id.substring(0, 8)}_${Math.random().toString(36).substr(2, 9)}`);
    setApiKeyCopied(true);
    setTimeout(() => setApiKeyCopied(false), 2000);
  };

  const getPlanDetails = (plan: string) => {
    switch (plan) {
      case 'enterprise':
        return { name: 'Agency', marketingName: 'La Citerne', icon: <Database size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-500 border-white/[0.1] shadow-[0_0_15px_rgba(168,85,247,0.1)]' };
      case 'pro':
        return { name: 'Pro', marketingName: 'La Pompe', icon: <Fuel size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-400 border-primary/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' };
      default:
        return { name: 'Starter', marketingName: 'Le Jerrican', icon: <Droplet size={14} />, style: 'bg-white/[0.04] text-gray-300 border-white/[0.08]' };
    }
  };

  const planDetails = getPlanDetails(user.plan);
  const projectPercentage = maxProjects >= 1000 ? 15 : Math.min((projectCount / maxProjects) * 100, 100);
  const isAtLimit = projectCount >= maxProjects && maxProjects < 1000;

  // ── Pricing data ──

  const plans = [
    {
      id: 'free', name: 'Starter', price: 29, period: '/mois',
      icon: <Droplet size={24} />, current: user.plan === 'free',
      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
      cta: 'Plan Actuel',
    },
    {
      id: 'pro', name: 'Pro', price: 89, period: '/mois', popular: true,
      icon: <Fuel size={24} />, current: user.plan === 'pro',
      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
      cta: 'Passer Pro',
    },
    {
      id: 'enterprise', name: 'Agency', price: 299, period: '/mois',
      icon: <Database size={24} />, current: user.plan === 'enterprise',
      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
      cta: 'Passer Agency',
    },
  ];

  // Prix du plan actuel de l'utilisateur
  const currentPlanPrice = user.plan === 'enterprise' ? 299 : user.plan === 'pro' ? 89 : 29;

  const handleUpgradeClick = (planId: string) => {
    const targetPlan = plans.find(p => p.id === planId);
    if (!targetPlan || targetPlan.current) return;
    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
    setPaymentStep('payment');
  };

  const handleProcessPayment = () => {
    if (!upgradeModal) return;
    setIsProcessing(true);
    setTimeout(() => {
      const amountPaid = upgradeModal.newPrice - currentPlanPrice;
      const now = new Date();
      const dateStr = now.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
      const invoiceNum = `INV-${now.getFullYear()}-${String(paymentHistory.length + 1).padStart(3, '0')}`;
      const newInvoice = {
        id: invoiceNum,
        date: dateStr,
        amount: amountPaid,
        desc: `Upgrade ${planDetails.name} → ${upgradeModal.planName} (Prorata)`,
        status: 'Payé',
      };
      setPaymentHistory(prev => [newInvoice, ...prev]);
      setPaidAmount(amountPaid);
      onUpgrade(upgradeModal.planId as any);
      setIsProcessing(false);
      setPaymentStep('success');
    }, 2500);
  };

  const handleCloseUpgradeModal = () => {
    setUpgradeModal(null);
    setPaymentStep('recap');
    setPaidAmount(0);
  };

  // ── Invoice PDF ──

  const generateInvoice = (payment: { id: string; date: string; amount: number; desc: string; status: string }) => {
    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text('CitedBy.ai', 20, 20);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Facture N° ${payment.id}`, 20, 30);
    doc.text(`Date : ${payment.date}`, 20, 35);
    doc.text('Facturé à :', 140, 30);
    doc.setFont('helvetica', 'bold');
    doc.text(user.name || 'Client', 140, 35);
    doc.setFont('helvetica', 'normal');
    doc.text(user.email || '', 140, 40);
    doc.line(20, 55, 190, 55);
    doc.setFont('helvetica', 'bold');
    doc.text('Description', 20, 62);
    doc.text('Montant HT', 160, 62);
    doc.line(20, 66, 190, 66);
    const priceHT = (payment.amount / 1.2).toFixed(2);
    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);
    doc.setFont('helvetica', 'normal');
    doc.text(payment.desc, 20, 75);
    doc.text(`${priceHT} €`, 160, 75);
    doc.line(20, 90, 190, 90);
    doc.text('Sous-total HT :', 130, 100);
    doc.text(`${priceHT} €`, 160, 100);
    doc.text('TVA (20%) :', 130, 107);
    doc.text(`${tva} €`, 160, 107);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.text('Total TTC :', 130, 117);
    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
    doc.setFontSize(8);
    doc.setFont('helvetica', 'italic');
    doc.text('Merci de votre confiance. Paiement effectué par CB.', 20, 140);
    doc.save(`Facture_${payment.id}.pdf`);
  };

  // ── Render ──

  return (
    <div className="animate-in fade-in duration-500">

      {/* ── STEP 2 : PLEINE PAGE DE PAIEMENT (comme Recharge.tsx) ── */}
      {upgradeModal && paymentStep === 'payment' && (
        <div className="animate-in fade-in slide-in-from-right duration-500">
          <StripeCheckout
            mode="subscription"
            productName={`Plan ${upgradeModal.planName}`}
            productDescription={`Upgrade ${planDetails.name} → ${upgradeModal.planName}`}
            amount={upgradeModal.newPrice - currentPlanPrice}
            amountDetails={[
              { label: `Nouveau plan (${upgradeModal.planName})`, value: `${upgradeModal.newPrice.toFixed(2)} €` },
              { label: `Crédit plan ${planDetails.name}`, value: `- ${currentPlanPrice.toFixed(2)} €` },
              { label: 'À payer aujourd\'hui', value: `${(upgradeModal.newPrice - currentPlanPrice).toFixed(2)} €`, highlight: true, separator: true },
            ]}
            userEmail={user.email}
            onConfirm={handleProcessPayment}
            onBack={() => setPaymentStep('recap')}
            isProcessing={isProcessing}
          />
        </div>
      )}

      {/* Contenu principal — masqué pendant le paiement */}
      {!(upgradeModal && paymentStep === 'payment') && (<>

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-purple-500/20 border-2 border-black">
            {user.name.charAt(0).toUpperCase()}
          </div>
          <div>
            <h1 className="text-3xl font-sans font-bold text-white">Compte & Plan</h1>
            <p className="text-gray-500 text-sm">Profil, abonnement, facturation</p>
          </div>
        </div>
        <button
          onClick={onLogout}
          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-colors text-sm font-medium"
        >
          <LogOut size={16} /> Déconnexion
        </button>
      </div>

      {/* Tabs */}
      <div className="flex justify-center mb-10">
        <div className="inline-flex bg-white/[0.04] p-1.5 rounded-2xl border border-white/[0.08] flex-wrap justify-center gap-1">
          {([
            { key: 'profile', icon: UserIcon, label: 'Profil' },
            { key: 'subscription', icon: ShieldCheck, label: 'Abonnement & Projets' },
            { key: 'billing', icon: CreditCard, label: 'Facturation' },
            ...(user.plan === 'enterprise' ? [{ key: 'whitelabel' as const, icon: Palette, label: 'White Label' }] : []),
          ] as const).map(tab => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
                activeTab === tab.key
                  ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg'
                  : 'text-gray-500 hover:text-white'
              }`}
            >
              <tab.icon size={16} /> {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* ═══════════════════════════════════════════════
          TAB 1 : PROFIL
          ═══════════════════════════════════════════════ */}
      {activeTab === 'profile' && (
        <div className="animate-in fade-in duration-300 grid lg:grid-cols-3 gap-8">

          {/* Left: Profile Card + GTO Balance */}
          <div className="space-y-6">
            {/* Profile summary */}
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] text-center relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-white/5 to-transparent"></div>
              <div className="relative">
                <div className="w-24 h-24 mx-auto bg-gradient-to-br from-purple-500 to-violet-600 rounded-full flex items-center justify-center text-white font-bold text-4xl shadow-xl shadow-purple-500/20 mb-4 border-4 border-black">
                  {user.name.charAt(0).toUpperCase()}
                </div>
                <h2 className="text-xl font-bold text-white">{user.name}</h2>
                <p className="text-sm text-gray-500 mb-4">{user.email}</p>
                <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full border text-xs font-bold uppercase tracking-wide ${planDetails.style}`}>
                  {planDetails.icon}
                  {planDetails.marketingName}
                </div>
              </div>
            </div>

            {/* GTO Gas balance */}
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
                  <Fuel size={24} />
                </div>
                <button
                  onClick={() => onNavigate('recharge')}
                  className="text-xs bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold px-3 py-1.5 rounded-full hover:brightness-110 transition-all"
                >
                  Recharger
                </button>
              </div>
              <p className="text-sm text-gray-500 mb-1">Solde GTO Gas</p>
              <div className="text-4xl font-bold text-white mb-2">{user.credits}</div>
              <div className="w-full bg-white/[0.08] h-1.5 rounded-full overflow-hidden">
                <div className="bg-purple-500 h-full rounded-full transition-all" style={{ width: `${Math.min((user.credits / 500) * 100, 100)}%` }}></div>
              </div>
              <p className="text-xs text-gray-500 mt-2">~{Math.floor(user.credits / 10)} audits restants</p>
            </div>
          </div>

          {/* Right: Settings */}
          <div className="lg:col-span-2 space-y-8">
            {/* API Keys */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <Key size={20} className="text-purple-400" /> Clés API & Intégrations
              </h3>
              <div className="bg-black/40 border border-white/[0.08] rounded-2xl p-4 flex items-center justify-between gap-4">
                <div className="flex-1 overflow-hidden">
                  <p className="text-xs text-gray-500 mb-1 uppercase tracking-wider">Clé Publique</p>
                  <code className="text-sm text-purple-300 font-mono block truncate">cb_pk_live_{user.id.substring(0, 8)}...</code>
                </div>
                <button
                  onClick={handleCopyApiKey}
                  className="p-2 hover:bg-purple-500/10 rounded-full transition-colors text-gray-500 hover:text-white"
                  title="Copier la clé"
                >
                  {apiKeyCopied ? <Check size={18} className="text-purple-400" /> : <Copy size={18} />}
                </button>
              </div>
              <p className="text-xs text-gray-500 mt-3">
                Cette clé permet d'utiliser l'API CitedBy.ai. Ne la partagez jamais.
              </p>
              <button
                onClick={() => onNavigate('api-developer')}
                className="mt-4 text-sm text-purple-400 hover:text-purple-300 transition-colors flex items-center gap-1.5 font-medium"
              >
                <ArrowUpRight size={14} /> Documentation API complète
              </button>
            </div>

            {/* Personal Info */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <UserIcon size={20} className="text-blue-400" /> Informations Personnelles
              </h3>
              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-500">Nom Complet</label>
                  <input type="text" defaultValue={user.name} className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-500">Email</label>
                  <input type="email" defaultValue={user.email} disabled className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-gray-500 cursor-not-allowed" />
                </div>
                <div className="space-y-2 md:col-span-2">
                  <label className="text-sm font-medium text-gray-500">Workspace / Entreprise</label>
                  <input type="text" defaultValue="Mon Espace Personnel" className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
                </div>
              </div>
              <div className="mt-6 flex justify-end">
                <button className="btn-gradient px-6 py-2.5 text-white font-bold text-sm">Enregistrer les modifications</button>
              </div>
            </div>

            {/* Notifications */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                <Bell size={20} className="text-purple-400" /> Préférences de notification
              </h3>
              <div className="space-y-4">
                {[
                  { label: "Rapport d'audit terminé", desc: 'Recevoir un email quand une analyse est finie.', default: true },
                  { label: 'Alerte de baisse de score', desc: 'Notification si le score AEO chute de plus de 10%.', default: true },
                  { label: 'Offres & Nouveautés', desc: 'Newsletters produit et mises à jour.', default: false },
                ].map((pref, i) => (
                  <div key={i} className="flex items-start justify-between pb-4 border-b border-white/[0.06] last:border-0 last:pb-0">
                    <div>
                      <p className="text-sm font-medium text-white">{pref.label}</p>
                      <p className="text-xs text-gray-500 mt-0.5">{pref.desc}</p>
                    </div>
                    <label className="relative inline-flex items-center cursor-pointer">
                      <input type="checkbox" defaultChecked={pref.default} className="sr-only peer" />
                      <div className="w-11 h-6 bg-gray-700 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-purple-500"></div>
                    </label>
                  </div>
                ))}
              </div>
            </div>

            {/* Danger Zone */}
            <div className="border border-red-500/20 rounded-2xl p-6 bg-red-500/5">
              <h3 className="text-sm font-bold text-red-400 flex items-center gap-2 mb-2">
                <AlertTriangle size={16} /> Zone de danger
              </h3>
              <p className="text-xs text-gray-500 mb-4">La suppression du compte est irréversible. Toutes vos données seront perdues.</p>
              <button className="text-xs font-bold text-red-500 hover:text-red-400 border border-red-500/30 hover:bg-red-500/10 px-4 py-2 rounded-full transition-colors">
                Supprimer mon compte
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ═══════════════════════════════════════════════
          TAB 2 : ABONNEMENT & PROJETS
          ═══════════════════════════════════════════════ */}
      {activeTab === 'subscription' && (
        <div className="animate-in fade-in duration-300 space-y-8">

          {/* Project Counter + Upgrade Banner */}
          <div className="grid md:grid-cols-2 gap-6">

            {/* Project consumption counter */}
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
              <div className="absolute top-0 right-0 w-40 h-40 bg-purple-500/5 blur-3xl"></div>
              <div className="flex items-center gap-3 mb-5">
                <div className="p-3 bg-purple-500/10 rounded-2xl">
                  <FolderOpen size={22} className="text-purple-400" />
                </div>
                <div>
                  <p className="text-sm text-gray-500">Projets ce mois</p>
                  <p className="text-xs text-gray-600">Renouvellement mensuel automatique</p>
                </div>
              </div>

              <div className="flex items-baseline gap-2 mb-3">
                <span className="text-5xl font-bold text-white">{projectCount}</span>
                <span className="text-2xl text-gray-600 font-bold">/</span>
                <span className="text-2xl text-gray-500 font-bold">{maxProjects >= 1000 ? '∞' : maxProjects}</span>
              </div>

              <div className="w-full bg-white/[0.06] h-2.5 rounded-full overflow-hidden mb-3">
                <div
                  className={`h-full rounded-full transition-all duration-500 ${
                    isAtLimit ? 'bg-red-500' : projectPercentage > 66 ? 'bg-yellow-500' : 'bg-purple-500'
                  }`}
                  style={{ width: `${projectPercentage}%` }}
                ></div>
              </div>

              {isAtLimit ? (
                <div className="flex items-center gap-2 text-red-400 text-sm font-medium">
                  <AlertTriangle size={14} />
                  Limite atteinte — Passez au plan supérieur
                </div>
              ) : (
                <p className="text-xs text-gray-500">
                  {maxProjects >= 1000 ? 'Projets illimités avec votre plan Agency' : `${maxProjects - projectCount} projet${maxProjects - projectCount > 1 ? 's' : ''} restant${maxProjects - projectCount > 1 ? 's' : ''} ce mois`}
                </p>
              )}
            </div>

            {/* GTO Gas + Credits */}
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
              <div className="flex items-center gap-3 mb-5">
                <div className="p-3 bg-purple-500/10 rounded-2xl">
                  <Fuel size={22} className="text-purple-400" />
                </div>
                <div>
                  <p className="text-sm text-gray-500">Solde GTO Gas</p>
                  <p className="text-xs text-gray-600">Crédits de génération IA</p>
                </div>
              </div>

              <div className="flex items-baseline gap-2 mb-3">
                <span className="text-5xl font-bold text-white">{user.credits}</span>
                <span className="text-lg text-gray-500">crédits</span>
              </div>

              <div className="w-full bg-white/[0.06] h-2.5 rounded-full overflow-hidden mb-3">
                <div className="h-full bg-purple-500 rounded-full transition-all" style={{ width: `${Math.min((user.credits / 500) * 100, 100)}%` }}></div>
              </div>

              <div className="flex items-center justify-between">
                <p className="text-xs text-gray-500">~{Math.floor(user.credits / 10)} audits restants</p>
                <button
                  onClick={() => onNavigate('recharge')}
                  className="text-xs bg-white/[0.06] hover:bg-purple-500/10 border border-white/[0.08] text-purple-400 font-bold px-3 py-1.5 rounded-full transition-colors"
                >
                  Recharger
                </button>
              </div>
            </div>
          </div>

          {/* Upgrade Banner (only if not enterprise) */}
          {user.plan !== 'enterprise' && (
            <div className="relative ninja-card rounded-2xl border border-purple-500/30 overflow-hidden">
              <div className="absolute inset-0 bg-gradient-to-r from-purple-500/10 via-violet-500/5 to-transparent"></div>
              <div className="relative p-8 flex flex-col md:flex-row items-center gap-6">
                <div className="p-4 bg-purple-500/10 rounded-2xl shrink-0">
                  <Zap size={32} className="text-purple-400" />
                </div>
                <div className="flex-1 text-center md:text-left">
                  <h3 className="text-xl font-bold text-white mb-2">
                    {user.plan === 'free' ? 'Passez au Plan Pro' : 'Passez à Agency'}
                  </h3>
                  <p className="text-gray-400 text-sm max-w-lg">
                    {user.plan === 'free'
                      ? 'Débloquez 3 projets/mois, le monitoring continu, l\'indexation IA et les rapports PDF marque blanche.'
                      : 'Projets illimités, Account Manager dédié, API complète, SSO et formation AEO équipe.'}
                  </p>
                  <div className="flex flex-wrap gap-3 mt-3">
                    {(user.plan === 'free'
                      ? ['3 Projets/mois', 'Monitoring continu', 'Indexation IA']
                      : ['Projets illimités', 'API Full Access', 'SSO']
                    ).map(feat => (
                      <span key={feat} className="inline-flex items-center gap-1.5 text-xs bg-purple-500/10 text-purple-300 px-2.5 py-1 rounded-full border border-purple-500/20">
                        <Check size={12} /> {feat}
                      </span>
                    ))}
                  </div>
                </div>
                <div className="shrink-0 text-center">
                  <p className="text-3xl font-bold text-white mb-1">
                    {user.plan === 'free' ? '89€' : '299€'}
                    <span className="text-sm text-gray-500 font-normal">/mois</span>
                  </p>
                  <button
                    onClick={() => handleUpgradeClick(user.plan === 'free' ? 'pro' : 'enterprise')}
                    disabled={isProcessing}
                    className="mt-2 px-8 py-3 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-2xl shadow-lg shadow-purple-500/20 transition-all flex items-center gap-2"
                  >
                    {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <><ArrowUpRight size={18} /> Upgrade</>}
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* Current Plan Summary */}
          <div className="ninja-card p-8 rounded-2xl border border-white/[0.08] relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/10 blur-3xl -z-10"></div>
            <div className="flex flex-col md:flex-row justify-between items-start gap-6 mb-8">
              <div>
                <p className="text-sm text-gray-500 uppercase tracking-wider mb-1">Plan Actuel</p>
                <h3 className="text-3xl font-bold text-white capitalize">{planDetails.name}</h3>
                <div className="flex items-center gap-2 mt-2">
                  <span className="w-2 h-2 rounded-full bg-purple-400 animate-pulse"></span>
                  <span className="text-xs text-purple-300 font-bold">Actif • Renouvellement le 01/04/2024</span>
                </div>
              </div>
              <div className="w-12 h-12 rounded-2xl bg-white/[0.04] flex items-center justify-center text-white">
                {user.plan === 'pro' ? <Fuel /> : user.plan === 'enterprise' ? <Database /> : <Droplet />}
              </div>
            </div>

            <div className="flex gap-4">
              <button className="px-4 py-3 bg-white/[0.04] text-gray-300 font-bold rounded-2xl hover:bg-purple-500/10 transition-colors border border-white/[0.08]">
                Gérer Stripe
              </button>
            </div>
          </div>

          {/* Pricing Cards */}
          <div>
            <h3 className="text-lg font-bold text-white mb-6 text-center">Comparer les offres</h3>
            <div className="grid md:grid-cols-3 gap-6">
              {plans.map((plan) => (
                <div
                  key={plan.id}
                  className={`relative ninja-card rounded-2xl p-6 border flex flex-col transition-all ${
                    plan.popular
                      ? 'border-purple-500 bg-white/[0.04] shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
                      : 'border-white/[0.08] hover:border-white/20'
                  } ${plan.current ? 'opacity-75 grayscale-[0.5]' : ''}`}
                >
                  {plan.popular && (
                    <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold text-xs px-4 py-1 rounded-full uppercase tracking-wider">
                      Recommandé
                    </div>
                  )}
                  <div className="mb-6 flex items-center justify-between">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${plan.popular ? 'bg-purple-500/20 text-purple-400' : 'bg-white/[0.04] text-gray-500'}`}>
                      {plan.icon}
                    </div>
                    {plan.current && (
                      <span className="bg-purple-500/10 text-purple-300 text-xs px-2 py-1 rounded border border-white/[0.1]">Actuel</span>
                    )}
                  </div>
                  <h3 className="text-xl font-bold text-white mb-2">{plan.name}</h3>
                  <div className="flex items-baseline gap-1 mb-6">
                    <span className="text-3xl font-bold text-white">{plan.price}€</span>
                    <span className="text-sm text-gray-500">{plan.period}</span>
                  </div>
                  <ul className="space-y-3 mb-8 flex-1">
                    {plan.features.map((feat, i) => (
                      <li
                        key={i}
                        className={`flex items-start gap-3 text-sm ${
                          feat === 'Indexation IA' ? 'text-white font-bold bg-white/[0.04] -mx-2 p-2 rounded-full' : 'text-gray-300'
                        }`}
                      >
                        {feat === 'Indexation IA' ? (
                          <Sparkles size={16} className="mt-0.5 text-purple-400 shrink-0 animate-pulse" />
                        ) : (
                          <Check size={16} className={`mt-0.5 ${plan.popular ? 'text-purple-400' : 'text-gray-500'} shrink-0`} />
                        )}
                        {feat}
                      </li>
                    ))}
                  </ul>
                  <button
                    onClick={() => handleUpgradeClick(plan.id)}
                    disabled={plan.current || isProcessing}
                    className={`w-full py-3 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${
                      plan.popular
                        ? 'bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white shadow-lg shadow-purple-500/20'
                        : 'bg-white/[0.08] hover:bg-purple-500/20 text-white border border-white/[0.08]'
                    } ${plan.current ? 'cursor-not-allowed opacity-50' : ''}`}
                  >
                    {isProcessing && !plan.current ? <Loader2 className="animate-spin" /> : plan.cta}
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ═══════════════════════════════════════════════
          TAB 3 : FACTURATION
          ═══════════════════════════════════════════════ */}
      {activeTab === 'billing' && (
        <div className="animate-in fade-in duration-300 space-y-8">

          {/* Payment Method + Billing Address */}
          <div className="grid md:grid-cols-2 gap-6">
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
              <h3 className="font-bold text-white mb-6 flex items-center gap-2">
                <CreditCard size={20} className="text-gray-500" /> Moyen de paiement
              </h3>
              <div className="flex items-center gap-4 bg-white/[0.04] p-4 rounded-2xl border border-white/[0.06] mb-4">
                <div className="w-10 h-6 bg-white rounded flex items-center justify-center text-xs font-bold text-gray-800">MC</div>
                <div>
                  <p className="text-sm font-bold text-white">•••• •••• •••• 4242</p>
                  <p className="text-xs text-gray-500">Expire le 12/25</p>
                </div>
                <button className="ml-auto text-xs text-purple-400 hover:underline">Modifier</button>
              </div>
            </div>

            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
              <h3 className="font-bold text-white mb-6">Adresse de facturation</h3>
              <div className="text-sm text-gray-400 space-y-1">
                <p className="text-white font-medium">{user.name}</p>
                <p>123 Avenue de l'Innovation</p>
                <p>75011 Paris, France</p>
                <p className="mt-2 text-xs text-gray-500">TVA: FR 12 345 678 901</p>
              </div>
              <button className="text-xs text-gray-500 hover:text-white transition-colors mt-4">
                Modifier l'adresse
              </button>
            </div>
          </div>

          {/* Invoice History */}
          <div className="ninja-card rounded-2xl border border-white/[0.08] overflow-hidden">
            <div className="p-6 border-b border-white/[0.08] flex justify-between items-center bg-white/[0.04]">
              <h3 className="font-bold text-white flex items-center gap-2">
                <FileText size={20} className="text-gray-500" /> Historique des paiements
              </h3>
              <button className="text-xs bg-white/[0.04] hover:bg-purple-500/10 border border-white/[0.08] px-3 py-1.5 rounded-full text-gray-300 transition-colors">
                Tout télécharger
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-black text-xs text-gray-500 uppercase tracking-wider">
                    <th className="px-6 py-4 font-medium">Référence</th>
                    <th className="px-6 py-4 font-medium">Date</th>
                    <th className="px-6 py-4 font-medium">Description</th>
                    <th className="px-6 py-4 font-medium">Montant</th>
                    <th className="px-6 py-4 font-medium">Statut</th>
                    <th className="px-6 py-4 font-medium text-right">Facture</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {paymentHistory.map(payment => (
                    <tr key={payment.id} className="hover:bg-white/[0.02] transition-colors">
                      <td className="px-6 py-4 text-sm font-medium text-white">{payment.id}</td>
                      <td className="px-6 py-4 text-sm text-gray-500">{payment.date}</td>
                      <td className="px-6 py-4 text-sm text-gray-300">{payment.desc}</td>
                      <td className="px-6 py-4 text-sm font-bold text-white">{payment.amount.toFixed(2)} €</td>
                      <td className="px-6 py-4">
                        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium bg-purple-500/10 text-purple-300 border border-white/[0.1]">
                          <div className="w-1.5 h-1.5 rounded-full bg-purple-400"></div> Payé
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() => generateInvoice(payment)}
                          className="text-gray-500 hover:text-purple-400 transition-colors p-2 hover:bg-white/[0.04] rounded-full"
                          title="Télécharger PDF"
                        >
                          <Download size={18} />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="p-4 bg-white/[0.04] border-t border-white/[0.08] text-center">
              <button className="text-xs text-gray-500 hover:text-white transition-colors">Charger plus de factures...</button>
            </div>
          </div>
        </div>
      )}

      {/* ═══════════════════════════════════════════════
          TAB 4 : WHITE LABEL (Agency only)
          ═══════════════════════════════════════════════ */}
      {activeTab === 'whitelabel' && user.plan === 'enterprise' && (
        <div className="animate-in fade-in duration-300 space-y-8">

          {/* Badge Agency */}
          <div className="flex items-center gap-3 mb-2">
            <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1.5 rounded-full border border-purple-500/20 flex items-center gap-1.5">
              <Database size={12} /> Plan Agency
            </span>
            <span className="text-xs text-gray-500">Personnalisez le branding de vos rapports clients</span>
          </div>

          <div className="grid lg:grid-cols-2 gap-8">
            {/* Form */}
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08] space-y-6">
              <h3 className="font-bold text-white text-lg flex items-center gap-2">
                <Palette size={20} className="text-purple-400" /> Configuration White Label
              </h3>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm text-gray-400 mb-2">Logo URL</label>
                  <div className="flex gap-3">
                    <input
                      type="url"
                      value={whiteLabel.logoUrl}
                      onChange={e => setWhiteLabel((p: any) => ({ ...p, logoUrl: e.target.value }))}
                      placeholder="https://mon-agence.com/logo.png"
                      className="flex-1 bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:border-purple-500/50 focus:outline-none transition-colors"
                    />
                    {whiteLabel.logoUrl && (
                      <div className="w-10 h-10 rounded-lg border border-white/[0.08] bg-white/[0.04] flex items-center justify-center overflow-hidden">
                        <img src={whiteLabel.logoUrl} alt="Logo" className="w-8 h-8 object-contain" onError={e => (e.currentTarget.style.display = 'none')} />
                      </div>
                    )}
                  </div>
                </div>

                <div>
                  <label className="block text-sm text-gray-400 mb-2">Nom de l'agence</label>
                  <input
                    type="text"
                    value={whiteLabel.agencyName}
                    onChange={e => setWhiteLabel((p: any) => ({ ...p, agencyName: e.target.value }))}
                    placeholder="Mon Agence AEO"
                    className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:border-purple-500/50 focus:outline-none transition-colors"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm text-gray-400 mb-2">Couleur primaire</label>
                    <div className="flex items-center gap-3">
                      <input
                        type="color"
                        value={whiteLabel.primaryColor}
                        onChange={e => setWhiteLabel((p: any) => ({ ...p, primaryColor: e.target.value }))}
                        className="w-10 h-10 rounded-lg border border-white/[0.08] cursor-pointer bg-transparent"
                      />
                      <input
                        type="text"
                        value={whiteLabel.primaryColor}
                        onChange={e => setWhiteLabel((p: any) => ({ ...p, primaryColor: e.target.value }))}
                        className="flex-1 bg-white/[0.04] border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white font-mono focus:border-purple-500/50 focus:outline-none"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm text-gray-400 mb-2">Couleur secondaire</label>
                    <div className="flex items-center gap-3">
                      <input
                        type="color"
                        value={whiteLabel.secondaryColor}
                        onChange={e => setWhiteLabel((p: any) => ({ ...p, secondaryColor: e.target.value }))}
                        className="w-10 h-10 rounded-lg border border-white/[0.08] cursor-pointer bg-transparent"
                      />
                      <input
                        type="text"
                        value={whiteLabel.secondaryColor}
                        onChange={e => setWhiteLabel((p: any) => ({ ...p, secondaryColor: e.target.value }))}
                        className="flex-1 bg-white/[0.04] border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white font-mono focus:border-purple-500/50 focus:outline-none"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex gap-3 pt-2">
                <button
                  onClick={handleSaveWhiteLabel}
                  className="flex-1 px-5 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl transition-all shadow-lg shadow-purple-500/20 text-sm flex items-center justify-center gap-2"
                >
                  {wlSaved ? <><Check size={16} /> Sauvegardé !</> : <><Palette size={16} /> Sauvegarder</>}
                </button>
                <button
                  onClick={generateBrandedPdf}
                  className="px-5 py-2.5 border border-white/[0.08] hover:bg-white/[0.04] text-gray-300 hover:text-white font-bold rounded-xl transition-all text-sm flex items-center gap-2"
                >
                  <Download size={16} /> Export PDF brandé
                </button>
              </div>
            </div>

            {/* Preview */}
            <div className="space-y-6">
              <div className="ninja-card rounded-2xl border border-white/[0.08] overflow-hidden">
                <div className="flex items-center gap-2 px-6 py-3 border-b border-white/[0.08]">
                  <Eye size={16} className="text-gray-500" />
                  <span className="text-sm font-bold text-gray-400">Aperçu en temps réel</span>
                </div>
                {/* Mini dashboard preview */}
                <div className="p-6 space-y-4" style={{ background: '#0a0a0f' }}>
                  {/* Header preview */}
                  <div className="flex items-center gap-3 pb-4 border-b border-white/[0.06]">
                    {whiteLabel.logoUrl ? (
                      <img src={whiteLabel.logoUrl} alt="Logo" className="w-8 h-8 rounded object-contain" onError={e => (e.currentTarget.style.display = 'none')} />
                    ) : (
                      <div className="w-8 h-8 rounded" style={{ background: whiteLabel.primaryColor }} />
                    )}
                    <span className="font-bold text-white text-sm">{whiteLabel.agencyName || 'Mon Agence'}</span>
                    <span className="ml-auto text-[10px] px-2 py-0.5 rounded-full border" style={{ borderColor: whiteLabel.primaryColor + '40', color: whiteLabel.primaryColor }}>Agency</span>
                  </div>
                  {/* Score preview */}
                  <div className="flex items-center gap-4">
                    <div className="w-16 h-16 rounded-full border-4 flex items-center justify-center" style={{ borderColor: whiteLabel.primaryColor }}>
                      <span className="text-lg font-bold text-white">78</span>
                    </div>
                    <div>
                      <p className="text-sm font-bold text-white">Score AEO Global</p>
                      <p className="text-xs text-gray-500">Dernière analyse : aujourd'hui</p>
                    </div>
                  </div>
                  {/* Bars preview */}
                  <div className="space-y-2">
                    {['Experience', 'Expertise', 'Authority', 'Trust'].map((label, i) => (
                      <div key={label} className="flex items-center gap-2">
                        <span className="text-[10px] text-gray-500 w-16">{label}</span>
                        <div className="flex-1 h-2 bg-white/[0.06] rounded-full overflow-hidden">
                          <div className="h-full rounded-full transition-all" style={{ width: `${[72, 85, 60, 90][i]}%`, background: `linear-gradient(90deg, ${whiteLabel.primaryColor}, ${whiteLabel.secondaryColor})` }} />
                        </div>
                        <span className="text-[10px] text-gray-400 w-6 text-right">{[72, 85, 60, 90][i]}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Custom domain - Coming Soon */}
              <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] opacity-60">
                <div className="flex items-center gap-3">
                  <div className="p-2.5 bg-purple-500/10 rounded-xl">
                    <Globe size={20} className="text-purple-400" />
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <h4 className="font-bold text-white text-sm">Domaine personnalisé</h4>
                      <span className="text-[10px] bg-amber-500/10 text-amber-400 px-2 py-0.5 rounded-full border border-amber-500/20">Coming Soon</span>
                    </div>
                    <p className="text-xs text-gray-500 mt-1">app.votre-agence.com — Accès client sous votre propre domaine</p>
                  </div>
                  <Lock size={16} className="text-gray-600" />
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      </>)}

      {/* MODAL SUCCÈS */}
      {upgradeModal && paymentStep === 'success' && createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => !isProcessing && handleCloseUpgradeModal()} />
          <div className="relative bg-[#111111] border border-purple-500/20 rounded-2xl w-full max-w-lg shadow-2xl shadow-purple-500/10 max-h-[90vh] overflow-y-auto">
            <div className="p-8 text-center space-y-5">
              <div className="w-20 h-20 mx-auto rounded-full bg-green-500/10 border-2 border-green-500/20 flex items-center justify-center">
                <Check size={40} className="text-green-400" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-white mb-2">Paiement confirmé !</h2>
                <p className="text-sm text-gray-400">
                  Vous êtes maintenant sur le plan <span className="text-purple-400 font-bold">{upgradeModal.planName}</span>.
                </p>
              </div>
              <div className="bg-white/[0.03] rounded-xl border border-white/[0.06] p-4 space-y-2 text-left">
                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">Montant débité</span>
                  <span className="text-white font-bold">{paidAmount.toFixed(2)} €</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">Moyen de paiement</span>
                  <span className="text-white">•••• 4242</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-400">Prochain renouvellement</span>
                  <span className="text-white">{upgradeModal.newPrice}€/mois</span>
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('subscription'); }}
                  className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.08] rounded-xl transition-colors">
                  Mon abonnement
                </button>
                <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('billing'); }}
                  className="flex-1 px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-500/20 text-sm">
                  <FileText size={16} /> Voir ma facture
                </button>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
};

export default Account;
"}

{"content":"import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { Fuel, Check, CreditCard, Loader2, Droplet, Database, ArrowLeft, ShieldCheck, Lock, Infinity, CheckCircle2, FileText, Download, XCircle, LayoutDashboard, RefreshCcw, Wrench } from 'lucide-react';
import jsPDF from 'jspdf';
import StripeCheckout from '../components/StripeCheckout';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  onRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
  user: User | null;
  onNavigate?: (view: string) => void;
  initialPackId?: number | null;
}

const Recharge: React.FC<Props> = ({ onBack, onRecharge, user, onNavigate, initialPackId }) => {
  const [viewMode, setViewMode] = useState<'list' | 'checkout' | 'result'>('list');
  const [paymentStatus, setPaymentStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [selectedPack, setSelectedPack] = useState<typeof packs[0] | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [invoiceId, setInvoiceId] = useState<string>('');

  const packs = [
    {
      id: 1,
      name: "Le Jerrican",
      amount: 50,
      price: 15,
      icon: <Droplet size={32} />,
      popular: false,
      level: 'free' as const,
      features: ["Idéal pour un audit ponctuel", "Valable 1 an"]
    },
    {
      id: 2,
      name: "La Pompe",
      amount: 200,
      price: 49,
      icon: <Fuel size={32} />,
      popular: true,
      level: 'pro' as const,
      features: ["Pour les optimisations régulières", "Support prioritaire", "+10% Bonus offert"]
    },
    {
      id: 3,
      name: "La Citerne",
      amount: 1000,
      price: 199,
      icon: <Database size={32} />,
      popular: false,
      level: 'enterprise' as const,
      features: ["Usage intensif / Agence", "Accès API Beta", "+20% Bonus offert"]
    }
  ];

  // Effet pour sélectionner automatiquement un pack si initialPackId est fourni
  useEffect(() => {
    if (initialPackId) {
        const targetPack = packs.find(p => p.id === initialPackId);
        if (targetPack) {
            setSelectedPack(targetPack);
            setViewMode('checkout');
        }
    }
  }, [initialPackId]);

  const handleSelectPack = (pack: typeof packs[0]) => {
    setSelectedPack(pack);
    setViewMode('checkout');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleConfirmPayment = () => {
    if (!selectedPack) return;
    setIsProcessing(true);
    setPaymentStatus('idle');
    
    // Simulation délai paiement et résultat aléatoire (90% de succès pour l'UX)
    setTimeout(() => {
      const isSuccess = Math.random() > 0.1;
      
      if (isSuccess) {
        onRecharge(selectedPack.amount, selectedPack.level);
        const newInvoiceId = `INV-${new Date().getFullYear()}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
        setInvoiceId(newInvoiceId);
        setPaymentStatus('success');
      } else {
        setPaymentStatus('error');
      }
      
      setIsProcessing(false);
      setViewMode('result');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 2000);
  };

  const generateInvoicePDF = () => {
    if (!selectedPack || !user) return;

    const doc = new jsPDF();
    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;
    const date = new Date().toLocaleDateString('fr-FR');

    // Header
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("CitedBy.ai", 20, 20);
    
    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("Facture N° " + invoiceId, 20, 30);
    doc.text("Date : " + date, 20, 35);

    // Client Info
    doc.text("Facturé à :", 140, 30);
    doc.setFont("helvetica", "bold");
    doc.text(user.name || "Client", 140, 35);
    doc.setFont("helvetica", "normal");
    doc.text(user.email || "", 140, 40);

    // Line Items Header
    doc.line(20, 55, 190, 55);
    doc.setFont("helvetica", "bold");
    doc.text("Description", 20, 62);
    doc.text("Quantité", 120, 62);
    doc.text("Montant HT", 160, 62);
    doc.line(20, 66, 190, 66);

    // Item
    doc.setFont("helvetica", "normal");
    doc.text(`Pack GTO Gas: ${selectedPack.name} (${selectedPack.amount} crédits)`, 20, 75);
    doc.text("1", 125, 75);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 75);

    // Totals
    doc.line(20, 90, 190, 90);
    doc.text("Sous-total HT :", 130, 100);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 100);
    
    doc.text("TVA (20%) :", 130, 107);
    doc.text(`${tva.toFixed(2)} €`, 160, 107);

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.text("Total TTC :", 130, 117);
    doc.text(`${totalTTC.toFixed(2)} €`, 160, 117);

    // Footer
    doc.setFontSize(8);
    doc.setFont("helvetica", "italic");
    doc.text("Merci de votre confiance. Cette facture a été réglée par carte bancaire.", 20, 140);
    doc.text("CitedBy Inc. - 123 Avenue de l'IA, Paris, France - SIRET 123 456 789", 20, 280);

    doc.save(`Facture_${invoiceId}.pdf`);
  };

  const renderList = () => (
    <div className="animate-in fade-in slide-in-from-left duration-500">
        <div className="text-center mb-16">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-accent/20 rounded-2xl mb-6 text-accent border border-accent/20 shadow-[0_0_30px_rgba(168,85,247,0.2)]">
            <Fuel size={32} />
            </div>
            <h1 className="text-4xl font-bold text-white mb-4">GTO <span className="gradient-text">Gas Station</span></h1>
            <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Le carburant essentiel pour propulser votre visibilité dans les moteurs de réponse.
            <br />
            <span className="text-sm mt-2 block text-gray-500">Solde actuel : <span className="text-white font-bold">{user?.credits || 0} Gas</span></span>
            </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8 w-full">
            {packs.map((pack) => (
            <div 
                key={pack.id} 
                className={`relative ninja-card p-8 flex flex-col transition-all duration-300 hover:transform hover:-translate-y-2 ${
                pack.popular
                    ? 'gradient-border !border-purple-500/30 shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
                    : ''
                }`}
            >
                {pack.popular && (
                <>
                <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-gradient-to-r from-purple-500 to-violet-500 text-white font-bold text-xs px-4 py-1.5 rounded-full uppercase tracking-wider shadow-lg shadow-purple-900/40 flex items-center gap-1.5">
                    <span className="animate-pulse">⭐</span> Meilleure Offre
                </div>
                <div className="absolute -top-px -left-px -right-px -bottom-px rounded-2xl bg-gradient-to-r from-purple-500/20 to-violet-500/20 -z-10 blur-sm" />
                </>
                )}

                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-6 ${pack.popular ? 'bg-accent/20 text-accent' : 'bg-white/[0.04] text-gray-500'}`}>
                {pack.icon}
                </div>

                <h3 className="text-xl font-bold text-white mb-2">{pack.name}</h3>
                <div className="flex items-baseline gap-1 mb-6">
                <span className="text-4xl font-bold gradient-text">{pack.amount}</span>
                <span className="text-sm text-gray-500 font-medium">Gas</span>
                </div>

                <ul className="space-y-3 mb-8 flex-1">
                {pack.features.map((feat, i) => (
                    <li key={i} className="flex items-start gap-3 text-sm text-gray-300">
                    <Check size={16} className={`mt-0.5 ${pack.popular ? 'text-accent' : 'text-gray-500'}`} />
                    {feat}
                    </li>
                ))}
                </ul>

                <div className="border-t border-white/[0.08] pt-6 mb-6">
                <div className="flex justify-between items-center mb-2">
                    <span className="text-gray-500">Prix HT</span>
                    <span className="text-xl font-bold text-white">{pack.price}€</span>
                </div>
                </div>

                <button
                onClick={() => handleSelectPack(pack)}
                className="w-full py-3.5 btn-gradient font-bold flex items-center justify-center gap-2 transition-all"
                >
                    <CreditCard size={18} /> Acheter
                </button>
            </div>
            ))}
        </div>

        <p className="text-center text-gray-500 text-xs mt-12">
            Paiement sécurisé via Stripe • Facture disponible instantanément • TVA non incluse
        </p>
    </div>
  );

  const renderCheckout = () => {
    if (!selectedPack) return null;

    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;

    // Logique Upsell
    const showCiterneUpsell = selectedPack.name !== "La Citerne";
    const showSubscriptionUpsell = user?.plan === 'free';

    return (
        <div className="animate-in fade-in slide-in-from-right duration-500">
            <div className="grid lg:grid-cols-12 gap-8">

                {/* Colonne Gauche: Paiement */}
                <div className="lg:col-span-8">
                    <StripeCheckout
                      mode="one-time"
                      productName={selectedPack.name}
                      productDescription={`Pack de ${selectedPack.amount} cr\u00e9dits GTO Gas`}
                      productIcon={selectedPack.icon}
                      amount={totalTTC}
                      amountDetails={[
                        { label: 'Prix Unitaire HT', value: `${priceHT.toFixed(2)} \u20ac` },
                        { label: 'Frais de service', value: '0.00 \u20ac' },
                        { label: 'TVA (20%)', value: `${tva.toFixed(2)} \u20ac` },
                        { label: 'Total TTC', value: `${totalTTC.toFixed(2)} \u20ac`, highlight: true, separator: true },
                      ]}
                      userEmail={user?.email}
                      onConfirm={handleConfirmPayment}
                      onBack={() => setViewMode('list')}
                      isProcessing={isProcessing}
                    />
                </div>

                {/* Colonne Droite: Upsells */}
                <div className="lg:col-span-4 space-y-4">
                    <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-2">Recommandé pour vous</h3>
                    
                    {/* Upsell Citerne */}
                    {showCiterneUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all" onClick={() => setSelectedPack(packs[2])}>
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg">
                                Meilleur Prix / Unité
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <Database size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">Passez à la Citerne</h4>
                                    <p className="text-xs text-purple-200/70">Économisez 60%</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                Obtenez <strong>1000 Crédits</strong> pour seulement 199€. Idéal pour les agences ou les refontes complètes.
                            </p>
                            <button className="w-full py-2 border border-white/[0.08] bg-white/[0.04] rounded-full text-purple-400 text-xs font-bold transition-colors hover:bg-white/[0.08]">
                                Choisir ce pack (199€)
                            </button>
                        </div>
                    )}

                    {/* Upsell Abonnement */}
                    {showSubscriptionUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all">
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg flex items-center gap-1">
                                <Infinity size={10} /> Mensuel
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <ShieldCheck size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">Activez le Monitoring</h4>
                                    <p className="text-xs text-purple-200/70">La Source</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                Ne perdez pas vos positions. Ajoutez l'indexation continue et la détection d'hallucinations.
                            </p>
                            <div className="flex items-center gap-2 mb-3">
                                <span className="text-lg font-bold text-white">89€</span>
                                <span className="text-xs text-gray-500">/mois</span>
                            </div>
                            <button className="w-full py-2 btn-gradient text-xs font-bold transition-colors">
                                Ajouter l'abonnement
                            </button>
                        </div>
                    )}

                    {!showCiterneUpsell && !showSubscriptionUpsell && (
                        <div className="p-5 rounded-2xl border border-white/[0.06] bg-white/[0.04] text-center">
                            <div className="w-12 h-12 bg-purple-400/10 rounded-full flex items-center justify-center text-purple-300 mx-auto mb-3">
                                <Check size={24} />
                            </div>
                            <p className="text-sm text-gray-300 font-medium">Vous avez choisi la meilleure offre pour vos besoins !</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
  };

  const renderPaymentResult = () => {
    if (!selectedPack) return null;
    
    // Status: ERROR
    if (paymentStatus === 'error') {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
                <div className="w-24 h-24 bg-red-500/20 rounded-full flex items-center justify-center mb-8 border border-red-500/50 shadow-[0_0_40px_rgba(239,68,68,0.3)]">
                    <XCircle size={48} className="text-red-500" />
                </div>
                
                <h2 className="text-4xl font-bold text-white mb-2">Paiement <span className="gradient-text">Refusé</span></h2>
                <p className="text-gray-500 text-center mb-10 text-lg">
                    La transaction n'a pas pu aboutir. Veuillez vérifier vos informations bancaires ou essayer une autre méthode de paiement.
                </p>

                <div className="flex gap-4 w-full">
                    <button
                        onClick={() => { setViewMode('list'); }}
                        className="flex-1 py-3.5 rounded-full font-bold border border-white/[0.08] bg-white/[0.04] text-white hover:bg-white/[0.08] transition-colors flex items-center justify-center gap-2"
                    >
                        <ArrowLeft size={18} /> Annuler
                    </button>
                    <button
                        onClick={() => { setViewMode('checkout'); }}
                        className="flex-1 py-3.5 btn-gradient font-bold transition-all flex items-center justify-center gap-2"
                    >
                        <RefreshCcw size={18} /> Réessayer
                    </button>
                </div>
            </div>
        );
    }

    // Status: SUCCESS
    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;

    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
            <div className="w-24 h-24 bg-purple-400/20 rounded-full flex items-center justify-center mb-8 border border-purple-400/50 shadow-[0_0_40px_rgba(168,85,247,0.3)]">
                <CheckCircle2 size={48} className="text-purple-400" />
            </div>
            
            <h2 className="text-4xl font-sans font-bold text-white mb-2">Paiement Accepté !</h2>
            <p className="text-gray-500 text-center mb-10 text-lg">
                Merci pour votre commande. Vos crédits <strong>{selectedPack.amount} GTO Gas</strong> ont été ajoutés à votre compte.
            </p>

            <div className="w-full bg-[#0f1115] border border-white/[0.08] rounded-2xl p-8 mb-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 px-3 py-1 bg-white/[0.08] rounded-bl-lg text-xs text-gray-500 font-mono">
                    {invoiceId}
                </div>
                
                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                    <FileText size={20} className="text-purple-400" /> Récapitulatif de commande
                </h3>

                <div className="space-y-4 text-sm">
                    <div className="flex justify-between items-center text-gray-300">
                        <span>Produit</span>
                        <span className="font-medium text-white">{selectedPack.name}</span>
                    </div>
                    <div className="flex justify-between items-center text-gray-300">
                        <span>Quantité</span>
                        <span className="font-medium text-white">1</span>
                    </div>
                    <div className="flex justify-between items-center text-gray-300 border-b border-white/[0.08] pb-4">
                        <span>Date</span>
                        <span className="font-medium text-white">{new Date().toLocaleDateString()}</span>
                    </div>
                    <div className="flex justify-between items-center pt-2">
                        <span className="font-bold text-white text-lg">Total Payé</span>
                        <span className="font-bold text-xl text-purple-400">{totalTTC.toFixed(2)} €</span>
                    </div>
                </div>
            </div>

            {/* Buttons Navigation Succès */}
            <div className="flex flex-col md:flex-row gap-4 w-full">
                <button 
                    onClick={() => { onNavigate ? onNavigate('projects') : onBack(); }}
                    className="flex-1 py-3.5 rounded-2xl font-bold bg-white/[0.08] text-white hover:bg-white/20 transition-colors flex items-center justify-center gap-2"
                >
                    <Wrench size={18} /> Continuer l'analyse
                </button>
                <button 
                    onClick={() => { onNavigate ? onNavigate('plan') : console.log("Navigation vers plan non disponible"); }}
                    className="flex-1 py-3.5 rounded-2xl font-bold bg-primary hover:bg-purple-600 text-white transition-all shadow-lg shadow-primary/20 flex items-center justify-center gap-2"
                >
                    <CreditCard size={18} /> Voir Plan & Facturation
                </button>
            </div>
            
            <button 
                onClick={generateInvoicePDF}
                className="mt-6 text-sm text-gray-500 hover:text-white flex items-center gap-2 transition-colors"
            >
                <Download size={14} /> Télécharger la facture PDF
            </button>
        </div>
    );
  };

  return (
    <div className="animate-in fade-in duration-500">
        {viewMode === 'list' && renderList()}
        {viewMode === 'checkout' && renderCheckout()}
        {viewMode === 'result' && renderPaymentResult()}
    </div>
  );
};

export default Recharge;"}

{"content":"import React from 'react';
import { PenTool, FileText, Code, FileCode, Search, Sparkles, AlertTriangle, Feather, Shield, Bot, BookOpen, Layers, ClipboardList, Target, MessageCircle, Trophy, Radar, Code2, CheckCircle, Loader2 } from 'lucide-react';
import { useTranslation } from '../i18n';
import { AnalysisResult, MegaGenerationStatus } from '../types';
import PageHeader from '../components/layout/PageHeader';

interface GenerativeToolsProps {
  onNavigate: (view: any) => void;
  history?: AnalysisResult[];
  megaStatus?: MegaGenerationStatus;
}

// IDs of tools that are pre-generable via mega-generation
const PRE_GENERABLE_TOOLS: Record<string, string> = {
  'robots-txt': 'robotsTxt',
  'schema-org': 'schemaOrg',
  'llms-txt': 'llmsTxt',
  'answer-first-audit': 'answerFirstAudit',
  'eeat-builder': 'eeatAudit',
};
// Note: llmJson is also pre-generated but shown via the llms-txt tool page

interface ToolCardProps {
  icon: React.ElementType;
  label: string;
  desc: string;
  color: string;
  bg: string;
  onClick: () => void;
  badge?: 'generating' | 'ready' | null;
}

const ToolCard: React.FC<ToolCardProps> = ({ icon: Icon, label, desc, color, bg, onClick, badge }) => (
  <button
    onClick={onClick}
    className="rounded-xl border border-white/[0.06] bg-slate-800/30 p-6 flex flex-col items-center justify-center gap-4 hover:bg-slate-800/60 transition-all duration-300 hover:-translate-y-1 group h-full relative"
  >
    {badge === 'generating' && (
      <span className="absolute top-3 right-3 flex items-center gap-1.5 bg-violet-500/15 text-violet-400 text-[10px] font-bold px-2.5 py-1 rounded-full border border-violet-500/20 animate-pulse">
        <Loader2 size={10} className="animate-spin" /> Génération...
      </span>
    )}
    {badge === 'ready' && (
      <span className="absolute top-3 right-3 flex items-center gap-1.5 bg-emerald-500/15 text-emerald-400 text-[10px] font-bold px-2.5 py-1 rounded-full border border-emerald-500/20">
        <CheckCircle size={10} /> Prêt
      </span>
    )}
    <div className={`relative p-5 rounded-2xl ${bg} group-hover:scale-110 transition-all duration-300`}>
      <Icon size={48} className={`${color} group-hover:drop-shadow-[0_0_8px_rgba(168,85,247,0.4)] transition-all duration-300`} />
      <div className="absolute inset-0 rounded-2xl bg-purple-500/0 group-hover:bg-purple-500/5 transition-all duration-300" />
    </div>
    <div className="text-center space-y-2">
      <span className="block text-xl font-bold text-gray-200 group-hover:text-white transition-colors duration-200">{label}</span>
      <span className="block text-sm text-gray-500 group-hover:text-gray-400 transition-colors duration-200">{desc}</span>
    </div>
  </button>
);

const GenerativeTools: React.FC<GenerativeToolsProps> = ({ onNavigate, history, megaStatus }) => {
  const { t } = useTranslation();

  // Determine badge state for a given tool
  const getBadge = (toolId: string): 'generating' | 'ready' | null => {
    const cacheKey = PRE_GENERABLE_TOOLS[toolId];
    if (!cacheKey) return null; // Not a pre-generable tool

    if (megaStatus === 'generating') return 'generating';

    if (megaStatus === 'completed' && history && history.length > 0) {
      const preGen = history[0]?.preGenerated;
      if (preGen?.status === 'completed' && (preGen as any)?.[cacheKey]) {
        return 'ready';
      }
    }

    return null;
  };

  const tools = [
    { id: 'smc-studio', label: t.generativeTools.smcStudio, icon: PenTool, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.smcStudioDesc },
    { id: 'content-writer', label: t.generativeTools.contentWriter, icon: Feather, color: 'text-violet-400', bg: 'bg-violet-500/10', desc: t.generativeTools.contentWriterDesc },
    { id: 'reputation', label: t.generativeTools.reputation, icon: Shield, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.reputationDesc },
    { id: 'source-of-truth', label: t.generativeTools.sourceOfTruth, icon: FileText, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.sourceOfTruthDesc },
    { id: 'schema-org', label: t.generativeTools.schemaOrg, icon: Code, color: 'text-blue-400', bg: 'bg-blue-500/10', desc: t.generativeTools.schemaOrgDesc },
    { id: 'robots-txt', label: t.generativeTools.robotsTxt, icon: FileCode, color: 'text-purple-300', bg: 'bg-purple-500/10', desc: t.generativeTools.robotsTxtDesc },
    { id: 'bot-tracking', label: t.generativeTools.botTracking || 'Suivi Bots IA', icon: Bot, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: t.generativeTools.botTrackingDesc || 'Activation & suivi des crawlers' },
    { id: 'blog-optimizer', label: t.generativeTools.blogOptimizer || 'Blog Optimiser', icon: BookOpen, color: 'text-pink-400', bg: 'bg-pink-500/10', desc: t.generativeTools.blogOptimizerDesc || 'Architecture & rédaction blog AEO' },
    { id: 'ai-response-layer', label: 'AI Response Layer', icon: Layers, color: 'text-emerald-400', bg: 'bg-emerald-500/10', desc: 'Hub, Query Pages, Catalogue & Sitemap IA' },
    { id: 'llms-txt', label: 'Générateur llms.txt', icon: ClipboardList, color: 'text-amber-400', bg: 'bg-amber-500/10', desc: 'Fichier llms.txt pour guider les IA sur votre marque' },
    { id: 'answer-first-audit', label: 'Audit Answer-First', icon: Target, color: 'text-rose-400', bg: 'bg-rose-500/10', desc: 'Score de citabilité IA sur 6 critères AEO' },
    { id: 'ai-citation-simulator', label: 'Simulateur Citation IA', icon: MessageCircle, color: 'text-sky-400', bg: 'bg-sky-500/10', desc: 'Simulez les réponses ChatGPT, Claude, Perplexity, Gemini & AI Overviews' },
    { id: 'eeat-builder', label: 'E-E-A-T Builder', icon: Trophy, color: 'text-yellow-400', bg: 'bg-yellow-500/10', desc: 'Bios auteur, About Page, Trust Signals & Audit E-E-A-T' },
    { id: 'ai-monitoring', label: 'Monitoring IA', icon: Radar, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: 'Tracker vos citations sur ChatGPT, Claude, Perplexity, Gemini & AI Overviews' },
    { id: 'api-developer', label: 'API Developer Hub', icon: Code2, color: 'text-indigo-400', bg: 'bg-indigo-500/10', desc: 'Documentation, clés API, webhooks & SDK' },
  ];

  return (
    <div className="animate-in fade-in duration-500">
      <PageHeader
        title={t.generativeTools.title}
        subtitle="Suite complete d'outils IA pour optimiser votre visibilite"
        badge={
          <span className="bg-purple-500/15 text-purple-400 text-[10px] font-semibold px-2.5 py-1 rounded-full border border-purple-500/20 flex items-center gap-1">
            <Sparkles size={10} /> {t.generativeTools.suitePro}
          </span>
        }
      />

      {/* Grid des Outils */}
      <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
        {tools.map((tool) => (
            <ToolCard
                key={tool.id}
                icon={tool.icon}
                label={tool.label}
                desc={tool.desc}
                color={tool.color}
                bg={tool.bg}
                onClick={() => onNavigate(tool.id)}
                badge={getBadge(tool.id)}
            />
        ))}
      </div>

      {/* Section Explicative */}
      <div className="ninja-card p-8">
        <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-purple-500/10 rounded-full">
                <AlertTriangle size={20} className="text-yellow-400" />
            </div>
            <h3 className="text-xl font-bold text-white">{t.generativeTools.whyUse}</h3>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.structuredContent}</h4>
                <p className="text-sm text-gray-500 leading-relaxed">
                    {t.generativeTools.structuredContentDesc}
                </p>
            </div>
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.technicalData}</h4>
                <p className="text-sm text-gray-500 leading-relaxed">
                    {t.generativeTools.technicalDataDesc}
                </p>
            </div>
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.sourceAuthority}</h4>
                <p className="text-sm text-gray-500 leading-relaxed">
                    {t.generativeTools.sourceAuthorityDesc}
                </p>
            </div>
        </div>
      </div>

      </div>
    </div>
  );
};

export default GenerativeTools;
"}

{"content":"import React, { useState } from 'react';
import { User, SMCContent } from '../types';
import { smcService } from '../services/smc';
import { ArrowLeft, FileText, HelpCircle, PenTool, Sparkles, Copy, Download, Check, Loader2, Layout, MessageSquare, BookOpen, Library, Clock, AlignLeft, Link as LinkIcon, Bot, Archive, ChevronRight, Award, Globe, ArrowRight, Eye } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  library: SMCContent[];
  onAddToLibrary: (item: SMCContent) => void;
  onNavigateToPublisher?: (data: { topic: string, url: string, brief: string }) => void;
  onNavigateToDirectory?: () => void;
}

type ToolType = 'home' | 'fiche' | 'faq' | 'article';
type Tab = 'studio' | 'library';

const SMCStudio: React.FC<Props> = ({ onBack, user, onDeductCredits, library, onAddToLibrary, onNavigateToPublisher, onNavigateToDirectory }) => {
  const [activeTab, setActiveTab] = useState<Tab>('studio');
  const [currentTool, setCurrentTool] = useState<ToolType>('home');
  const [result, setResult] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  // --- States pour l'outil Article (Flux Blog Optimizer) ---
  const [articleStep, setArticleStep] = useState<'brief' | 'writing' | 'done'>('brief');
  const [briefContent, setBriefContent] = useState('');
  
  // Form States
  const [ficheData, setFicheData] = useState({ name: '', features: '' });
  const [faqData, setFaqData] = useState({ topic: '', context: '' });
  const [articleData, setArticleData] = useState({ title: '', url: '', tone: 'Professionnel' }); // URL & Tone used for Brief gen

  const COSTS = {
    fiche: 1,
    faq: 1,
    brief: 1, // Brief d'article
    article: 3 // Rédaction complète
  };

  const handleCopy = (content: string) => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleNavigateToPublisherAction = () => {
    if (onNavigateToPublisher) {
        onNavigateToPublisher({
            topic: articleData.title,
            url: articleData.url,
            brief: briefContent // Le PublisherRequest se base sur le brief
        });
    }
  };

  const handleRestoreFromLibrary = (item: SMCContent) => {
    // 1. Déterminer l'outil
    let tool: ToolType = 'home';
    if (item.type === 'fiche') tool = 'fiche';
    else if (item.type === 'faq') tool = 'faq';
    else if (item.type === 'article' || item.type === 'brief') tool = 'article';

    setCurrentTool(tool);

    // 2. Restaurer le contenu et l'état
    if (item.type === 'article') {
        setResult(item.content);
        setArticleStep('done');
        // Tentative de récupération du titre depuis "Article: Titre - Date"
        const titleClean = item.title.split(' - ')[0].replace('Article: ', '').trim();
        setArticleData(prev => ({ ...prev, title: titleClean }));
        // Si possible, on pourrait essayer de retrouver le brief parent via meta, mais ici on affiche juste le résultat
    } else if (item.type === 'brief') {
        setBriefContent(item.content);
        setArticleStep('writing');
        const titleClean = item.title.split(' - ')[0].replace('Brief: ', '').trim();
        setArticleData(prev => ({ ...prev, title: titleClean }));
    } else {
        setResult(item.content);
        // Restauration contextuelle basique pour les formulaires
        if (item.type === 'fiche') {
             const nameClean = item.title.split(' - ')[0].replace('Fiche: ', '').trim();
             setFicheData(prev => ({ ...prev, name: nameClean }));
        }
        if (item.type === 'faq') {
             const topicClean = item.title.split(' - ')[0].replace('FAQ: ', '').trim();
             setFaqData(prev => ({ ...prev, topic: topicClean }));
        }
    }

    // 3. Basculer vers l'onglet Studio
    setActiveTab('studio');
  };

  // Generic generator for simple tools (Fiche, FAQ)
  const runSimpleGeneration = async (type: 'fiche' | 'faq', cost: number, generator: () => Promise<string>, titlePrefix: string) => {
    if (onDeductCredits(cost)) {
      setIsGenerating(true);
      setResult('');
      try {
        const content = await generator();
        setResult(content);
        
        // Save to Library
        const newItem: SMCContent = {
            id: `smc_${Date.now()}`,
            type,
            title: `${titlePrefix} - ${new Date().toLocaleTimeString()}`,
            content,
            timestamp: new Date().toISOString()
        };
        onAddToLibrary(newItem);

      } catch (e) {
        console.error(e);
        alert("Une erreur est survenue.");
      } finally {
        setIsGenerating(false);
      }
    }
  };

  // --- Article Generation Logic (2 Steps) ---

  const handleGenerateBrief = async () => {
    if (!articleData.title && !articleData.url) {
        alert("Sujet ou URL requis.");
        return;
    }

    if (onDeductCredits(COSTS.brief)) {
        setIsGenerating(true);
        try {
            const brief = await smcService.generateBrief(articleData.title, articleData.url);
            setBriefContent(brief);
            setArticleStep('writing'); // Move to step 2
            
            // Save Brief to Library
            onAddToLibrary({
                id: `brief_${Date.now()}`,
                type: 'brief',
                title: `Brief: ${articleData.title || 'Architecture Article'}`,
                content: brief,
                timestamp: new Date().toISOString()
            });

        } catch (e) {
            console.error(e);
            alert("Erreur lors du brief.");
        } finally {
            setIsGenerating(false);
        }
    }
  };

  const handleWriteFullArticle = async () => {
    if (onDeductCredits(COSTS.article)) {
        setIsGenerating(true);
        try {
            const article = await smcService.generateFullArticle(briefContent, articleData.title);
            setResult(article);
            setArticleStep('done'); // Move to step 3

            // Save Article to Library
            onAddToLibrary({
                id: `art_${Date.now()}`,
                type: 'article',
                title: `Article: ${articleData.title || 'Rédaction Complète'}`,
                content: article,
                timestamp: new Date().toISOString(),
                meta: { briefId: `brief_${Date.now()}` } // Link to brief loosely
            });

        } catch (e) {
            console.error(e);
            alert("Erreur lors de la rédaction.");
        } finally {
            setIsGenerating(false);
        }
    }
  };

  const renderHome = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="text-center space-y-4">
        <h1 className="text-4xl font-bold text-white">SMC <span className="gradient-text">Studio</span></h1>
        <p className="text-gray-400 max-w-xl mx-auto">
          Smart Marketing Content : Votre usine de production de contenu optimisé pour les Answer Engines.
        </p>
      </div>

      <div className="grid md:grid-cols-3 gap-6 w-full">
        {/* Card Fiche */}
        <button
          onClick={() => setCurrentTool('fiche')}
          className="ninja-card p-8 hover:border-blue-500/50 hover:bg-white/[0.04] transition-all group text-left relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <Layout size={80} />
          </div>
          <div className="w-12 h-12 rounded-xl bg-blue-500/20 flex items-center justify-center text-blue-400 mb-6 group-hover:scale-110 transition-transform">
            <FileText size={24} />
          </div>
          <h3 className="text-xl font-bold text-white mb-2">Fiche Produit</h3>
          <p className="text-sm text-gray-400 mb-6">Générez des fiches techniques structurées et vendeuses.</p>
          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-blue-500/10 text-blue-400 text-xs font-bold border border-blue-500/20">
            <Sparkles size={10} /> 1 Crédit
          </div>
        </button>

        {/* Card FAQ */}
        <button
          onClick={() => setCurrentTool('faq')}
          className="ninja-card p-8 hover:border-purple-500/50 hover:bg-white/[0.04] transition-all group text-left relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <MessageSquare size={80} />
          </div>
          <div className="w-12 h-12 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400 mb-6 group-hover:scale-110 transition-transform">
            <HelpCircle size={24} />
          </div>
          <h3 className="text-xl font-bold text-white mb-2">Générateur FAQ</h3>
          <p className="text-sm text-gray-400 mb-6">Créez des questions/réponses pertinentes pour rassurer vos clients.</p>
          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple-500/10 text-purple-400 text-xs font-bold border border-purple-500/20">
            <Sparkles size={10} /> 1 Crédit
          </div>
        </button>

        {/* Card Article */}
        <button
          onClick={() => setCurrentTool('article')}
          className="ninja-card p-8 hover:border-purple-500/50 hover:bg-white/[0.04] transition-all group text-left relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <BookOpen size={80} />
          </div>
          <div className="w-12 h-12 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400 mb-6 group-hover:scale-110 transition-transform">
            <PenTool size={24} />
          </div>
          <h3 className="text-xl font-bold text-white mb-2">Rédaction Article</h3>
          <p className="text-sm text-gray-400 mb-6">Workflow complet : Architecture (Brief) puis Rédaction AEO.</p>
          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple-500/10 text-purple-400 text-xs font-bold border border-purple-500/20">
            <Sparkles size={10} /> 1 + 3 Crédits
          </div>
        </button>
      </div>
    </div>
  );

  const renderToolArchives = (tool: ToolType) => {
    const archives = library.filter(item => {
        if (tool === 'article') return item.type === 'article' || item.type === 'brief';
        return item.type === tool;
    });

    if (archives.length === 0) return null;

    return (
        <div className="border-t border-white/10 pt-10 animate-in fade-in slide-in-from-bottom-8">
            <div className="flex items-center justify-between mb-6">
                <h3 className="text-xl font-serif font-bold text-white flex items-center gap-2">
                    <Archive size={20} className="text-gray-400" /> 
                    Archives {tool === 'fiche' ? 'Fiches Produits' : tool === 'faq' ? 'FAQs' : 'Articles & Briefs'}
                </h3>
                <span className="text-xs text-gray-500 bg-purple-500/5 px-2 py-1 rounded-full">{archives.length} fichiers</span>
            </div>

            <div className="grid md:grid-cols-3 gap-6">
                {archives.map((item) => (
                    <div key={item.id} className="glass-panel p-5 rounded-xl border border-white/10 hover:border-primary/30 transition-all group flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <span className={`text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider 
                                ${item.type === 'article' ? 'bg-purple-400/10 text-purple-300 border border-purple-400/20' : 
                                  item.type === 'brief' ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 
                                  'bg-blue-500/10 text-blue-400 border border-blue-500/20'}`}>
                                {item.type.toUpperCase()}
                            </span>
                            <span className="text-xs text-gray-500 flex items-center gap-1">
                                <Clock size={10} /> {new Date(item.timestamp).toLocaleDateString()}
                            </span>
                        </div>
                        
                        <h4 className="font-bold text-white mb-2 line-clamp-2 min-h-[3rem] text-sm">{item.title}</h4>
                        
                        <div className="bg-[#050208] p-3 rounded border border-white/5 mb-4 flex-1 overflow-hidden relative h-24">
                            <p className="text-[10px] text-gray-500 font-mono line-clamp-4 leading-relaxed">{item.content}</p>
                            <div className="absolute bottom-0 left-0 w-full h-8 bg-gradient-to-t from-[#050208] to-transparent"></div>
                        </div>

                        <div className="flex gap-2 pt-2 border-t border-white/5">
                            <button 
                                onClick={() => handleRestoreFromLibrary(item)}
                                className="flex-1 py-1.5 bg-primary/10 hover:bg-primary/20 rounded text-[10px] font-bold text-primary transition-colors flex items-center justify-center gap-1"
                            >
                                <Eye size={10} /> Ouvrir
                            </button>
                            <button 
                                onClick={() => handleCopy(item.content)}
                                className="flex-1 py-1.5 bg-purple-500/5 hover:bg-white/10 rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
                            >
                                <Copy size={10} /> Copier
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
  };

  const renderTool = () => {
    let title = '', color = '', icon = null;
    
    switch(currentTool) {
      case 'fiche': title = 'Fiche Produit'; color = 'text-blue-400'; icon = <FileText />; break;
      case 'faq': title = 'Générateur FAQ'; color = 'text-purple-400'; icon = <HelpCircle />; break;
      case 'article': title = 'Rédaction Article'; color = 'text-purple-400'; icon = <PenTool />; break;
    }

    // Contenu à afficher dans la fenêtre de droite
    const displayContent = currentTool === 'article' 
        ? (articleStep === 'done' ? result : briefContent) 
        : result;

    return (
      <div className="flex flex-col gap-12 animate-in slide-in-from-right duration-300">
        <div className="grid lg:grid-cols-12 gap-8 h-full min-h-[600px]">
          
          {/* Left: Input Form */}
          <div className="lg:col-span-4 space-y-6">
            <div className="ninja-card p-6">
              <div className="flex items-center gap-3 mb-6">
                <div className={`p-2 rounded-lg bg-purple-500/10 ${color}`}>{icon}</div>
                <h2 className="text-xl font-bold text-white">{title}</h2>
              </div>

              {currentTool === 'fiche' && (
                <div className="space-y-4">
                  <div>
                    <label className="text-sm text-gray-400 block mb-2">Nom du produit / service</label>
                    <input
                      type="text"
                      className="w-full bg-[#111111] border border-white/[0.08] rounded-xl p-3 text-white focus:border-blue-500/50 outline-none"
                      placeholder="Ex: SuperVacuum 3000"
                      value={ficheData.name}
                      onChange={(e) => setFicheData({...ficheData, name: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="text-sm text-gray-400 block mb-2">Caractéristiques / Notes en vrac</label>
                    <textarea
                      className="w-full bg-[#111111] border border-white/[0.08] rounded-xl p-3 text-white focus:border-blue-500/50 outline-none h-40 resize-none"
                      placeholder="- Aspiration 200W&#10;- Silencieux&#10;- Batterie 1h"
                      value={ficheData.features}
                      onChange={(e) => setFicheData({...ficheData, features: e.target.value})}
                    />
                  </div>
                  <button
                    onClick={() => runSimpleGeneration('fiche', COSTS.fiche, () => smcService.generateFiche(ficheData.name, ficheData.features), `Fiche: ${ficheData.name}`)}
                    disabled={isGenerating || !ficheData.name}
                    className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {isGenerating ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />}
                    Générer ({COSTS.fiche} Crédit)
                  </button>
                </div>
              )}

              {currentTool === 'faq' && (
                <div className="space-y-4">
                  <div>
                    <label className="text-sm text-gray-400 block mb-2">Sujet Principal</label>
                    <input
                      type="text"
                      className="w-full bg-[#111111] border border-white/[0.08] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none"
                      placeholder="Ex: Politique de retour"
                      value={faqData.topic}
                      onChange={(e) => setFaqData({...faqData, topic: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="text-sm text-gray-400 block mb-2">Contexte / Éléments à inclure</label>
                    <textarea
                      className="w-full bg-[#111111] border border-white/[0.08] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none h-40 resize-none"
                      placeholder="30 jours pour changer d'avis. Frais de retour gratuits si défectueux."
                      value={faqData.context}
                      onChange={(e) => setFaqData({...faqData, context: e.target.value})}
                    />
                  </div>
                  <button 
                    onClick={() => runSimpleGeneration('faq', COSTS.faq, () => smcService.generateFAQ(faqData.topic, faqData.context), `FAQ: ${faqData.topic}`)}
                    disabled={isGenerating || !faqData.topic}
                    className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {isGenerating ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />}
                    Générer ({COSTS.faq} Crédit)
                  </button>
                </div>
              )}

              {/* INTEGRATED BLOG OPTIMIZER FLOW */}
              {currentTool === 'article' && (
                <div className="space-y-6">
                  {/* Steps Indicator */}
                  <div className="flex items-center gap-2 text-xs mb-4">
                      <span className={`px-2 py-1 rounded ${articleStep === 'brief' ? 'bg-purple-500 text-white' : 'bg-white/10 text-gray-500'}`}>1. Brief</span>
                      <ChevronRight size={12} className="text-gray-600"/>
                      <span className={`px-2 py-1 rounded ${articleStep === 'writing' ? 'bg-purple-500 text-white' : 'bg-white/10 text-gray-500'}`}>2. Validation</span>
                      <ChevronRight size={12} className="text-gray-600"/>
                      <span className={`px-2 py-1 rounded ${articleStep === 'done' ? 'bg-purple-400 text-white' : 'bg-white/10 text-gray-500'}`}>3. Article</span>
                  </div>

                  <div className="space-y-4">
                      <div>
                          <label className="text-sm text-gray-400 block mb-2 flex items-center gap-2">
                              <AlignLeft size={16} /> Sujet / Mot-clé
                          </label>
                          <input
                              type="text"
                              className="w-full bg-[#111111] border border-white/[0.08] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none"
                              placeholder="Ex: Avantages AEO"
                              value={articleData.title}
                              onChange={(e) => setArticleData({...articleData, title: e.target.value})}
                              disabled={articleStep !== 'brief'}
                          />
                      </div>
                      <div>
                          <label className="text-sm text-gray-400 block mb-2 flex items-center gap-2">
                              <LinkIcon size={16} /> URL Source (Optionnel)
                          </label>
                          <input
                              type="url"
                              className="w-full bg-[#111111] border border-white/[0.08] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none"
                              placeholder="https://..."
                              value={articleData.url}
                              onChange={(e) => setArticleData({...articleData, url: e.target.value})}
                              disabled={articleStep !== 'brief'}
                          />
                      </div>

                      {articleStep === 'brief' && (
                          <button 
                              onClick={handleGenerateBrief}
                              disabled={isGenerating || (!articleData.title && !articleData.url)}
                              className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                          >
                              {isGenerating ? <Loader2 className="animate-spin" /> : <FileText size={18} />}
                              Générer le Brief ({COSTS.brief} Crédit)
                          </button>
                      )}

                      {articleStep === 'writing' && (
                          <div className="space-y-4 pt-2 border-t border-white/5 animate-in fade-in">
                              <p className="text-xs text-gray-400">Le brief est prêt. Vous pouvez maintenant lancer la rédaction complète.</p>
                              <button 
                                  onClick={handleWriteFullArticle}
                                  disabled={isGenerating}
                                  className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 shadow-lg shadow-purple-500/20"
                              >
                                  {isGenerating ? <Loader2 className="animate-spin" /> : <PenTool size={18} />}
                                  Rédiger l'Article ({COSTS.article} Crédits)
                              </button>
                              <button 
                                  onClick={() => setArticleStep('brief')}
                                  className="w-full py-2 text-gray-400 hover:text-white text-xs underline"
                              >
                                  Modifier les paramètres
                              </button>
                          </div>
                      )}

                      {articleStep === 'done' && (
                          <div className="space-y-6 animate-in slide-in-from-bottom-2 duration-500">
                              {/* Success Message */}
                              <div className="text-center py-4 bg-purple-400/10 rounded-xl border border-purple-400/20">
                                  <Check size={32} className="text-purple-400 mx-auto mb-2" />
                                  <p className="text-purple-300 font-bold">Article Généré !</p>
                                  <p className="text-xs text-purple-300/70 mt-1">Sauvegardé dans la bibliothèque</p>
                                  <div className="flex justify-center gap-4 mt-2">
                                      <button 
                                          onClick={() => setActiveTab('library')}
                                          className="text-xs text-purple-300/70 hover:text-purple-200 underline flex items-center gap-1"
                                      >
                                          <Library size={12} /> Accès rapide Bibliothèque
                                      </button>
                                  </div>
                              </div>

                              <div className="pt-4 border-t border-white/5">
                                  <h4 className="text-xs font-bold text-gray-400 uppercase mb-3 flex items-center gap-2">
                                      <Sparkles size={12} /> Aller plus loin
                                  </h4>
                                  
                                  <div className="space-y-3">
                                      {/* Publisher Option */}
                                      <button
                                          onClick={handleNavigateToPublisherAction}
                                          className="w-full bg-gradient-to-r from-purple-500/10 to-purple-700/10 border border-purple-500/30 p-3 rounded-xl flex items-center justify-between group hover:border-purple-500/50 transition-all text-left"
                                      >
                                          <div className="flex items-center gap-3">
                                              <div className="p-2 bg-purple-500/20 rounded-lg text-purple-400 group-hover:text-purple-300">
                                                  <Award size={18} />
                                              </div>
                                              <div>
                                                  <span className="block text-sm font-bold text-white group-hover:text-purple-100">Publisher Expert</span>
                                                  <span className="block text-[10px] text-gray-400">Relecture humaine & publication</span>
                                              </div>
                                          </div>
                                          <ChevronRight size={16} className="text-purple-500/50 group-hover:text-purple-400" />
                                      </button>

                                      {/* Directory Option */}
                                      <button
                                          onClick={onNavigateToDirectory}
                                          className="w-full bg-gradient-to-r from-purple-500/10 to-purple-700/10 border border-purple-500/30 p-3 rounded-xl flex items-center justify-between group hover:border-purple-500/50 transition-all text-left"
                                      >
                                          <div className="flex items-center gap-3">
                                              <div className="p-2 bg-purple-500/20 rounded-lg text-purple-400 group-hover:text-purple-300">
                                                  <Globe size={18} />
                                              </div>
                                              <div>
                                                  <span className="block text-sm font-bold text-white group-hover:text-purple-100">La Source</span>
                                                  <span className="block text-[10px] text-gray-400">Indexation Annuaire IA</span>
                                              </div>
                                          </div>
                                          <ChevronRight size={16} className="text-purple-500/50 group-hover:text-purple-400" />
                                      </button>
                                  </div>
                              </div>

                              <button 
                                  onClick={() => { setArticleStep('brief'); setBriefContent(''); setResult(''); setArticleData({ title: '', url: '', tone: 'Professionnel' }); }}
                                  className="w-full text-xs text-white bg-white/10 px-3 py-2 rounded-lg hover:bg-white/20 transition-colors flex items-center justify-center gap-2"
                              >
                                  <ArrowRight size={12} /> Commencer un nouvel article
                              </button>
                          </div>
                      )}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Right: Output */}
          <div className="lg:col-span-8 flex flex-col h-full">
            <div className="flex-1 ninja-card overflow-hidden flex flex-col shadow-2xl">
              <div className="p-4 border-b border-white/[0.08] bg-white/[0.02] flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <span className="text-sm font-medium text-gray-300">
                      {currentTool === 'article' 
                          ? (articleStep === 'brief' ? 'En attente...' : articleStep === 'writing' ? 'Brief Généré' : 'Article Complet') 
                          : 'Résultat généré'}
                    </span>
                    {currentTool === 'article' && articleStep === 'writing' && <span className="text-xs bg-purple-500/20 text-purple-400 px-2 py-0.5 rounded">Étape 1/2 validée</span>}
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleCopy(displayContent)} 
                    disabled={!displayContent}
                    className="p-2 hover:bg-white/10 rounded-lg text-gray-400 hover:text-white transition-colors disabled:opacity-50"
                    title="Copier"
                  >
                    {copied ? <Check size={18} className="text-purple-300" /> : <Copy size={18} />}
                  </button>
                  <button 
                    onClick={() => handleDownload(`${currentTool}_export.md`, displayContent)} 
                    disabled={!displayContent}
                    className="p-2 hover:bg-white/10 rounded-lg text-gray-400 hover:text-white transition-colors disabled:opacity-50"
                    title="Télécharger"
                  >
                    <Download size={18} />
                  </button>
                </div>
              </div>
              <div className="flex-1 p-8 overflow-y-auto bg-[#0a0a0a] custom-scrollbar">
                {isGenerating ? (
                  <div className="h-full flex flex-col items-center justify-center text-gray-500 space-y-4">
                    <Loader2 size={48} className={`animate-spin ${color}`} />
                    <p className="animate-pulse">
                      {currentTool === 'article' && articleStep === 'writing' ? "Rédaction de l'article expert..." : "L'IA génère votre contenu..."}
                    </p>
                  </div>
                ) : displayContent ? (
                  <pre className="whitespace-pre-wrap font-mono text-sm text-gray-300 leading-relaxed selection:bg-white/10">
                    {displayContent}
                  </pre>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-gray-600 border-2 border-dashed border-white/5 rounded-lg m-4">
                    <Sparkles size={48} className="opacity-20 mb-4" />
                    <p>Le contenu généré apparaîtra ici.</p>
                  </div>
                )}
              </div>
            </div>
          </div>

        </div>

        {/* Section Archives Solutions (Nouveauté) */}
        {renderToolArchives(currentTool)}
      </div>
    );
  };

  const renderLibrary = () => (
    <div className="animate-in fade-in slide-in-from-right duration-300">
        <div className="mb-8">
            <h2 className="text-2xl font-bold text-white mb-2">Archives <span className="gradient-text">Solutions</span></h2>
            <p className="text-gray-400">Retrouvez tous vos contenus générés (Fiches, FAQ, Briefs, Articles).</p>
        </div>

        {library.length === 0 ? (
            <div className="text-center py-20 ninja-card border-dashed">
                <Archive size={48} className="mx-auto text-gray-600 mb-4" />
                <p className="text-gray-400">Aucun contenu dans la bibliothèque.</p>
                <button onClick={() => setActiveTab('studio')} className="mt-4 text-primary hover:underline">Créer du contenu</button>
            </div>
        ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                {library.map((item) => (
                    <div key={item.id} className="glass-panel p-5 rounded-xl border border-white/10 hover:border-primary/30 transition-all group flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <span className={`text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider 
                                ${item.type === 'article' ? 'bg-purple-400/10 text-purple-300 border border-purple-400/20' : 
                                  item.type === 'brief' ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 
                                  'bg-blue-500/10 text-blue-400 border border-blue-500/20'}`}>
                                {item.type.toUpperCase()}
                            </span>
                            <span className="text-xs text-gray-500 flex items-center gap-1">
                                <Clock size={10} /> {new Date(item.timestamp).toLocaleDateString()}
                            </span>
                        </div>
                        
                        <h4 className="font-bold text-white mb-2 line-clamp-2 min-h-[3rem]">{item.title}</h4>
                        
                        <div className="bg-[#050208] p-3 rounded border border-white/5 mb-4 flex-1 overflow-hidden relative">
                            <p className="text-xs text-gray-500 font-mono line-clamp-4">{item.content}</p>
                            <div className="absolute bottom-0 left-0 w-full h-8 bg-gradient-to-t from-[#050208] to-transparent"></div>
                        </div>

                        <div className="flex gap-2 pt-2 border-t border-white/5">
                            <button 
                                onClick={() => handleRestoreFromLibrary(item)}
                                className="flex-1 py-2 bg-primary/10 hover:bg-primary/20 rounded text-xs font-medium text-primary transition-colors flex items-center justify-center gap-2"
                            >
                                <Eye size={12} /> Ouvrir
                            </button>
                            <button 
                                onClick={() => handleCopy(item.content)}
                                className="flex-1 py-2 bg-purple-500/5 hover:bg-white/10 rounded text-xs font-medium text-gray-300 transition-colors flex items-center justify-center gap-2"
                            >
                                <Copy size={12} /> Copier
                            </button>
                            <button 
                                onClick={() => handleDownload(`${item.type}_${item.id}.md`, item.content)}
                                className="flex-1 py-2 bg-purple-500/5 hover:bg-white/10 rounded text-xs font-medium text-gray-300 transition-colors flex items-center justify-center gap-2"
                            >
                                <Download size={12} /> MD
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        )}
    </div>
  );

  return (
    <div className="">
      <div className="flex justify-between items-center mb-8">
        <button 
            onClick={activeTab === 'studio' && currentTool !== 'home' ? () => setCurrentTool('home') : onBack} 
            className="flex items-center text-gray-400 hover:text-white transition-colors"
        >
            <ArrowLeft size={18} className="mr-2" /> 
            {activeTab === 'studio' && currentTool !== 'home' ? 'Retour au studio' : 'Retour'}
        </button>

        {/* Tabs Switcher */}
        <div className="flex bg-[#111111] p-1 rounded-full border border-white/[0.08]">
            <button
                onClick={() => setActiveTab('studio')}
                className={`px-6 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'studio' ? 'btn-gradient !py-2 !px-6' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <Sparkles size={16} /> Studio
            </button>
            <button
                onClick={() => setActiveTab('library')}
                className={`px-6 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'library' ? 'btn-gradient !py-2 !px-6' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <Library size={16} /> Bibliothèque <span className="bg-white/10 px-1.5 py-0.5 rounded-full text-[10px]">{library.length}</span>
            </button>
        </div>
      </div>

      {activeTab === 'studio' ? (currentTool === 'home' ? renderHome() : renderTool()) : renderLibrary()}
    </div>
  );
};

export default SMCStudio;"}

{"content":"import React, { useState, useEffect } from 'react';
import { AnalysisResult, SourceOfTruthData, User, SMCContent } from '../types';
import { LLM_TRUTH_TEMPLATES } from '../services/llm_templates';
import { ArrowLeft, FileText, Download, Copy, Sparkles, Check, Plus, Trash2, Building2, MapPin, Calendar, ChevronDown, History, RefreshCw, Save, RotateCcw, Loader2, Zap, BookOpen, FolderOpen, FileCode, ShieldCheck, Lock, Eye, Archive, Server, Globe } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  history: AnalysisResult[];
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  savedFiles: SMCContent[];
  onSaveFile: (item: SMCContent) => void;
}

const SourceOfTruth: React.FC<Props> = ({ onBack, history, user, onDeductCredits, savedFiles, onSaveFile }) => {
  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
  const [format, setFormat] = useState<'txt' | 'json'>('txt');
  const [copied, setCopied] = useState(false);
  const [selectedAnalysisIndex, setSelectedAnalysisIndex] = useState<number>(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [hasGenerated, setHasGenerated] = useState(false);

  const GENERATION_COST = 10;

  // Fonction pour simuler l'extraction de données basée sur l'URL analysée
  const extractDataFromUrl = (url: string): SourceOfTruthData => {
    try {
        const hostname = new URL(url).hostname;
        const nameParts = hostname.replace('www.', '').split('.');
        const rawName = nameParts[0];
        const formattedName = rawName.charAt(0).toUpperCase() + rawName.slice(1);
        
        return {
          description: `${formattedName} est une référence dans son secteur, offrant des solutions optimisées pour les utilisateurs modernes. Notre plateforme garantit fiabilité et performance.`,
          type: 'Entreprise de services numériques',
          founded: '2020',
          location: 'Paris, France',
          services: [
            { name: `Offre ${formattedName} Pro`, description: `Solution complète pour les professionnels utilisant ${formattedName}.`, category: 'B2B' },
            { name: 'Support Expert', description: 'Assistance technique et accompagnement stratégique.', category: 'Service Client' }
          ],
          faqs: [
            { question: `Qu'est-ce que ${formattedName} ?`, answer: `${formattedName} est une plateforme digitale innovante conçue pour simplifier vos opérations.` },
            { question: 'Comment accéder au service ?', answer: 'Le service est accessible via notre portail web sécurisé et notre API.' }
          ]
        };
    } catch (e) {
        return {
            description: '',
            type: '',
            founded: '',
            location: '',
            services: [],
            faqs: []
        };
    }
  };

  // État pour les données actuelles (modifiables)
  const [data, setData] = useState<SourceOfTruthData>(() => {
    if (history.length > 0) {
        return extractDataFromUrl(history[0].url);
    }
    return {
        description: '',
        type: 'SaaS B2B',
        founded: new Date().getFullYear().toString(),
        location: 'Paris, France',
        services: [{ name: 'Service Principal', description: 'Description du service...', category: 'Core' }],
        faqs: [{ question: 'Question fréquente ?', answer: 'Réponse factuelle...' }]
    };
  });

  // État pour conserver les données d'origine (pour le reset)
  const [originalData, setOriginalData] = useState<SourceOfTruthData | null>(null);

  useEffect(() => {
    if (history.length > 0 && history[selectedAnalysisIndex]) {
        const extracted = extractDataFromUrl(history[selectedAnalysisIndex].url);
        setData(extracted);
        setOriginalData(extracted);
        // Reset generated state when changing project context to force regeneration/validation
        setHasGenerated(false);
        setActiveTab('edit');
    }
  }, [selectedAnalysisIndex, history]);

  const currentProjectName = history.length > 0 
    ? new URL(history[selectedAnalysisIndex].url).hostname 
    : "Mon Projet";

  const currentProjectDomain = history.length > 0 
    ? new URL(history[selectedAnalysisIndex].url).origin 
    : "https://monsite.com";
  
  const currentHostname = history.length > 0 
    ? new URL(history[selectedAnalysisIndex].url).hostname
    : "monsite.com";

  const handleServiceChange = (idx: number, field: string, value: string) => {
    const newServices = [...data.services];
    (newServices[idx] as any)[field] = value;
    setData({ ...data, services: newServices });
  };

  const handleFaqChange = (idx: number, field: string, value: string) => {
    const newFaqs = [...data.faqs];
    (newFaqs[idx] as any)[field] = value;
    setData({ ...data, faqs: newFaqs });
  };

  const addService = () => setData({ ...data, services: [...data.services, { name: '', description: '', category: '' }] });
  const removeService = (idx: number) => setData({ ...data, services: data.services.filter((_, i) => i !== idx) });

  const addFaq = () => setData({ ...data, faqs: [...data.faqs, { question: '', answer: '' }] });
  const removeFaq = (idx: number) => setData({ ...data, faqs: data.faqs.filter((_, i) => i !== idx) });

  const handleReset = () => {
    if (originalData) {
        if (window.confirm("Voulez-vous vraiment restaurer les données d'origine issues de l'analyse ? Vos modifications seront perdues.")) {
            setData(originalData);
        }
    }
  };

  const handleGenerate = async () => {
    // La vérification de connexion et de solde est gérée par onDeductCredits
    if (onDeductCredits(GENERATION_COST)) {
      setIsGenerating(true);
      
      // Simulation du temps de génération/traitement des nouvelles données
      await new Promise(resolve => setTimeout(resolve, 800));
      
      const content = generateContent();
      
      // Sauvegarde dans l'historique
      onSaveFile({
        id: `truth_${Date.now()}`,
        type: 'brief', // Using brief generic type as it fits text content
        title: `Source of Truth - ${currentProjectName}`,
        content: content,
        timestamp: new Date().toISOString()
      });

      setIsGenerating(false);
      setHasGenerated(true);
      setActiveTab('preview');
      setShowSuccessMessage(true);
      setTimeout(() => setShowSuccessMessage(false), 3000);
    }
  };

  const generateContent = () => {
    const projectInfo = { name: currentProjectName, domain: currentProjectDomain };
    return format === 'json' 
      ? LLM_TRUTH_TEMPLATES.json(projectInfo, data)
      : LLM_TRUTH_TEMPLATES.txt(projectInfo, data);
  };

  const handleCopy = (txt?: string) => {
    navigator.clipboard.writeText(txt || generateContent());
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = (filename?: string, content?: string) => {
    const blob = new Blob([content || generateContent()], { type: format === 'json' ? 'application/json' : 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename || `llm.${format}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="animate-in fade-in duration-500 relative">
      
      {/* Success Message Toast */}
      {showSuccessMessage && (
        <div className="fixed top-24 right-8 z-50 bg-purple-400 text-white px-6 py-3 rounded-2xl font-bold shadow-2xl animate-in slide-in-from-right fade-in flex items-center gap-2">
            <Check size={20} />
            Fichiers mis à jour avec succès
        </div>
      )}

      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-purple-500/20 flex items-center justify-center text-purple-400 border border-purple-500/30">
              <FileText size={24} />
            </div>
            LLM Source of Truth
          </h1>
          <p className="text-gray-500">Générez et maintenez le fichier de référence (llm.txt / llm.json) pour les moteurs d'IA.</p>
        </div>

        {/* Analysis Selector & Actions */}
        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
             {history.length > 0 ? (
                 <div className="relative group">
                    <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none text-gray-500">
                        <History size={16} />
                    </div>
                    <select 
                      value={selectedAnalysisIndex}
                      onChange={(e) => setSelectedAnalysisIndex(Number(e.target.value))}
                      className="appearance-none bg-white/[0.04] border border-white/[0.08] text-white pl-10 pr-10 py-2.5 rounded-2xl focus:outline-none focus:border-purple-500/50 w-full min-w-[250px] cursor-pointer hover:bg-white/[0.08] transition-colors"
                    >
                      {history.map((analysis, idx) => (
                        <option key={idx} value={idx} className="bg-[#1a1d24]">
                            {new URL(analysis.url).hostname} - {new Date(analysis.timestamp).toLocaleDateString()}
                        </option>
                      ))}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" size={16} />
                 </div>
             ) : (
                <div className="px-4 py-2 bg-purple-500/10 border border-white/[0.1] rounded-2xl text-purple-200 text-xs flex items-center gap-2">
                    <Sparkles size={14} /> Aucune analyse disponible. <span className="underline cursor-pointer" onClick={onBack}>Lancer un audit</span> pour pré-remplir.
                </div>
             )}
             
             <div className="flex bg-white/[0.04] rounded-2xl p-1 border border-white/[0.08]">
                <button onClick={() => setActiveTab('edit')} className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${activeTab === 'edit' ? 'bg-white/[0.08] text-white shadow-sm' : 'text-gray-500 hover:text-white'}`}>Éditer</button>
                <button 
                  onClick={() => hasGenerated && setActiveTab('preview')}
                  disabled={!hasGenerated}
                  className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${
                    activeTab === 'preview' 
                      ? 'bg-purple-500/20 text-purple-300 shadow-sm' 
                      : !hasGenerated 
                        ? 'text-gray-600 cursor-not-allowed opacity-50' 
                        : 'text-gray-500 hover:text-white'
                  }`}
                >
                  {!hasGenerated && <Lock size={12} />} Aperçu
                </button>
             </div>
        </div>
      </div>

      <div className="grid lg:grid-cols-12 gap-8">
         {/* Main Content Area */}
         <div className="lg:col-span-8">
            <div className="ninja-card rounded-2xl overflow-hidden border border-white/[0.08] min-h-[600px] flex flex-col transition-all duration-500">
                
                {activeTab === 'edit' ? (
                    <div className="flex flex-col h-full">
                        <div className="p-8 space-y-8 flex-1">
                            {/* Toolbar */}
                            <div className="flex justify-end mb-4">
                                <button 
                                    onClick={handleReset}
                                    className="text-xs text-gray-500 hover:text-red-400 flex items-center gap-2 transition-colors px-3 py-2 rounded-full hover:bg-white/[0.04]"
                                    title="Revenir aux données extraites de l'URL"
                                >
                                    <RotateCcw size={14} /> Restaurer les données d'origine
                                </button>
                            </div>

                            {/* Identity Section */}
                            <section className="space-y-4">
                                <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2 border-b border-white/[0.06] pb-2">
                                <Building2 size={16} /> Identité Organisation
                                </h4>
                                <div className="grid md:grid-cols-2 gap-6">
                                <div className="md:col-span-2">
                                    <div className="flex justify-between mb-1.5">
                                        <label className="block text-xs font-medium text-gray-500">Description courte (Optimisée pour Context Window)</label>
                                        <span className="text-[10px] text-purple-300 flex items-center gap-1"><Sparkles size={10} /> Générée par IA</span>
                                    </div>
                                    <textarea 
                                    value={data.description}
                                    onChange={(e) => setData({...data, description: e.target.value})}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-2xl p-4 text-white focus:border-purple-500/50 outline-none h-24 text-sm transition-colors"
                                    placeholder="Décrivez votre organisation en 2-3 phrases factuelles..."
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1.5">Type d'organisation</label>
                                    <input 
                                    type="text" value={data.type}
                                    onChange={(e) => setData({...data, type: e.target.value})}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-2xl p-3 text-white text-sm focus:border-purple-500/50 outline-none transition-colors" 
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-medium text-gray-500 mb-1.5">Année de création</label>
                                    <div className="relative">
                                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                                    <input 
                                        type="text" value={data.founded}
                                        onChange={(e) => setData({...data, founded: e.target.value})}
                                        className="w-full bg-black/40 border border-white/[0.08] rounded-2xl p-3 pl-10 text-white text-sm focus:border-purple-500/50 outline-none transition-colors" 
                                    />
                                    </div>
                                </div>
                                <div className="md:col-span-2">
                                    <label className="block text-xs font-medium text-gray-500 mb-1.5">Localisation / Siège</label>
                                    <div className="relative">
                                    <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                                    <input 
                                        type="text" value={data.location}
                                        onChange={(e) => setData({...data, location: e.target.value})}
                                        className="w-full bg-black/40 border border-white/[0.08] rounded-2xl p-3 pl-10 text-white text-sm focus:border-purple-500/50 outline-none transition-colors" 
                                    />
                                    </div>
                                </div>
                                </div>
                            </section>

                            {/* Services Section */}
                            <section className="space-y-4 pt-4">
                                <div className="flex justify-between items-center border-b border-white/[0.06] pb-2">
                                <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2">
                                    <Sparkles size={16} /> Services & Offres Clés
                                </h4>
                                <button onClick={addService} className="text-xs flex items-center gap-1 text-gray-500 hover:text-white bg-white/[0.04] px-2 py-1 rounded hover:bg-white/[0.08] transition-colors"><Plus size={14} /> Ajouter</button>
                                </div>
                                {data.services.map((service, idx) => (
                                <div key={idx} className="bg-white/[0.02] p-5 rounded-2xl border border-white/[0.06] hover:border-white/[0.08] transition-colors group relative">
                                    <button onClick={() => removeService(idx)} className="absolute top-4 right-4 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity p-1"><Trash2 size={16} /></button>
                                    <div className="grid md:grid-cols-2 gap-4 mb-3">
                                    <input 
                                        placeholder="Nom du service"
                                        value={service.name}
                                        onChange={(e) => handleServiceChange(idx, 'name', e.target.value)}
                                        className="bg-black/40 border border-white/[0.08] rounded-xl p-2.5 text-sm text-white focus:border-purple-500/30 outline-none"
                                    />
                                    <input 
                                        placeholder="Catégorie (ex: Analytics)"
                                        value={service.category}
                                        onChange={(e) => handleServiceChange(idx, 'category', e.target.value)}
                                        className="bg-black/40 border border-white/[0.08] rounded-xl p-2.5 text-sm text-white focus:border-purple-500/30 outline-none"
                                    />
                                    </div>
                                    <textarea 
                                    placeholder="Description factuelle (ce que l'IA doit retenir)..."
                                    value={service.description}
                                    onChange={(e) => handleServiceChange(idx, 'description', e.target.value)}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-2.5 text-sm text-white h-20 focus:border-purple-500/30 outline-none resize-none"
                                    />
                                </div>
                                ))}
                            </section>

                            {/* FAQ Section */}
                            <section className="space-y-4 pt-4">
                                <div className="flex justify-between items-center border-b border-white/[0.06] pb-2">
                                <h4 className="text-sm font-bold text-purple-400 uppercase tracking-wider flex items-center gap-2">
                                    <FileText size={16} /> FAQ (Knowledge Graph)
                                </h4>
                                <button onClick={addFaq} className="text-xs flex items-center gap-1 text-gray-500 hover:text-white bg-white/[0.04] px-2 py-1 rounded hover:bg-white/[0.08] transition-colors"><Plus size={14} /> Ajouter</button>
                                </div>
                                {data.faqs.map((faq, idx) => (
                                <div key={idx} className="bg-white/[0.02] p-5 rounded-2xl border border-white/[0.06] hover:border-white/[0.08] transition-colors group relative">
                                    <button onClick={() => removeFaq(idx)} className="absolute top-4 right-4 text-gray-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity p-1"><Trash2 size={16} /></button>
                                    <input 
                                    placeholder="Question fréquente ?"
                                    value={faq.question}
                                    onChange={(e) => handleFaqChange(idx, 'question', e.target.value)}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-2.5 text-sm text-white mb-3 font-medium focus:border-purple-500/30 outline-none"
                                    />
                                    <textarea 
                                    placeholder="Réponse de référence..."
                                    value={faq.answer}
                                    onChange={(e) => handleFaqChange(idx, 'answer', e.target.value)}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-2.5 text-sm text-gray-300 h-20 focus:border-purple-500/30 outline-none resize-none"
                                    />
                                </div>
                                ))}
                            </section>
                        </div>
                        
                        {/* Generate Button Footer */}
                        <div className="p-6 border-t border-white/[0.08] bg-[#000000] sticky bottom-0 z-10 flex justify-end">
                             <div className="flex items-center gap-4">
                                {user && (
                                   <p className="text-xs text-gray-500">
                                      Crédits disponibles: <span className="font-bold text-white">{user.credits}</span>
                                   </p>
                                )}
                                <button 
                                    onClick={handleGenerate}
                                    disabled={isGenerating}
                                    className="flex items-center gap-2 bg-purple-600 hover:bg-purple-700 text-white font-bold py-3 px-6 rounded-2xl transition-all shadow-lg shadow-purple-500/20 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <Zap size={20} className="fill-white" />}
                                    {isGenerating ? 'Mise à jour...' : `Générer les fichiers (-${GENERATION_COST})`}
                                </button>
                             </div>
                        </div>
                    </div>
                ) : (
                    <div className="h-full flex flex-col">
                        <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-[#111111]">
                            <div className="flex items-center gap-4">
                            <button onClick={() => setFormat('txt')} className={`text-xs font-bold px-3 py-1.5 rounded-full transition-colors ${format === 'txt' ? 'bg-purple-500 text-white' : 'text-gray-500 hover:text-white bg-white/[0.04]'}`}>llm.txt</button>
                            <button onClick={() => setFormat('json')} className={`text-xs font-bold px-3 py-1.5 rounded-full transition-colors ${format === 'json' ? 'bg-purple-500 text-white' : 'text-gray-500 hover:text-white bg-white/[0.04]'}`}>llm.json</button>
                            </div>
                            <div className="flex gap-2">
                            <button onClick={() => handleCopy()} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-xs font-medium text-white border border-white/[0.08] transition-colors">
                                {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
                                {copied ? 'Copié' : 'Copier'}
                            </button>
                            <button onClick={() => handleDownload()} className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-600 hover:to-violet-700 rounded-full text-xs font-bold transition-colors shadow-lg shadow-purple-500/10">
                                <Download size={14} /> Télécharger
                            </button>
                            </div>
                        </div>
                        <div className="flex-1 bg-[#111111] p-8 overflow-auto">
                            <pre className="font-mono text-sm text-gray-300 whitespace-pre-wrap">{generateContent()}</pre>
                        </div>
                    </div>
                )}
            </div>
         </div>

         {/* GUIDE D'IMPLEMENTATION - RIGHT SIDEBAR (Always visible but blurred if not generated) */}
         <div className="lg:col-span-4 animate-in slide-in-from-right duration-700 space-y-6">
            <div className="mb-2">
                <h2 className="text-xl font-sans font-bold text-white flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-white/[0.04] flex items-center justify-center text-gray-300 border border-white/[0.08]">
                        <BookOpen size={18} />
                    </div>
                    Guide d'implémentation
                </h2>
            </div>

            <div className={`relative transition-all duration-700 ${!hasGenerated ? 'filter blur-sm opacity-50 pointer-events-none select-none grayscale' : ''}`}>
                
                {/* Overlay Lock when not generated */}
                {!hasGenerated && (
                    <div className="absolute inset-0 z-10 flex flex-col items-center justify-center text-center p-6">
                        <div className="w-12 h-12 bg-black/50 backdrop-blur-md rounded-full flex items-center justify-center text-white mb-2 border border-white/[0.08] shadow-xl">
                            <Lock size={20} />
                        </div>
                        <p className="text-white font-bold text-sm bg-black/50 px-3 py-1 rounded-full border border-white/[0.08]">Générer pour débloquer</p>
                    </div>
                )}

                {/* Step 1: Hébergement Standard */}
                <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] relative overflow-hidden mb-6">
                    <div className="absolute top-0 right-0 p-3 opacity-5">
                        <Server size={48} />
                    </div>
                    <div className="flex items-center gap-3 mb-3">
                        <div className="w-8 h-8 rounded-full bg-blue-500/20 flex items-center justify-center text-blue-400 font-bold border border-blue-500/30 text-sm">1</div>
                        <h3 className="text-base font-bold text-white">Hébergement Racine</h3>
                    </div>
                    <p className="text-xs text-gray-500 leading-relaxed mb-3">
                        Le fichier doit impérativement être accessible à la racine de votre domaine pour être découvert par les bots respectant le standard <code>llm.txt</code>.
                    </p>
                    <div className="bg-black/40 p-2.5 rounded-xl border border-white/[0.06] font-mono text-[10px] text-purple-300 break-all flex items-center gap-2">
                        <Globe size={12} className="text-gray-500" />
                        https://{currentHostname}/llm.txt
                    </div>
                </div>

                {/* Step 2: Déclaration HTML */}
                <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] relative overflow-hidden mb-6">
                    <div className="absolute top-0 right-0 p-3 opacity-5">
                        <FileCode size={48} />
                    </div>
                    <div className="flex items-center gap-3 mb-3">
                        <div className="w-8 h-8 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-400 font-bold border border-purple-500/30 text-sm">2</div>
                        <h3 className="text-base font-bold text-white">Discovery Link</h3>
                    </div>
                    <p className="text-xs text-gray-500 leading-relaxed mb-3">
                        Ajoutez cette balise dans le <code>&lt;head&gt;</code> de votre page d'accueil pour signaler explicitement le fichier aux crawlers IA.
                    </p>
                    <div className="bg-black/40 p-2.5 rounded-xl border border-white/[0.06] font-mono text-[10px] text-purple-300 break-all">
                        &lt;link rel="llm-text" href="/llm.txt" /&gt;
                    </div>
                </div>

                {/* Step 3: Conformité Technique */}
                <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-3 opacity-5">
                        <ShieldCheck size={48} />
                    </div>
                    <div className="flex items-center gap-3 mb-3">
                        <div className="w-8 h-8 rounded-full bg-purple-400/20 flex items-center justify-center text-purple-300 font-bold border border-purple-400/30 text-sm">3</div>
                        <h3 className="text-base font-bold text-white">Standards Requis</h3>
                    </div>
                    <ul className="space-y-3 text-[10px] text-gray-500">
                        <li className="flex items-start gap-2">
                            <Check size={12} className="text-purple-400 mt-0.5"/> 
                            <span>Format <strong>Markdown</strong> standardisé</span>
                        </li>
                        <li className="flex items-start gap-2">
                            <Check size={12} className="text-purple-400 mt-0.5"/> 
                            <span>Encodage <strong>UTF-8</strong> obligatoire</span>
                        </li>
                        <li className="flex items-start gap-2">
                            <Check size={12} className="text-purple-400 mt-0.5"/> 
                            <span>MIME Type : <code>text/plain</code> ou <code>text/markdown</code></span>
                        </li>
                        <li className="flex items-start gap-2">
                            <Check size={12} className="text-purple-400 mt-0.5"/> 
                            <span>Ne pas bloquer via <strong>robots.txt</strong></span>
                        </li>
                    </ul>
                </div>
            </div>
         </div>
      </div>

      {/* HISTORIQUE DES FICHIERS */}
      {savedFiles.length > 0 && (
        <div className="mt-12 border-t border-white/[0.08] pt-10">
            <h3 className="text-xl font-sans font-bold text-white mb-6 flex items-center gap-2">
                <Archive size={20} className="text-gray-500" />
                Historique des versions
            </h3>
            
            <div className="grid md:grid-cols-3 lg:grid-cols-4 gap-6">
                {savedFiles.map((file) => (
                    <div key={file.id} className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-purple-500/30 transition-all flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <span className="text-[10px] font-bold px-2 py-1 rounded bg-purple-500/10 text-purple-400 border border-white/[0.1] uppercase">
                                llm.{format}
                            </span>
                            <span className="text-xs text-gray-500">{new Date(file.timestamp).toLocaleDateString()}</span>
                        </div>
                        
                        <h4 className="font-bold text-white mb-2 text-sm line-clamp-1">{file.title}</h4>
                        
                        <div className="bg-[#000000] p-3 rounded border border-white/[0.06] mb-4 flex-1 overflow-hidden relative h-20">
                            <p className="text-[10px] text-gray-500 font-mono line-clamp-3">{file.content}</p>
                            <div className="absolute bottom-0 left-0 w-full h-6 bg-gradient-to-t from-[#000000] to-transparent"></div>
                        </div>

                        <div className="flex gap-2">
                            <button 
                                onClick={() => handleCopy(file.content)}
                                className="flex-1 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
                            >
                                <Copy size={10} /> Copier
                            </button>
                            <button 
                                onClick={() => handleDownload(`llm_archive_${file.id}.${format}`, file.content)}
                                className="flex-1 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
                            >
                                <Download size={10} /> DL
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      )}
    </div>
  );
};

export default SourceOfTruth;
"}

{"content":"import React, { useState, useEffect } from 'react';
import { AnalysisResult, User, SMCContent } from '../types';
import { generateJsonLd, generateSchemaWithAI, SchemaInput } from '../services/schema_service';
import { ArrowLeft, Code, Download, Copy, Check, ShieldCheck, Globe, Share2, Building2, Phone, Mail, Image as ImageIcon, ExternalLink, RefreshCw, Zap, Archive, Eye, Sparkles, Loader2 } from 'lucide-react';

interface Props {
  onBack: () => void;
  history: AnalysisResult[];
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  savedFiles: SMCContent[];
  onSaveFile: (item: SMCContent) => void;
}

const SchemaOrg: React.FC<Props> = ({ onBack, history, user, onDeductCredits, savedFiles, onSaveFile }) => {
  const [copied, setCopied] = useState(false);
  const [formData, setFormData] = useState<SchemaInput>({
    name: '',
    url: '',
    logoUrl: '',
    description: '',
    socialProfiles: ['', '', ''],
    contactPhone: '',
    contactEmail: '',
    alternateName: ''
  });
  
  const [jsonOutput, setJsonOutput] = useState('');
  const [isGenerated, setIsGenerated] = useState(false);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [generationMode, setGenerationMode] = useState<'local' | 'ai'>('local');

  // Pré-remplissage basé sur l'historique
  useEffect(() => {
    if (history.length > 0) {
      const latest = history[0];
      const urlObj = new URL(latest.url);
      const hostname = urlObj.hostname;
      const name = hostname.replace('www.', '').split('.')[0];
      const formattedName = name.charAt(0).toUpperCase() + name.slice(1);

      setFormData(prev => ({
        ...prev,
        name: formattedName,
        url: urlObj.origin,
        logoUrl: `${urlObj.origin}/logo.png`,
        description: `Site officiel de ${formattedName}.`,
        contactEmail: `contact@${hostname}`
      }));
    }
  }, [history]);

  // Régénération automatique à chaque changement du formulaire
  useEffect(() => {
    if (isGenerated) {
        setJsonOutput(generateJsonLd(formData));
    }
  }, [formData, isGenerated]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSocialChange = (index: number, value: string) => {
    const newSocials = [...formData.socialProfiles];
    newSocials[index] = value;
    setFormData({ ...formData, socialProfiles: newSocials });
  };

  const handleGenerate = async (mode: 'local' | 'ai' = 'local') => {
    const cost = mode === 'ai' ? 8 : 5;
    if (!onDeductCredits(cost)) return;

    setGenerationMode(mode);

    if (mode === 'ai') {
      // Check pre-generated cache first (only if form hasn't been significantly modified from defaults)
      const cachedSchema = history.length > 0 ? history[0]?.preGenerated?.schemaOrg : undefined;
      if (cachedSchema?.content) {
        setJsonOutput(cachedSchema.content);
        setIsGenerated(true);
        onSaveFile({
          id: `schema_ai_${Date.now()}`,
          type: 'fiche',
          title: `Schema Organization (AI) - ${formData.name}`,
          content: cachedSchema.content,
          timestamp: new Date().toISOString()
        });
        return;
      }

      setIsGeneratingAI(true);
      try {
        const result = await generateSchemaWithAI(formData);
        setJsonOutput(result.content);
        setIsGenerated(true);
        onSaveFile({
          id: `schema_ai_${Date.now()}`,
          type: 'fiche',
          title: `Schema Organization (AI) - ${formData.name}`,
          content: result.content,
          timestamp: new Date().toISOString()
        });
      } catch {
        // Fallback to local on error
        const output = generateJsonLd(formData);
        setJsonOutput(output);
        setIsGenerated(true);
      } finally {
        setIsGeneratingAI(false);
      }
    } else {
      const output = generateJsonLd(formData);
      setJsonOutput(output);
      setIsGenerated(true);
      onSaveFile({
        id: `schema_${Date.now()}`,
        type: 'fiche',
        title: `Schema Organization - ${formData.name}`,
        content: output,
        timestamp: new Date().toISOString()
      });
    }
  };

  const handleCopy = (content?: string) => {
    navigator.clipboard.writeText(content || jsonOutput);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = (filename?: string, content?: string) => {
    const blob = new Blob([content || jsonOutput], { type: 'application/ld+json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename || 'schema.jsonld';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleRestore = (content: string) => {
      // Pour une restauration complète, il faudrait parser le JSON pour remplir le formulaire
      // Ici on restaure juste le code de sortie pour la visualisation
      setJsonOutput(content);
      setIsGenerated(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="animate-in fade-in duration-500">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-purple-500/20 flex items-center justify-center text-purple-400 border border-purple-500/30">
              <Code size={24} />
            </div>
            Générateur Schema.org
          </h1>
          <p className="text-gray-500">Créez le JSON-LD "Organization" pour connecter votre marque au Knowledge Graph de Google et des IA.</p>
        </div>
        
        {user && (
            <div className="bg-white/[0.04] border border-white/[0.08] px-4 py-2 rounded-2xl text-sm text-gray-300">
                Solde : <span className="font-bold text-white">{user.credits}</span> Gas
            </div>
        )}
      </div>

      <div className="grid lg:grid-cols-12 gap-8">
        
        {/* Formulaire Gauche */}
        <div className="lg:col-span-5 space-y-6">
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
                <h3 className="font-bold text-white mb-4 flex items-center gap-2">
                    <Building2 size={18} className="text-purple-400" /> Identité de l'Organisation
                </h3>
                
                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Nom de l'organisation</label>
                        <input 
                            type="text" 
                            name="name"
                            value={formData.name}
                            onChange={handleInputChange}
                            className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                            placeholder="Ex: CitedBy Corp"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Nom alternatif (Optionnel)</label>
                        <input 
                            type="text" 
                            name="alternateName"
                            value={formData.alternateName}
                            onChange={handleInputChange}
                            className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                            placeholder="Ex: CBC"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">URL du site Web</label>
                        <div className="relative">
                            <Globe size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                            <input 
                                type="url" 
                                name="url"
                                value={formData.url}
                                onChange={handleInputChange}
                                className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                placeholder="https://..."
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">URL du Logo</label>
                        <div className="relative">
                            <ImageIcon size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                            <input 
                                type="url" 
                                name="logoUrl"
                                value={formData.logoUrl}
                                onChange={handleInputChange}
                                className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                placeholder="https://.../logo.png"
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Description courte</label>
                        <textarea 
                            name="description"
                            value={formData.description}
                            onChange={handleInputChange}
                            rows={3}
                            className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none resize-none"
                            placeholder="Description pour le Knowledge Graph..."
                        />
                    </div>
                </div>
            </div>

            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
                <h3 className="font-bold text-white mb-4 flex items-center gap-2">
                    <Share2 size={18} className="text-purple-400" /> Réseaux & Contact
                </h3>
                
                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Profils Sociaux (sameAs)</label>
                        <div className="space-y-2">
                            {formData.socialProfiles.map((url, idx) => (
                                <input 
                                    key={idx}
                                    type="url" 
                                    value={url}
                                    onChange={(e) => handleSocialChange(idx, e.target.value)}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                    placeholder={`URL Profil social ${idx + 1}`}
                                />
                            ))}
                        </div>
                        <p className="text-[10px] text-gray-500 mt-1">Essentiel pour la désambiguïsation de l'entité.</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs font-medium text-gray-500 mb-1">Téléphone</label>
                            <div className="relative">
                                <Phone size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                                <input 
                                    type="tel" 
                                    name="contactPhone"
                                    value={formData.contactPhone}
                                    onChange={handleInputChange}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                    placeholder="+33..."
                                />
                            </div>
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-gray-500 mb-1">Email</label>
                            <div className="relative">
                                <Mail size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                                <input 
                                    type="email" 
                                    name="contactEmail"
                                    value={formData.contactEmail}
                                    onChange={handleInputChange}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                    placeholder="contact@..."
                                />
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="space-y-3">
              <button
                  onClick={() => handleGenerate('ai')}
                  disabled={isGeneratingAI}
                  className="w-full py-4 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-2xl transition-all shadow-lg shadow-purple-500/20 flex items-center justify-center gap-2 disabled:opacity-60"
              >
                  {isGeneratingAI ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
                  {isGeneratingAI ? 'Gemini génère le Schema.org enrichi...' : `Générer avec Gemini AI (-8 Gas)`}
              </button>
              <button
                  onClick={() => handleGenerate('local')}
                  disabled={isGeneratingAI}
                  className="w-full py-3 bg-white/[0.04] hover:bg-white/[0.08] border border-white/[0.08] text-gray-300 font-medium rounded-2xl transition-all flex items-center justify-center gap-2 text-sm disabled:opacity-60"
              >
                  {isGenerated && generationMode === 'local' ? <RefreshCw size={16} /> : <Zap size={16} />}
                  {isGenerated && generationMode === 'local' ? 'Regénérer (local, -5 Gas)' : 'Génération rapide locale (-5 Gas)'}
              </button>
            </div>
        </div>

        {/* Output Droite */}
        <div className="lg:col-span-7 flex flex-col gap-6">
            <div className="bg-[#0f1115] border border-white/[0.08] rounded-2xl flex flex-col shadow-2xl overflow-hidden h-full min-h-[500px]">
                <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-white/[0.04]">
                    <div className="flex items-center gap-2">
                        <span className="text-sm font-bold text-white flex items-center gap-2">
                            <Code size={16} className="text-purple-400" />
                            {'<script type="application/ld+json">'}
                        </span>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={() => handleCopy()} disabled={!isGenerated} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-xs font-medium text-white border border-white/[0.08] transition-colors disabled:opacity-50">
                            {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
                            {copied ? 'Copié' : 'Copier'}
                        </button>
                        <button onClick={() => handleDownload()} disabled={!isGenerated} className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-600 hover:to-violet-700 rounded-full text-xs font-bold transition-colors disabled:opacity-50">
                            <Download size={14} /> Télécharger
                        </button>
                    </div>
                </div>
                
                <div className="relative bg-[#000000] p-6 flex-1 group">
                    {isGenerated ? (
                        <pre className="font-mono text-sm text-purple-100/90 whitespace-pre-wrap leading-relaxed selection:bg-purple-500/30 overflow-auto h-full max-h-[600px]">
                            {jsonOutput}
                        </pre>
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-500 opacity-50">
                            <Code size={64} className="mb-4" />
                            <p>Remplissez le formulaire pour générer le code.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Implementation Guide */}
            <div className="bg-white/[0.04] rounded-2xl border border-white/[0.08] p-6">
                <h3 className="font-bold text-white mb-4 flex items-center gap-2">
                    <ShieldCheck size={18} className="text-purple-300" /> Guide d'implémentation
                </h3>
                <div className="space-y-4 text-sm text-gray-300">
                    <div className="flex gap-4">
                        <div className="w-6 h-6 rounded-full bg-white/[0.08] flex items-center justify-center text-xs font-bold shrink-0">1</div>
                        <div>
                            <strong className="text-white block mb-1">Insertion dans le Header</strong>
                            Copiez le code et collez-le dans la section <code>&lt;head&gt;</code> de toutes vos pages (ou au moins la page d'accueil).
                        </div>
                    </div>
                    <div className="flex gap-4">
                        <div className="w-6 h-6 rounded-full bg-white/[0.08] flex items-center justify-center text-xs font-bold shrink-0">2</div>
                        <div>
                            <strong className="text-white block mb-1">Validation Google</strong>
                            Testez le code avec l'outil <a href="https://search.google.com/test/rich-results" target="_blank" className="text-purple-400 hover:underline inline-flex items-center gap-1">Résultats enrichis <ExternalLink size={10} /></a>.
                        </div>
                    </div>
                </div>
            </div>
        </div>

      </div>

      {/* HISTORIQUE DES FICHIERS */}
      {savedFiles.length > 0 && (
        <div className="mt-12 border-t border-white/[0.08] pt-10">
            <h3 className="text-xl font-sans font-bold text-white mb-6 flex items-center gap-2">
                <Archive size={20} className="text-gray-500" />
                Historique des versions
            </h3>
            
            <div className="grid md:grid-cols-3 lg:grid-cols-4 gap-6">
                {savedFiles.map((file) => (
                    <div key={file.id} className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-purple-500/30 transition-all flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <span className="text-[10px] font-bold px-2 py-1 rounded bg-purple-500/10 text-purple-400 border border-white/[0.1] uppercase">
                                JSON-LD
                            </span>
                            <span className="text-xs text-gray-500">{new Date(file.timestamp).toLocaleDateString()}</span>
                        </div>
                        
                        <h4 className="font-bold text-white mb-2 text-sm line-clamp-1">{file.title}</h4>
                        
                        <div className="bg-[#000000] p-3 rounded border border-white/[0.06] mb-4 flex-1 overflow-hidden relative h-20">
                            <p className="text-[10px] text-gray-500 font-mono line-clamp-3">{file.content}</p>
                            <div className="absolute bottom-0 left-0 w-full h-6 bg-gradient-to-t from-[#000000] to-transparent"></div>
                        </div>

                        <div className="flex gap-2">
                            <button 
                                onClick={() => handleRestore(file.content)}
                                className="flex-1 py-1.5 bg-purple-500/10 hover:bg-purple-500/20 rounded text-[10px] font-bold text-purple-400 transition-colors flex items-center justify-center gap-1"
                            >
                                <Eye size={10} /> Voir
                            </button>
                            <button 
                                onClick={() => handleDownload(`schema_archive_${file.id}.jsonld`, file.content)}
                                className="flex-1 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
                            >
                                <Download size={10} /> DL
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      )}
    </div>
  );
};

export default SchemaOrg;
"}

{"content":"import React, { useState, useEffect } from 'react';
import { AnalysisResult, User, SMCContent } from '../types';
import { generateOptimizedRobotsTxt, generateRobotsWithAI, parseCurrentRobotsTxt, getDetectedPlatformName } from '../services/robots_service';
import { ArrowLeft, FileCode, Download, Copy, Check, Bot, ShieldCheck, AlertTriangle, RefreshCw, ChevronDown, History, Server, Eye, Settings, FileJson, Globe, Terminal, Lock, Zap, Archive, Sparkles, Loader2 } from 'lucide-react';

interface Props {
  onBack: () => void;
  history: AnalysisResult[];
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  onUpdateAnalysis: (index: number, data: Partial<AnalysisResult>) => void;
  savedFiles: SMCContent[];
  onSaveFile: (item: SMCContent) => void;
}

const RobotsTxt: React.FC<Props> = ({ onBack, history, user, onDeductCredits, onUpdateAnalysis, savedFiles, onSaveFile }) => {
  const [selectedAnalysisIndex, setSelectedAnalysisIndex] = useState<number>(0);
  const [currentContent, setCurrentContent] = useState('');
  const [optimizedContent, setOptimizedContent] = useState('');
  const [platformName, setPlatformName] = useState('');
  const [copied, setCopied] = useState(false);
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);

  const GENERATION_COST = 10;
  const AI_GENERATION_COST = 15;

  // Initialize with data from history
  useEffect(() => {
    const processUrl = (analysis: AnalysisResult | undefined) => {
        if (!analysis) {
            // Mode Demo / Fallback
            const demoUrl = "https://monsite-wordpress.com";
            setCurrentContent(parseCurrentRobotsTxt(demoUrl));
            setOptimizedContent(generateOptimizedRobotsTxt(demoUrl));
            setPlatformName(getDetectedPlatformName(demoUrl));
            setIsUnlocked(false);
            return;
        }

        const url = analysis.url;
        setCurrentContent(parseCurrentRobotsTxt(url));
        setPlatformName(getDetectedPlatformName(url));

        // Check if previously unlocked/saved in history
        if (analysis.robotsTxtData && analysis.robotsTxtData.isUnlocked) {
            setOptimizedContent(analysis.robotsTxtData.content);
            setIsUnlocked(true);
        } else {
            // Fresh generation (locked)
            setOptimizedContent(generateOptimizedRobotsTxt(url));
            setIsUnlocked(false);
        }
    };

    if (history.length > 0) {
      processUrl(history[selectedAnalysisIndex]);
    } else {
      processUrl(undefined);
    }
  }, [selectedAnalysisIndex, history]);

  const handleUnlock = () => {
    if (onDeductCredits(GENERATION_COST)) {
        setIsUnlocked(true);

        if (history.length > 0) {
            onUpdateAnalysis(selectedAnalysisIndex, {
                robotsTxtData: {
                    content: optimizedContent,
                    isUnlocked: true,
                    platform: platformName,
                    generatedAt: new Date().toISOString()
                }
            });
        }

        onSaveFile({
            id: `robots_${Date.now()}`,
            type: 'fiche',
            title: `Robots.txt - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
            content: optimizedContent,
            timestamp: new Date().toISOString()
        });
    }
  };

  const handleUnlockAI = async () => {
    if (!onDeductCredits(AI_GENERATION_COST)) return;

    // Check for pre-generated cache first
    const cachedRobots = history.length > 0 && selectedAnalysisIndex === 0
      ? history[0]?.preGenerated?.robotsTxt
      : undefined;

    if (cachedRobots?.content) {
      setOptimizedContent(cachedRobots.content);
      setPlatformName(cachedRobots.platformDetected);
      setIsUnlocked(true);

      if (history.length > 0) {
        onUpdateAnalysis(selectedAnalysisIndex, {
          robotsTxtData: {
            content: cachedRobots.content,
            isUnlocked: true,
            platform: cachedRobots.platformDetected,
            generatedAt: new Date().toISOString()
          }
        });
      }

      onSaveFile({
        id: `robots_ai_${Date.now()}`,
        type: 'fiche',
        title: `Robots.txt (AI) - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
        content: cachedRobots.content,
        timestamp: new Date().toISOString()
      });
      return;
    }

    setIsGeneratingAI(true);
    try {
      const url = history.length > 0 ? history[selectedAnalysisIndex].url : 'https://monsite-wordpress.com';
      const result = await generateRobotsWithAI(url);
      setOptimizedContent(result.content);
      setPlatformName(result.platformDetected);
      setIsUnlocked(true);

      if (history.length > 0) {
        onUpdateAnalysis(selectedAnalysisIndex, {
          robotsTxtData: {
            content: result.content,
            isUnlocked: true,
            platform: result.platformDetected,
            generatedAt: new Date().toISOString()
          }
        });
      }

      onSaveFile({
        id: `robots_ai_${Date.now()}`,
        type: 'fiche',
        title: `Robots.txt (AI) - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
        content: result.content,
        timestamp: new Date().toISOString()
      });
    } catch {
      // Fallback to local generation
      setIsUnlocked(true);
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleDownload = (filename?: string, content?: string) => {
    const blob = new Blob([content || optimizedContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename || 'robots.txt';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCopy = (content?: string) => {
    navigator.clipboard.writeText(content || optimizedContent);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getImplementationSteps = (platform: string) => {
    if (platform.includes('WordPress')) {
      return {
        title: "Installation sur WordPress",
        icon: <Settings size={20} />,
        steps: [
          "Connectez-vous à votre tableau de bord WordPress (/wp-admin).",
          "Si vous utilisez Yoast SEO : Allez dans 'SEO' → 'Outils' → 'Éditeur de fichiers'.",
          "Si vous utilisez RankMath : Allez dans 'Rank Math' → 'Réglages généraux' → 'Modifier robots.txt'.",
          "Si aucun plugin SEO : Utilisez un plugin 'File Manager' ou un accès FTP.",
          "Copiez le code généré ci-dessus et remplacez tout le contenu existant.",
          "Sauvegardez les modifications."
        ]
      };
    }
    if (platform.includes('Shopify')) {
      return {
        title: "Installation sur Shopify",
        icon: <FileJson size={20} />,
        steps: [
          "Depuis votre admin Shopify, allez dans 'Boutique en ligne' → 'Thèmes'.",
          "Cliquez sur le bouton 'Actions' (ou les trois points) → 'Modifier le code'.",
          "Dans la barre de recherche de fichiers, tapez 'robots'.",
          "Cliquez sur 'Ajouter un nouveau modèle' → sélectionnez 'robots.txt' si robots.txt.liquid n'existe pas.",
          "Collez le code optimisé dans le fichier.",
          "Cliquez sur 'Enregistrer' en haut à droite."
        ]
      };
    }
    if (platform.includes('SaaS') || platform.includes('App')) {
      return {
        title: "Installation App Web (React/Next.js/Vue)",
        icon: <Terminal size={20} />,
        steps: [
          "Localisez le dossier 'public' ou 'static' à la racine de votre projet.",
          "Créez ou modifiez le fichier nommé 'robots.txt'.",
          "Collez le contenu généré.",
          "Pour Next.js (App Router) : Vous pouvez alternativement créer un fichier `app/robots.ts` et retourner cet objet.",
          "Redéployez votre application pour appliquer les changements."
        ]
      };
    }
    // Default
    return {
      title: "Installation Standard (Apache/Nginx/FTP)",
      icon: <Server size={20} />,
      steps: [
        "Connectez-vous à votre serveur via FTP (FileZilla) ou Gestionnaire de fichiers (cPanel).",
        "Naviguez vers le dossier racine publique (souvent /public_html/ ou /www/).",
        "Cherchez le fichier 'robots.txt'. S'il n'existe pas, créez-le.",
        "Ouvrez le fichier avec un éditeur de texte.",
        "Collez le code généré ci-dessus et sauvegardez.",
        "Vérifiez l'accès en allant sur votre-site.com/robots.txt"
      ]
    };
  };

  const guide = getImplementationSteps(platformName);

  const handleRestore = (content: string) => {
      setOptimizedContent(content);
      setIsUnlocked(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="animate-in fade-in duration-500">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-blue-500/20 flex items-center justify-center text-blue-400 border border-blue-500/30">
              <FileCode size={24} />
            </div>
            Robots.txt Optimizer
          </h1>
          <p className="text-gray-500">Ouvrez les portes aux bots IA (GPTBot, Claude, Gemini) tout en sécurisant votre site.</p>
        </div>

        {/* Project Selector */}
        {history.length > 0 && (
            <div className="relative group w-full md:w-auto">
            <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none text-gray-500">
                <History size={16} />
            </div>
            <select 
                value={selectedAnalysisIndex}
                onChange={(e) => setSelectedAnalysisIndex(Number(e.target.value))}
                className="appearance-none bg-white/[0.04] border border-white/[0.08] text-white pl-10 pr-10 py-2.5 rounded-2xl focus:outline-none focus:border-blue-500/50 w-full min-w-[250px] cursor-pointer hover:bg-white/[0.08] transition-colors"
            >
                {history.map((analysis, idx) => (
                <option key={idx} value={idx} className="bg-[#1a1d24]">
                    {new URL(analysis.url).hostname}
                </option>
                ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" size={16} />
            </div>
        )}
      </div>

      <div className="grid lg:grid-cols-2 gap-8 mb-12">
        
        {/* Left Column: Context & Education (Always Visible) */}
        <div className="space-y-6">
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                    <Server size={64} />
                </div>
                <h3 className="text-lg font-bold text-white mb-2 flex items-center gap-2">
                    <Eye size={18} className="text-blue-400" /> Analyse Technique
                </h3>
                <div className="flex items-center gap-2 mb-4">
                    <span className="text-sm text-gray-500">Architecture détectée :</span>
                    <span className="px-2 py-1 bg-blue-500/20 text-blue-300 text-xs font-bold rounded uppercase border border-blue-500/30">
                        {platformName}
                    </span>
                </div>
                <p className="text-sm text-gray-500 leading-relaxed mb-4">
                    Nous avons adapté les règles <code>Disallow</code> pour masquer les routes sensibles spécifiques à votre technologie ({platformName}), tout en ouvrant les routes de contenu public aux bots IA.
                </p>

                <div className="bg-[#111111] p-4 rounded-2xl border border-white/[0.06] font-mono text-xs text-gray-500 overflow-auto max-h-[150px] relative">
                    <div className="absolute top-2 right-2 text-[10px] text-gray-600 font-sans bg-white/[0.04] px-2 py-1 rounded">Fichier Actuel (Simulé)</div>
                    <pre>{currentContent}</pre>
                </div>
            </div>

            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
                <h3 className="text-lg font-bold text-white mb-4">La Stratégie "Open-AI, Closed-Admin"</h3>
                <ul className="space-y-4">
                    <li className="flex items-start gap-3">
                        <div className="w-8 h-8 rounded-full bg-green-500/20 flex items-center justify-center shrink-0 text-green-400"><Bot size={16} /></div>
                        <div>
                            <p className="text-sm font-bold text-gray-200">Whitelist Explicite</p>
                            <p className="text-xs text-gray-500">
                                GPTBot, CCBot et Google-Extended sont souvent bloqués par défaut par les pare-feux. Ce fichier force leur autorisation pour garantir votre citation.
                            </p>
                        </div>
                    </li>
                    <li className="flex items-start gap-3">
                        <div className="w-8 h-8 rounded-full bg-purple-500/20 flex items-center justify-center shrink-0 text-purple-400"><AlertTriangle size={16} /></div>
                        <div>
                            <p className="text-sm font-bold text-gray-200">Protection Budgétaire</p>
                            <p className="text-xs text-gray-500">
                                En bloquant les dossiers <code>/api/</code> ou <code>/search/</code>, nous évitons que les bots IA ne consomment vos ressources serveur inutilement.
                            </p>
                        </div>
                    </li>
                </ul>
            </div>
        </div>

        {/* Right Column: Optimized Output (Locked or Unlocked based on history) */}
        <div className="flex flex-col">
            <div className="bg-[#0f1115] border border-white/[0.08] rounded-2xl flex flex-col shadow-2xl overflow-hidden relative">
                
                <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-white/[0.04]">
                    <div className="flex items-center gap-2">
                        <div className={`w-2 h-2 rounded-full ${isUnlocked ? 'bg-purple-400 animate-pulse' : 'bg-gray-500'}`}></div>
                        <span className="text-sm font-bold text-white">robots.txt (Optimisé AEO)</span>
                        {!isUnlocked && <Lock size={14} className="text-gray-500 ml-1" />}
                        {isUnlocked && history.length > 0 && history[selectedAnalysisIndex]?.robotsTxtData && (
                            <span className="text-xs text-purple-300 bg-purple-400/10 px-2 py-0.5 rounded ml-2">Payé</span>
                        )}
                    </div>
                    <div className="flex gap-2">
                        {isUnlocked ? (
                            <>
                                <button onClick={() => handleCopy()} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-xs font-medium text-white border border-white/[0.08] transition-colors">
                                    {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
                                    {copied ? 'Copié' : 'Copier'}
                                </button>
                                <button onClick={() => handleDownload()} className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-600 hover:to-violet-700 rounded-full text-xs font-bold transition-colors">
                                    <Download size={14} /> Télécharger
                                </button>
                            </>
                        ) : (
                            <span className="text-xs text-gray-500 flex items-center gap-1 bg-white/[0.04] px-2 py-1 rounded">
                                <Lock size={10} /> Aperçu verrouillé
                            </span>
                        )}
                    </div>
                </div>
                
                <div className="relative bg-[#000000] p-6 h-[300px] group">
                    {isUnlocked ? (
                        <pre className="font-mono text-sm text-purple-100/90 whitespace-pre-wrap leading-relaxed selection:bg-purple-400/30 overflow-auto h-full">
                            {optimizedContent}
                        </pre>
                    ) : (
                        <>
                            {/* Blurry Code Placeholder */}
                            <pre className="font-mono text-sm text-gray-600 blur-[4px] opacity-50 select-none overflow-hidden h-full">
                                {`User-agent: GPTBot\nAllow: /\nUser-agent: CCBot\nAllow: /\n\n# Secure Admin Paths\nDisallow: /wp-admin/\nDisallow: /private/\n\n# Sitemap Declaration\nSitemap: https://...`}
                            </pre>
                            
                            {/* Unlock Overlay */}
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 backdrop-blur-[2px] z-10 p-6 text-center">
                                <div className="w-12 h-12 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-400 mb-4 border border-primary/30">
                                    {isGeneratingAI ? <Loader2 size={24} className="animate-spin" /> : <Lock size={24} />}
                                </div>
                                <h4 className="text-white font-bold text-lg mb-2">
                                    {isGeneratingAI ? 'Gemini analyse votre site...' : 'Fichier Optimisé Prêt'}
                                </h4>
                                <p className="text-gray-300 text-sm mb-6 max-w-xs">
                                    {isGeneratingAI
                                      ? 'Génération intelligente du robots.txt avec bots IA avancés en cours...'
                                      : <>Débloquez votre fichier <code>robots.txt</code> configuré pour GPT-4, Claude et Gemini.</>
                                    }
                                </p>
                                <div className="flex flex-col gap-3 w-full max-w-xs">
                                  <button
                                      onClick={handleUnlockAI}
                                      disabled={isGeneratingAI}
                                      className="px-6 py-3 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-2xl transition-all transform hover:scale-105 shadow-[0_0_20px_rgba(168,85,247,0.2)] flex items-center justify-center gap-2 disabled:opacity-60 disabled:transform-none"
                                  >
                                      {isGeneratingAI ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
                                      {isGeneratingAI ? 'Génération en cours...' : `Générer avec Gemini AI (-${AI_GENERATION_COST} Gas)`}
                                  </button>
                                  <button
                                      onClick={handleUnlock}
                                      disabled={isGeneratingAI}
                                      className="px-6 py-2.5 bg-white/[0.04] hover:bg-white/[0.08] border border-white/[0.08] text-gray-300 font-medium rounded-2xl transition-all flex items-center justify-center gap-2 text-sm disabled:opacity-60"
                                  >
                                      <Zap size={14} />
                                      Génération rapide locale (-{GENERATION_COST} Gas)
                                  </button>
                                </div>
                                <p className="text-xs text-gray-500 mt-4">
                                    Solde actuel : <span className="text-white font-bold">{user ? user.credits : 0}</span> crédits
                                </p>
                            </div>
                        </>
                    )}
                </div>

                <div className="p-4 border-t border-white/[0.08] bg-white/[0.04] text-xs text-gray-500 flex justify-between items-center">
                    <span>Généré pour : {platformName}</span>
                    <span>{isUnlocked ? `Taille : ~${optimizedContent.length} bytes` : 'En attente de déverrouillage'}</span>
                </div>
            </div>
        </div>
      </div>

      {/* IMPLEMENTATION GUIDE SECTION (Blurred if locked to add value) */}
      <div className={`border-t border-white/[0.08] pt-10 transition-all duration-500 ${!isUnlocked ? 'opacity-50 blur-[2px] pointer-events-none grayscale' : ''}`}>
        <h2 className="text-2xl font-sans font-bold text-white mb-6 flex items-center gap-3">
            <div className="w-8 h-8 rounded-full bg-white/[0.04] flex items-center justify-center text-gray-300">
                {guide.icon}
            </div>
            Guide d'implémentation : {guide.title}
        </h2>
        
        <div className="grid md:grid-cols-2 gap-8 items-start">
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08] bg-gradient-to-br from-white/5 to-transparent">
                <ol className="relative border-l border-white/[0.08] ml-3 space-y-8">
                    {guide.steps.map((step, index) => (
                        <li key={index} className="pl-8 relative group">
                            <span className="absolute -left-[17px] top-0 flex items-center justify-center w-8 h-8 bg-[#000000] border border-white/20 rounded-full text-xs font-bold text-gray-500 group-hover:text-purple-400 group-hover:border-primary transition-colors">
                                {index + 1}
                            </span>
                            <p className="text-gray-300 leading-relaxed group-hover:text-white transition-colors text-sm">
                                {step}
                            </p>
                        </li>
                    ))}
                </ol>
            </div>

            <div className="space-y-6">
                <div className="bg-purple-500/10 border border-white/[0.1] rounded-2xl p-6">
                    <h4 className="text-purple-300 font-bold mb-2 flex items-center gap-2">
                        <AlertTriangle size={18} /> Point de Vigilance
                    </h4>
                    <p className="text-sm text-purple-200/80 leading-relaxed">
                        Une erreur dans le fichier <code>robots.txt</code> peut désindexer totalement votre site de Google. 
                        Avant de mettre en production, testez toujours votre fichier avec l'outil de test du fichier robots.txt de la Google Search Console.
                    </p>
                </div>

                <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] flex items-center gap-4">
                    <div className="w-12 h-12 rounded-full bg-purple-500/10 flex items-center justify-center text-purple-400 shrink-0">
                        <Globe size={24} />
                    </div>
                    <div>
                        <h4 className="font-bold text-white text-sm">Vérification Post-Install</h4>
                        <p className="text-xs text-gray-500 mt-1">
                            Accédez à <code>{history.length > 0 ? new URL(history[selectedAnalysisIndex].url).origin : 'votre-site.com'}/robots.txt</code> pour confirmer que le nouveau contenu est bien en ligne.
                        </p>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {/* HISTORIQUE DES FICHIERS */}
      {savedFiles.length > 0 && (
        <div className="mt-12 border-t border-white/[0.08] pt-10">
            <h3 className="text-xl font-sans font-bold text-white mb-6 flex items-center gap-2">
                <Archive size={20} className="text-gray-500" />
                Historique des versions
            </h3>
            
            <div className="grid md:grid-cols-3 lg:grid-cols-4 gap-6">
                {savedFiles.map((file) => (
                    <div key={file.id} className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-blue-500/30 transition-all flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <span className="text-[10px] font-bold px-2 py-1 rounded bg-blue-500/10 text-blue-400 border border-blue-500/20 uppercase">
                                robots.txt
                            </span>
                            <span className="text-xs text-gray-500">{new Date(file.timestamp).toLocaleDateString()}</span>
                        </div>
                        
                        <h4 className="font-bold text-white mb-2 text-sm line-clamp-1">{file.title}</h4>
                        
                        <div className="bg-[#000000] p-3 rounded border border-white/[0.06] mb-4 flex-1 overflow-hidden relative h-20">
                            <p className="text-[10px] text-gray-500 font-mono line-clamp-3">{file.content}</p>
                            <div className="absolute bottom-0 left-0 w-full h-6 bg-gradient-to-t from-[#000000] to-transparent"></div>
                        </div>

                        <div className="flex gap-2">
                            <button 
                                onClick={() => handleRestore(file.content)}
                                className="flex-1 py-1.5 bg-purple-500/10 hover:bg-purple-500/20 rounded text-[10px] font-bold text-purple-400 transition-colors flex items-center justify-center gap-1"
                            >
                                <Eye size={10} /> Voir
                            </button>
                            <button 
                                onClick={() => handleDownload(`robots_archive_${file.id}.txt`, file.content)}
                                className="flex-1 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
                            >
                                <Download size={10} /> DL
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      )}

    </div>
  );
};

export default RobotsTxt;
"}

{"content":"import React, { useState, useRef, useCallback } from 'react';
import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Fuel, Zap, Star, Check, Search, Bot, BrainCircuit, Database, Share2, Layers, Infinity, Radio, Globe, Droplet, Loader2, Gift, Shield, UserCheck, GraduationCap, BadgeCheck } from 'lucide-react';
import { User } from '../types';
import ScoreRing from '../components/ScoreRing';
import { auditAnswerFirst, AnswerFirstAuditResult } from '../services/answer-first-audit';

interface HomeProps {
  onNavigate: (view: 'analyze' | 'login' | 'recharge' | 'directory') => void;
  user: User | null;
  onDirectRecharge?: (packId: number) => void;
}

const Home: React.FC<HomeProps> = ({ onNavigate, user, onDirectRecharge }) => {

  // ── Score Gratuit State ──
  const [brandName, setBrandName] = useState('');
  const [siteUrl, setSiteUrl] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [auditResult, setAuditResult] = useState<AnswerFirstAuditResult | null>(null);
  const [auditError, setAuditError] = useState<string | null>(null);
  const resultsRef = useRef<HTMLDivElement>(null);

  // Derive E-E-A-T pillar scores from the 6 audit categories
  const eeatPillars = auditResult ? [
    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
  ] : [];

  const handleFreeAudit = useCallback(async () => {
    if (!brandName.trim() || !siteUrl.trim()) {
      setAuditError('Veuillez remplir les deux champs.');
      return;
    }
    // Basic URL validation
    let finalUrl = siteUrl.trim();
    if (!/^https?:\/\//i.test(finalUrl)) {
      finalUrl = 'https://' + finalUrl;
    }
    try {
      new URL(finalUrl);
    } catch {
      setAuditError('URL invalide. Exemple : https://www.example.com');
      return;
    }

    setAuditError(null);
    setAuditResult(null);
    setIsAnalyzing(true);

    try {
      const result = await auditAnswerFirst(finalUrl, brandName.trim());
      setAuditResult(result);
      // Scroll to results after a small delay for render
      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 150);
    } catch (err) {
      setAuditError('Une erreur est survenue lors de l\'analyse. Veuillez reessayer.');
    } finally {
      setIsAnalyzing(false);
    }
  }, [brandName, siteUrl]);

  const getScoreLabel = (score: number): string => {
    if (score >= 80) return 'Excellent';
    if (score >= 60) return 'Bon';
    if (score >= 40) return 'Moyen';
    if (score >= 20) return 'Faible';
    return 'Critique';
  };

  const getScoreColor = (score: number): string => {
    if (score >= 80) return 'text-purple-400';
    if (score >= 60) return 'text-violet-400';
    if (score >= 40) return 'text-amber-400';
    return 'text-red-400';
  };

  const getBarColor = (score: number): string => {
    if (score >= 80) return 'bg-purple-500';
    if (score >= 60) return 'bg-violet-500';
    if (score >= 40) return 'bg-amber-500';
    return 'bg-red-500';
  };

  const handleStartAnalysis = () => {
    if (user) {
      onNavigate('analyze');
    } else {
      onNavigate('login');
    }
  };

  const handleSelectPlan = (packId: number) => {
    if (user) {
      if (onDirectRecharge) {
        onDirectRecharge(packId);
      } else {
        onNavigate('recharge');
      }
    } else {
      onNavigate('login');
    }
  };

  const plans = [
    {
      id: 1,
      name: "Le Jerrican",
      credits: 50,
      price: 15,
      icon: <Droplet size={24} />,
      popular: false,
      features: ["Id\u00e9al pour tester", "1 Audit complet", "Valable 1 an"]
    },
    {
      id: 2,
      name: "La Pompe",
      credits: 200,
      price: 49,
      icon: <Fuel size={24} />,
      popular: true,
      features: ["Pour optimiser s\u00e9rieusement", "Support prioritaire", "+10% Bonus offert"]
    },
    {
      id: 3,
      name: "La Citerne",
      credits: 1000,
      price: 199,
      icon: <Database size={24} />,
      popular: false,
      features: ["Usage intensif / Agence", "Acc\u00e8s API Beta", "+20% Bonus offert"]
    }
  ];

  return (
    <div className="w-full px-6 pt-16 pb-32 overflow-hidden">

      {/* ── HERO SECTION ── */}
      <div className="text-center mb-32 relative">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[700px] h-[500px] bg-purple-600/8 blur-[150px] rounded-full -z-10 pointer-events-none"></div>

        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
          <Sparkles size={12} className="text-purple-400" />
          <span>Plateforme AEO / GEO</span>
        </div>

        <h1 className="text-5xl sm:text-6xl md:text-[5.5rem] font-sans font-bold tracking-tight text-white leading-[1.05] mb-8">
          Faites-vous citer{' '}
          <br className="hidden md:block" />
          par les <span className="gradient-text">IA G{'\u00e9'}n{'\u00e9'}ratives</span>
        </h1>

        <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto leading-relaxed mb-12 font-light">
          La premi{'\u00e8'}re plateforme d'optimisation AEO. Analysez et influencez la fa{'\u00e7'}on dont ChatGPT, Claude, Gemini et AI Overviews per{'\u00e7'}oivent votre marque.
        </p>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
          <button onClick={handleStartAnalysis} className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30">
            Lancer un Audit Gratuit <ArrowRight size={18} />
          </button>
          <button onClick={() => onNavigate('directory')} className="px-8 py-3.5 rounded-full border border-white/[0.1] text-gray-300 text-base font-medium hover:bg-white/[0.04] hover:border-white/[0.15] transition-all">
            Explorer l'Annuaire
          </button>
        </div>
      </div>

      {/* ── SCORE GRATUIT DE VISIBILITE IA ── */}
      <div className="mb-32 relative" id="score-gratuit">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[600px] bg-purple-600/[0.06] blur-[180px] rounded-full -z-10 pointer-events-none"></div>

        {/* Section header */}
        <div className="text-center mb-12">
          {/* GRATUIT Banner */}
          <div className="inline-flex items-center gap-2 px-5 py-2 rounded-full bg-gradient-to-r from-purple-500/20 to-violet-600/20 border border-purple-500/30 text-white text-sm font-bold tracking-wide uppercase mb-8 shadow-lg shadow-purple-600/10">
            <Gift size={16} className="text-purple-400" />
            <span>100% GRATUIT</span>
            <span className="text-purple-400">&mdash;</span>
            <span className="text-purple-300">Sans inscription</span>
          </div>

          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
            Votre Score de <span className="gradient-text">Visibilit{'\u00e9'} IA</span>
          </h2>
          <p className="text-gray-500 max-w-2xl mx-auto text-lg">
            D{'\u00e9'}couvrez en 30 secondes comment les IA g{'\u00e9'}n{'\u00e9'}ratives per{'\u00e7'}oivent votre marque. Aucun compte requis.
          </p>
        </div>

        {/* Form + Results Container */}
        <div className="max-w-3xl mx-auto">
          {/* Form Card */}
          <div className="ninja-card p-8 md:p-10 relative overflow-hidden">
            {/* Decorative gradient line at top */}
            <div className="absolute top-0 left-0 right-0 h-[2px] bg-gradient-to-r from-transparent via-purple-500 to-transparent"></div>

            <form
              onSubmit={(e) => { e.preventDefault(); handleFreeAudit(); }}
              className="space-y-5"
            >
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">Nom de marque</label>
                  <input
                    type="text"
                    value={brandName}
                    onChange={(e) => setBrandName(e.target.value)}
                    placeholder="Ex: CitedBy"
                    className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 outline-none transition-all focus:border-purple-500/50 focus:bg-white/[0.06] focus:shadow-[0_0_20px_rgba(168,85,247,0.08)]"
                    disabled={isAnalyzing}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">URL du site</label>
                  <input
                    type="text"
                    value={siteUrl}
                    onChange={(e) => setSiteUrl(e.target.value)}
                    placeholder="Ex: https://www.citedby.ai"
                    className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 outline-none transition-all focus:border-purple-500/50 focus:bg-white/[0.06] focus:shadow-[0_0_20px_rgba(168,85,247,0.08)]"
                    disabled={isAnalyzing}
                  />
                </div>
              </div>

              {auditError && (
                <p className="text-sm text-red-400 bg-red-500/10 border border-red-500/20 rounded-xl px-4 py-2.5">{auditError}</p>
              )}

              <button
                type="submit"
                disabled={isAnalyzing}
                className="w-full btn-gradient py-4 text-base font-bold flex items-center justify-center gap-3 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30 disabled:opacity-60 disabled:cursor-not-allowed transition-all"
              >
                {isAnalyzing ? (
                  <>
                    <Loader2 size={20} className="animate-spin" />
                    Analyse en cours...
                  </>
                ) : (
                  <>
                    <Sparkles size={20} />
                    Analyser gratuitement
                  </>
                )}
              </button>

              <p className="text-center text-xs text-gray-600">
                Aucune carte bancaire requise. 0 GTO Gas consomm{'\u00e9'}. R{'\u00e9'}sultat instantan{'\u00e9'}.
              </p>
            </form>
          </div>

          {/* Loading Animation */}
          {isAnalyzing && (
            <div className="mt-8 ninja-card p-10 flex flex-col items-center justify-center gap-5">
              <div className="relative">
                <div className="w-24 h-24 rounded-full border-4 border-white/[0.06]"></div>
                <div className="absolute inset-0 w-24 h-24 rounded-full border-4 border-transparent border-t-purple-500 animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <ScanLine size={28} className="text-purple-400 animate-pulse" />
                </div>
              </div>
              <div className="text-center">
                <p className="text-white font-semibold mb-1">Scan en cours...</p>
                <p className="text-sm text-gray-500">Nous interrogeons les LLMs pour {'\u00e9'}valuer votre marque</p>
              </div>
              {/* Animated category tags */}
              <div className="flex flex-wrap justify-center gap-2">
                {['Answer-First', 'Schema.org', 'FAQ', 'S\u00e9mantique', 'Fra\u00eecheur', 'Meta'].map((label, i) => (
                  <div
                    key={label}
                    className="px-3 py-1 rounded-full text-[10px] font-medium bg-white/[0.04] border border-white/[0.06] text-gray-500"
                    style={{ animation: `pulse 1.5s ease-in-out ${i * 0.25}s infinite` }}
                  >
                    {label}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Results Section */}
          {auditResult && !isAnalyzing && (
            <div ref={resultsRef} className="mt-8 space-y-6">
              {/* Main Score Card */}
              <div className="ninja-card p-8 md:p-10 relative overflow-hidden">
                {/* GRATUIT tag */}
                <div className="absolute top-0 right-0 px-5 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-xs font-bold rounded-bl-2xl rounded-tr-[1rem] text-white uppercase tracking-wider">
                  GRATUIT
                </div>

                <div className="flex flex-col md:flex-row items-center gap-8 md:gap-12">
                  {/* ScoreRing */}
                  <div className="flex flex-col items-center gap-3 shrink-0">
                    <ScoreRing score={auditResult.globalScore} size={160} strokeWidth={10} />
                    <div className={`text-sm font-bold ${getScoreColor(auditResult.globalScore)}`}>
                      {getScoreLabel(auditResult.globalScore)}
                    </div>
                  </div>

                  {/* E-E-A-T Pillars */}
                  <div className="flex-1 w-full">
                    <h3 className="text-lg font-bold text-white mb-5 flex items-center gap-2">
                      <Shield size={18} className="text-purple-400" />
                      Piliers E-E-A-T
                    </h3>
                    <div className="space-y-4">
                      {eeatPillars.map((pillar) => (
                        <div key={pillar.label}>
                          <div className="flex items-center justify-between mb-1.5">
                            <div className="flex items-center gap-2">
                              <span className="text-purple-400">{pillar.icon}</span>
                              <span className="text-sm font-medium text-gray-300">{pillar.label}</span>
                            </div>
                            <span className={`text-sm font-bold ${getScoreColor(pillar.score)}`}>{pillar.score}/100</span>
                          </div>
                          <div className="w-full h-2.5 bg-white/[0.06] rounded-full overflow-hidden">
                            <div
                              className={`h-full rounded-full transition-all duration-1000 ease-out ${getBarColor(pillar.score)}`}
                              style={{ width: `${pillar.score}%` }}
                            ></div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>

              {/* Summary Card */}
              <div className="ninja-card p-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                  <Target size={18} className="text-purple-400" />
                  Synth{'\u00e8'}se
                </h3>
                <p className="text-gray-400 leading-relaxed text-[15px] mb-6">{auditResult.summary}</p>

                {auditResult.topRecommendations.length > 0 && (
                  <div>
                    <h4 className="text-sm font-bold text-gray-300 mb-3 uppercase tracking-wider">Recommandations prioritaires</h4>
                    <ul className="space-y-2.5">
                      {auditResult.topRecommendations.map((rec, i) => (
                        <li key={i} className="flex items-start gap-3 text-sm text-gray-400">
                          <div className="w-5 h-5 rounded-full bg-purple-500/20 flex items-center justify-center shrink-0 mt-0.5">
                            <span className="text-[10px] font-bold text-purple-400">{i + 1}</span>
                          </div>
                          {rec}
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>

              {/* CTA Card */}
              <div className="gradient-border p-8 text-center relative overflow-hidden">
                {/* Grid pattern */}
                <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
                <div className="relative z-10">
                  <h3 className="text-xl md:text-2xl font-bold text-white mb-3">
                    D{'\u00e9'}bloquez l'analyse <span className="gradient-text">compl{'\u00e8'}te</span>
                  </h3>
                  <p className="text-gray-500 mb-6 max-w-lg mx-auto">
                    Cr{'\u00e9'}ez votre compte pour acc{'\u00e9'}der {'\u00e0'} l'audit d{'\u00e9'}taill{'\u00e9'} avec recommandations personnalis{'\u00e9'}es, outils de correction et monitoring continu.
                  </p>
                  <button
                    onClick={() => onNavigate('login')}
                    className="btn-gradient text-base px-8 py-3.5 inline-flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30"
                  >
                    Cr{'\u00e9'}ez votre compte pour l'analyse compl{'\u00e8'}te <ArrowRight size={18} />
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* ── STATS BAR ── */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-32">
        {[
          { value: '50%', label: 'des recherches vont vers l\'IA', sublabel: 'd\'ici 2026' },
          { value: '24h', label: 'pour \u00eatre cit\u00e9', sublabel: 'premier audit' },
          { value: '0', label: 'clic n\u00e9cessaire', sublabel: 'r\u00e9ponse directe' },
          { value: '3x', label: 'plus de conversions', sublabel: 'vs SEO classique' },
        ].map((stat, i) => (
          <div key={i} className="ninja-card p-6 text-center group hover:-translate-y-1 transition-all duration-300" style={{ animationDelay: `${i * 150}ms`, animation: `slide-in-from-bottom 0.5s ease-out ${i * 150}ms both` }}>
            <div className="text-3xl md:text-4xl font-bold gradient-text mb-2 group-hover:scale-110 transition-transform duration-300">{stat.value}</div>
            <p className="text-sm text-gray-300 font-medium">{stat.label}</p>
            <p className="text-xs text-gray-600 mt-1">{stat.sublabel}</p>
          </div>
        ))}
      </div>

      {/* ── FEATURES GRID ── */}
      <div className="mb-32">
        <div className="text-center mb-14">
          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
            Vos outils de <span className="gradient-text">visibilit{'\u00e9'} IA</span>
          </h2>
          <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Tout ce dont vous avez besoin pour dominer les r{'\u00e9'}ponses g{'\u00e9'}n{'\u00e9'}ratives.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-5">
          {[
            {
              icon: <ScanLine size={28} />,
              title: "Simulateur de Perception",
              desc: "Visualisez comment les LLMs (GPT-4, Claude 3) 'voient' votre entit\u00e9 en temps r\u00e9el."
            },
            {
              icon: <Code2 size={28} />,
              title: "Code S\u00e9mantique",
              desc: "G\u00e9n\u00e9rez automatiquement les donn\u00e9es structur\u00e9es (JSON-LD) que les robots pr\u00e9f\u00e8rent."
            },
            {
              icon: <Globe2 size={28} />,
              title: "Annuaire Index\u00e9",
              desc: "Inscrivez votre marque dans le Knowledge Graph CitedBy pour forcer la d\u00e9couverte."
            }
          ].map((item, i) => (
            <div key={i} className="ninja-card p-8 group cursor-default">
              <div className="w-14 h-14 rounded-2xl bg-purple-500/10 flex items-center justify-center mb-6 text-purple-400 group-hover:bg-purple-500/20 group-hover:scale-110 transition-all duration-300">
                {item.icon}
              </div>
              <h3 className="text-xl font-bold mb-3 text-white group-hover:text-purple-300 transition-colors">{item.title}</h3>
              <p className="text-gray-500 leading-relaxed text-[15px]">{item.desc}</p>
            </div>
          ))}
        </div>
      </div>

      {/* ── SEO vs AEO COMPARISON ── */}
      <div className="mb-32">
        <div className="text-center mb-14">
          <h2 className="text-3xl md:text-5xl font-sans font-bold mb-5 text-white tracking-tight">
            Le Changement de <span className="gradient-text">Paradigme</span>
          </h2>
          <p className="text-gray-500 max-w-2xl mx-auto text-lg">
            Nous passons de l'{'\u00e8'}re de la recherche (Google) {'\u00e0'} l'{'\u00e8'}re de la r{'\u00e9'}ponse (IA).
          </p>
        </div>

        <div className="grid md:grid-cols-2 gap-6 relative">
          {/* VS Badge */}
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-14 h-14 bg-[#111111] border border-white/[0.1] rounded-full flex items-center justify-center font-bold text-white z-10 text-lg shadow-xl shadow-black/50">
            VS
          </div>

          {/* SEO Classic Card */}
          <div className="ninja-card p-8 md:p-10 opacity-60 hover:opacity-90 transition-opacity">
            <div className="flex items-center gap-4 mb-8">
              <div className="p-3 bg-white/[0.04] rounded-xl text-gray-500">
                <Search size={24} />
              </div>
