          </div>

          {/* AEO Card - Gradient Border */}
          <div className="gradient-border p-8 md:p-10 relative">
            <div className="absolute top-0 right-0 px-5 py-1.5 btn-gradient text-xs font-bold rounded-bl-2xl rounded-tr-[1rem]">Le Futur</div>
            <div className="flex items-center gap-4 mb-8">
              <div className="p-3 bg-purple-500/10 rounded-xl text-purple-400">
                <Bot size={24} />
              </div>
              <h3 className="text-2xl font-bold text-white">AEO & GEO</h3>
            </div>
            <ul className="space-y-5">
              {[
                "Optimise pour des entit\u00e9s et des faits.",
                "Vise la r\u00e9ponse unique (Citations).",
                "Trafic de \"conviction\" (Autorit\u00e9).",
                "Format \"Answer-First\" structur\u00e9 pour les LLMs."
              ].map((text, i) => (
                <li key={i} className="flex items-start gap-3 text-gray-300">
