            },
            {
              icon: <Share2 size={28} />,
              title: "3. Ubiquit\u00e9 (Signal)",
              desc: "Une IA confirme une information en la croisant. Nous multiplions les signaux de corroboration via notre Annuaire AEO et optimisons vos fichiers techniques."
            }
          ].map((pillar, i) => (
            <div key={i} className="ninja-card p-8 group relative overflow-hidden">
              {/* Hover glow */}
              <div className="absolute -top-20 -right-20 w-40 h-40 bg-purple-600/0 group-hover:bg-purple-600/5 blur-3xl rounded-full transition-all duration-500"></div>
              <div className="relative z-10">
                <div className="w-14 h-14 rounded-2xl bg-purple-500/10 flex items-center justify-center text-purple-400 mb-6 group-hover:bg-purple-500/20 transition-colors">
                  {pillar.icon}
                </div>
                <h3 className="text-xl font-bold text-white mb-4">{pillar.title}</h3>
                <p className="text-gray-500 text-[15px] leading-relaxed mb-6">{pillar.desc}</p>
                <div className="h-[2px] w-10 bg-white/10 rounded-full group-hover:w-16 group-hover:bg-purple-500/50 transition-all duration-500"></div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ── PROCESS SECTION ── */}
      <div className="mb-32 w-full">
        <div className="gradient-border p-8 md:p-12 relative overflow-hidden">
          {/* Grid pattern */}
          <div className="absolute inset-0 opacity-30" style={{ backgroundImage: 'linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px)', backgroundSize: '32px 32px' }}></div>

          <div className="relative z-10">
            <h3 className="text-2xl md:text-3xl font-bold text-center mb-12 text-white">Votre parcours d'optimisation</h3>

            <div className="space-y-0">
              {[
                {
                  step: '01',
                  title: 'Analyse de Perception',
                  desc: 'Notre scanner interroge les principaux LLMs pour \u00e9tablir votre score de visibilit\u00e9 actuel et identifier les "trous" dans leur connaissance de votre marque.',
                  active: true
                },
                {
                  step: '02',
                  title: 'G\u00e9n\u00e9ration du "Source of Truth"',
                  desc: 'Nous cr\u00e9ons les fichiers llm.txt et llm.json qui serviront de r\u00e9f\u00e9rence canonique pour les robots d\'indexation.',
                  active: false
                },
                {
                  step: '03',
                  title: 'Monitoring Continu',
                  desc: 'Les mod\u00e8les d\'IA changent chaque semaine. CitedBy surveille vos positions et vous alerte si une hallucination concernant votre marque appara\u00eet.',
                  active: false
                }
              ].map((item, i) => (
                <div key={i} className="flex gap-6 md:gap-8">
                  <div className="flex flex-col items-center">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold shrink-0 ${
                      item.active
                        ? 'btn-gradient shadow-lg shadow-purple-600/30'
