                      {item.step}
                    </div>
                    {i < 2 && <div className="w-px h-full bg-white/[0.06] my-2"></div>}
                  </div>
                  <div className="pb-10">
                    <h4 className="text-lg font-bold text-white mb-2">{item.title}</h4>
                    <p className="text-sm text-gray-500 leading-relaxed">{item.desc}</p>
