              ))}
            </div>
          </div>
        </div>
      </div>

      {/* ── TESTIMONIALS ── */}
      <div className="mb-32">
        <div className="text-center mb-14">
          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
            Ils nous font <span className="gradient-text">confiance</span>
          </h2>
          <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Des marques de toutes tailles optimisent leur visibilit{'\u00e9'} IA avec CitedBy.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-5 mb-12">
          {[
            {
              quote: "En 3 semaines, notre marque est pass\u00e9e de 0 citation \u00e0 \u00eatre recommand\u00e9e par ChatGPT sur nos mots-cl\u00e9s principaux. Le ROI est incroyable.",
              name: "Marie Dubois",
              role: "CMO, TechFlow SaaS",
              avatar: "M",
              rating: 5
            },
            {
              quote: "L'outil Schema.org et le Source of Truth ont compl\u00e8tement transform\u00e9 notre pr\u00e9sence. Claude nous cite maintenant comme r\u00e9f\u00e9rence dans notre secteur.",
              name: "Thomas Martin",
              role: "Head of SEO, GreenGarden",
              avatar: "T",
              rating: 5
            },
            {
              quote: "Le dashboard de monitoring est une mine d'or. On voit en temps r\u00e9el quand un bot IA crawle nos pages et comment notre score \u00e9volue.",
              name: "Sophie Laurent",
              role: "Directrice Digitale, OmniMedia",
              avatar: "S",
              rating: 5
            }
          ].map((testimonial, i) => (
            <div key={i} className="ninja-card p-8 flex flex-col">
              <div className="flex gap-1 mb-5">
                {Array.from({ length: testimonial.rating }).map((_, j) => (
                  <Star key={j} size={16} className="text-amber-400 fill-amber-400" />
                ))}
              </div>
              <p className="text-gray-300 text-[15px] leading-relaxed flex-1 mb-6">"{testimonial.quote}"</p>
              <div className="flex items-center gap-3 pt-4 border-t border-white/[0.06]">
                <div className="w-10 h-10 rounded-full bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center text-white font-bold text-sm">
                  {testimonial.avatar}
                </div>
                <div>
                  <p className="text-white font-semibold text-sm">{testimonial.name}</p>
                  <p className="text-gray-500 text-xs">{testimonial.role}</p>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Trust Badges */}
        <div className="flex flex-wrap justify-center items-center gap-8 md:gap-12 py-8 border-y border-white/[0.06]">
          {[
            { label: 'RGPD Compliant', icon: '\u{1F6E1}\uFE0F' },
            { label: 'SSL Chiffr\u00e9', icon: '\u{1F512}' },
            { label: '99.9% Uptime', icon: '\u26A1' },
            { label: 'Support 24/7', icon: '\u{1F4AC}' },
            { label: 'Made in France', icon: '\u{1F1EB}\u{1F1F7}' },
          ].map((badge, i) => (
            <div key={i} className="flex items-center gap-2 text-gray-500 text-sm">
              <span className="text-lg">{badge.icon}</span>
              <span className="font-medium">{badge.label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ── PRICING SECTION ── */}
      <div className="mb-12 relative">
        {/* Background glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[400px] bg-purple-600/5 blur-[120px] rounded-full -z-10 pointer-events-none"></div>

        <div className="text-center mb-14">
          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-gray-400 text-xs font-medium tracking-wide uppercase mb-6">
            <Fuel size={12} className="text-purple-400" />
            <span>Carburant Algorithmique</span>
          </div>
          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
            Rechargez votre <span className="gradient-text">GTO Gas</span>
          </h2>
          <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Notre monnaie virtuelle pour ex{'\u00e9'}cuter les audits, g{'\u00e9'}n{'\u00e9'}rer les correctifs et valider votre entit{'\u00e9'}.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-5 w-full items-stretch">
          {plans.map((plan, idx) => (
            <div
              key={idx}
              className={`relative ninja-card p-8 flex flex-col h-full ${
                plan.popular
                  ? '!border-purple-500/30 shadow-[0_0_50px_rgba(168,85,247,0.08)] md:scale-105 z-10'
                  : ''
              }`}
            >
              {plan.popular && (
                <div className="absolute -top-4 left-1/2 -translate-x-1/2 btn-gradient text-xs font-bold px-5 py-1.5 rounded-full uppercase tracking-wider shadow-lg shadow-purple-600/30">
                  Le Choix Expert
                </div>
              )}

              <div className="mb-6 flex items-center justify-between pt-2">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${
                  plan.popular
                    ? 'bg-gradient-to-br from-purple-500 to-violet-600 text-white'
                    : 'bg-purple-500/10 text-gray-500'
                }`}>
                  {plan.icon}
                </div>
                <div className="text-right">
                  <span className="block text-3xl font-bold gradient-text">{plan.credits}</span>
                  <span className="text-[11px] text-gray-600 uppercase font-bold tracking-wider">Cr{'\u00e9'}dits Gas</span>
                </div>
              </div>

              <h3 className="text-xl font-bold text-white mb-2">{plan.name}</h3>
              <div className="flex items-baseline gap-1 mb-8">
                <span className="text-4xl font-bold text-white">{plan.price}{'\u20ac'}</span>
                <span className="text-sm text-gray-600">HT</span>
              </div>

              <ul className="space-y-3.5 mb-8 flex-1">
                {plan.features.map((feat, i) => (
                  <li key={i} className="flex items-start gap-3 text-[15px] text-gray-400">
